{
  "name": "SIGA Ngumbul",
  "description": "Sistem Informasi & Data Kependudukan Desa Ngumbul, Kecamatan Todanan, Kabupaten Blora. Fokus pada manajemen data kepala keluarga, rekapitulasi indikator, dan visualisasi dashboard kependudukan."
}

export type Gender = 'Laki-laki' | 'Perempuan';
export type MaritalStatus = 'Kawin' | 'Belum Kawin' | 'Cerai Hidup' | 'Cerai Mati';
export type Education = 'Tidak/Belum Sekolah' | 'SD' | 'SMP' | 'SMA' | 'Diploma' | 'Sarjana' | 'Pascasarjana';
export type BloodType = 'A' | 'B' | 'AB' | 'O' | 'Tidak Tahu';

export interface Resident {
  id: string;
  dusun: string;
  rt: string;
  rw: string;
  noKK: string;
  nik: string;
  fullName: string;
  relationship: string; // e.g., 'Kepala Keluarga', 'Istri', 'Anak'
  birthPlace: string;
  birthDate: string; // YYYY-MM-DD
  gender: Gender;
  bloodType: BloodType;
  maritalStatus: MaritalStatus;
  education: Education;
  job: string;
  fatherName: string;
  motherName: string;
  isHeadOfFamily: boolean;
}

export interface AppConfig {
  appName: string;
  subtitle: string;
  logoUrl: string;
  developerInfo: string;
}

export type AgeGroup = 'Balita' | 'Anak' | 'Remaja' | 'Dewasa' | 'Lansia';

import { AgeGroup } from '../types';

export const calculateAge = (birthDate: string): number => {
  const today = new Date();
  const birth = new Date(birthDate);
  let age = today.getFullYear() - birth.getFullYear();
  const m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
    age--;
  }
  return age;
};

export const getAgeGroup = (age: number): AgeGroup => {
  if (age <= 5) return 'Balita';
  if (age <= 12) return 'Anak';
  if (age <= 19) return 'Remaja';
  if (age <= 59) return 'Dewasa';
  return 'Lansia';
};

export const formatDate = (dateStr: string): string => {
  try {
    return new Date(dateStr).toLocaleDateString('id-ID', {
      day: '2-digit',
      month: 'long',
      year: 'numeric'
    });
  } catch (e) {
    return dateStr;
  }
};

export const downloadCSV = (data: any[], filename: string) => {
  const headers = Object.keys(data[0]);
  const csvRows = [
    headers.join(','),
    ...data.map(row => headers.map(header => `"${row[header]}"`).join(','))
  ];
  const blob = new Blob([csvRows.join('\n')], { type: 'text/csv' });
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.setAttribute('hidden', '');
  a.setAttribute('href', url);
  a.setAttribute('download', `${filename}.csv`);
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
};

