import React from 'react';
import { 
  Users, 
  Baby, 
  UserRound, 
  UserCheck, 
  Briefcase, 
  GraduationCap,
  MapPin
} from 'lucide-react';
import { 
  PieChart, 
  Pie, 
  Cell, 
  ResponsiveContainer, 
  Tooltip, 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid,
  Legend
} from 'recharts';
import { Resident } from '../types';
import { calculateAge, getAgeGroup } from '../utils/helpers';

interface DashboardProps {
  residents: Resident[];
}

const Dashboard: React.FC<DashboardProps> = ({ residents }) => {
  // Stats Calculation
  const totalResidents = residents.length;
  const maleCount = residents.filter(r => r.gender === 'Laki-laki').length;
  const femaleCount = residents.filter(r => r.gender === 'Perempuan').length;

  const ageData = residents.reduce((acc, r) => {
    const group = getAgeGroup(calculateAge(r.birthDate));
    acc[group] = (acc[group] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const genderChartData = [
    { name: 'Laki-laki', value: maleCount, color: '#3b82f6' },
    { name: 'Perempuan', value: femaleCount, color: '#ec4899' },
  ];

  const educationData = residents.reduce((acc, r) => {
    acc[r.education] = (acc[r.education] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const eduChartData = Object.keys(educationData).map(k => ({ name: k, value: educationData[k] }));

  const dusunData = residents.reduce((acc, r) => {
    acc[r.dusun] = (acc[r.dusun] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);

  const dusunChartData = Object.keys(dusunData).map(k => ({ name: k, count: dusunData[k] }));

  const StatCard = ({ icon: Icon, label, value, colorClass }: any) => (
    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex items-center space-x-4">
      <div className={`p-3 rounded-lg ${colorClass}`}>
        <Icon size={24} />
      </div>
      <div>
        <p className="text-sm font-medium text-slate-500 uppercase tracking-wider">{label}</p>
        <p className="text-2xl font-bold text-slate-900">{value}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={Users} label="Total Penduduk" value={totalResidents} colorClass="bg-blue-100 text-blue-600" />
        <StatCard icon={UserRound} label="Laki-laki" value={maleCount} colorClass="bg-indigo-100 text-indigo-600" />
        <StatCard icon={UserCheck} label="Perempuan" value={femaleCount} colorClass="bg-pink-100 text-pink-600" />
        <StatCard icon={MapPin} label="Total Dusun" value={Object.keys(dusunData).length} colorClass="bg-green-100 text-green-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Gender Pie Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold mb-6 flex items-center">
            <Users className="mr-2 text-slate-400" size={20} />
            Proporsi Jenis Kelamin
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={genderChartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {genderChartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend verticalAlign="bottom" height={36}/>
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Age Groups Bar Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold mb-6 flex items-center">
            <Baby className="mr-2 text-slate-400" size={20} />
            Kelompok Usia
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={Object.entries(ageData).map(([name, value]) => ({ name, value }))}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Dusun Bar Chart */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold mb-6 flex items-center">
            <MapPin className="mr-2 text-slate-400" size={20} />
            Penduduk per Dusun
          </h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={dusunChartData} layout="vertical">
                <CartesianGrid strokeDasharray="3 3" horizontal={false} />
                <XAxis type="number" />
                <YAxis dataKey="name" type="category" width={100} />
                <Tooltip />
                <Bar dataKey="count" fill="#10b981" radius={[0, 4, 4, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Education/Job Indicators */}
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold mb-6 flex items-center">
            <GraduationCap className="mr-2 text-slate-400" size={20} />
            Indikator Pendidikan
          </h3>
          <div className="space-y-4">
            {eduChartData.sort((a,b) => b.value - a.value).map((edu, idx) => (
              <div key={idx}>
                <div className="flex justify-between text-sm mb-1">
                  <span className="text-slate-600 font-medium">{edu.name}</span>
                  <span className="text-slate-900 font-bold">{edu.value} Orang</span>
                </div>
                <div className="w-full bg-slate-100 rounded-full h-2">
                  <div 
                    className="bg-blue-600 h-2 rounded-full" 
                    style={{ width: `${(edu.value / totalResidents) * 100}%` }}
                  ></div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { 
  Search, 
  Filter, 
  Download, 
  Upload, 
  Plus, 
  Trash2, 
  Edit2, 
  MoreHorizontal,
  ChevronLeft,
  ChevronRight,
  Eye,
  CheckSquare,
  Square
} from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, downloadCSV } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [filters, setFilters] = useState({
    dusun: '',
    rw: '',
    rt: ''
  });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);

  const headOfFamilies = useMemo(() => residents.filter(r => r.isHeadOfFamily), [residents]);

  const dusuns = useMemo(() => Array.from(new Set(residents.map(r => r.dusun))), [residents]);
  const rws = useMemo(() => Array.from(new Set(residents.filter(r => r.dusun === filters.dusun || !filters.dusun).map(r => r.rw))), [residents, filters.dusun]);
  const rts = useMemo(() => Array.from(new Set(residents.filter(r => (r.dusun === filters.dusun || !filters.dusun) && (r.rw === filters.rw || !filters.rw)).map(r => r.rt))), [residents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;

      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDeleteMultiple = () => {
    if (window.confirm(`Yakin ingin menghapus ${selectedIds.length} data terpilih?`)) {
      setResidents(prev => prev.filter(r => !selectedIds.includes(r.id)));
      setSelectedIds([]);
    }
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Logic for parsing Excel/CSV would go here
      alert('Fitur Import simulasi: Menghubungkan ke parser Excel...');
    }
  };

  return (
    <div className="space-y-6">
      {/* Action Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-lg px-3 py-2 border border-slate-200 max-w-md">
          <Search size={18} className="text-slate-400 mr-2" />
          <input 
            type="text" 
            placeholder="Cari Nama, NIK, atau No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={() => downloadCSV(filteredData, 'Data_Penduduk_Ngumbul')}
            className="flex items-center space-x-2 px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium hover:bg-slate-50 transition-all shadow-sm"
          >
            <Download size={16} />
            <span className="hidden sm:inline">Export PDF/CSV</span>
          </button>

          <label className="flex items-center space-x-2 px-4 py-2 bg-white border border-slate-200 rounded-lg text-sm font-medium hover:bg-slate-50 transition-all cursor-pointer shadow-sm">
            <Upload size={16} />
            <span className="hidden sm:inline">Import Excel</span>
            <input type="file" className="hidden" onChange={handleImport} accept=".csv,.xlsx" />
          </label>

          <button className="flex items-center space-x-2 px-4 py-2 bg-blue-600 text-white rounded-lg text-sm font-bold hover:bg-blue-700 transition-all shadow-md">
            <Plus size={16} />
            <span>Tambah Data</span>
          </button>
        </div>
      </div>

      {/* Filter Bar */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="relative">
          <select 
            className="w-full bg-white border border-slate-200 rounded-lg px-4 py-2 text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500/20"
            value={filters.dusun}
            onChange={(e) => setFilters({...filters, dusun: e.target.value, rw: '', rt: ''})}
          >
            <option value="">Semua Dusun</option>
            {dusuns.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
          <Filter size={14} className="absolute right-3 top-3 text-slate-400 pointer-events-none" />
        </div>
        <div className="relative">
          <select 
            className="w-full bg-white border border-slate-200 rounded-lg px-4 py-2 text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500/20"
            value={filters.rw}
            onChange={(e) => setFilters({...filters, rw: e.target.value, rt: ''})}
            disabled={!filters.dusun}
          >
            <option value="">Semua RW</option>
            {rws.sort().map(rw => <option key={rw} value={rw}>RW {rw}</option>)}
          </select>
          <Filter size={14} className="absolute right-3 top-3 text-slate-400 pointer-events-none" />
        </div>
        <div className="relative">
          <select 
            className="w-full bg-white border border-slate-200 rounded-lg px-4 py-2 text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500/20"
            value={filters.rt}
            onChange={(e) => setFilters({...filters, rt: e.target.value})}
            disabled={!filters.rw}
          >
            <option value="">Semua RT</option>
            {rts.sort().map(rt => <option key={rt} value={rt}>RT {rt}</option>)}
          </select>
          <Filter size={14} className="absolute right-3 top-3 text-slate-400 pointer-events-none" />
        </div>

        {selectedIds.length > 0 && (
          <button 
            onClick={handleDeleteMultiple}
            className="flex items-center justify-center space-x-2 px-4 py-2 bg-red-100 text-red-600 rounded-lg text-sm font-bold hover:bg-red-200 transition-all"
          >
            <Trash2 size={16} />
            <span>Hapus ({selectedIds.length})</span>
          </button>
        )}
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4">
                  <button onClick={toggleSelectAll} className="text-slate-400 hover:text-blue-600">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? (
                      <CheckSquare size={18} className="text-blue-600" />
                    ) : (
                      <Square size={18} />
                    )}
                  </button>
                </th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase">Dusun/RT/RW</th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase">No. KK / NIK</th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase">Nama Lengkap</th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase">Usia / JK</th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase">Pekerjaan</th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase">Pendidikan</th>
                <th className="px-4 py-4 text-xs font-bold text-slate-500 uppercase text-right">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.length > 0 ? filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-slate-50/80 transition-all group">
                  <td className="px-6 py-4">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-400 hover:text-blue-600">
                      {selectedIds.includes(r.id) ? (
                        <CheckSquare size={18} className="text-blue-600" />
                      ) : (
                        <Square size={18} />
