import { Resident } from '../types';
import { calculateAge, getAgeGroup } from '../utils/helpers';

interface RecapIndicatorsProps {
  residents: Resident[];
}

const RecapIndicators: React.FC<RecapIndicatorsProps> = ({ residents }) => {
  const [filter, setFilter] = useState({
    dusun: '',
    rw: '',
    rt: ''
  });

  const filteredResidents = useMemo(() => {
    return residents.filter(r => {
      const matchDusun = !filter.dusun || r.dusun === filter.dusun;
      const matchRW = !filter.rw || r.rw === filter.rw;
      const matchRT = !filter.rt || r.rt === filter.rt;
      return matchDusun && matchRW && matchRT;
    });
  }, [residents, filter]);

  const dusuns = Array.from(new Set(residents.map(r => r.dusun)));

  const getRecapData = (key: keyof Resident | 'ageGroup') => {
    const counts = filteredResidents.reduce((acc, r) => {
      let val: string;
      if (key === 'ageGroup') {
        val = getAgeGroup(calculateAge(r.birthDate));
      } else {
        val = String(r[key]);
      }
      acc[val] = (acc[val] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.entries(counts).map(([name, value]) => ({ name, value }));
  };

  const eduRecap = getRecapData('education');
  const jobRecap = getRecapData('job');
  const ageRecap = getRecapData('ageGroup');
  const maritalRecap = getRecapData('maritalStatus');

  const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899'];

  const RecapSection = ({ title, data, type = 'bar' }: any) => (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden flex flex-col">
      <div className="p-4 border-b border-slate-100 bg-slate-50 flex justify-between items-center">
        <h3 className="font-bold text-slate-800">{title}</h3>
        <button className="p-1.5 hover:bg-slate-200 rounded text-slate-400">
          <FileText size={16} />
        </button>
      </div>
      <div className="p-6">
        <div className="h-64 mb-6">
          <ResponsiveContainer width="100%" height="100%">
            {type === 'bar' ? (
              <BarChart data={data}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" fontSize={10} interval={0} angle={-15} textAnchor="end" />
                <YAxis fontSize={10} />
                <Tooltip />
                <Bar dataKey="value" fill="#3b82f6" radius={[4, 4, 0, 0]} />
              </BarChart>
            ) : (
              <PieChart>
                <Pie data={data} innerRadius={60} outerRadius={80} paddingAngle={5} dataKey="value">
                  {data.map((entry: any, index: number) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip />
                <Legend layout="vertical" align="right" verticalAlign="middle" />
              </PieChart>
            )}
          </ResponsiveContainer>
        </div>
        <div className="space-y-2 border-t pt-4">
          <div className="flex justify-between text-xs font-bold text-slate-400 uppercase tracking-wider px-2">
            <span>Kategori</span>
            <span>Jumlah</span>
          </div>
          {data.sort((a: any, b: any) => b.value - a.value).map((item: any, idx: number) => (
            <div key={idx} className="flex justify-between items-center p-2 rounded hover:bg-slate-50 transition-all">
              <span className="text-sm font-medium text-slate-700">{item.name}</span>
              <span className="text-sm font-bold text-slate-900 bg-slate-100 px-2 py-0.5 rounded">{item.value}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );

  return (
    <div className="space-y-8">
      {/* Filtering Header */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-wrap items-center gap-4">
        <div className="flex items-center space-x-2 mr-4">
          <Filter className="text-blue-600" size={20} />
          <h2 className="text-lg font-bold">Filter Rekapitulasi</h2>
        </div>
        <select 
          className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-500/20"
          value={filter.dusun}
          onChange={(e) => setFilter({...filter, dusun: e.target.value})}
        >
          <option value="">Semua Dusun</option>
          {dusuns.map(d => <option key={d} value={d}>{d}</option>)}
        </select>
        <div className="flex-1 text-right">
          <p className="text-sm text-slate-500">Basis Data: <span className="font-bold text-slate-900">{filteredResidents.length}</span> Penduduk Terpilih</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <RecapSection title="Indikator Pendidikan" data={eduRecap} type="bar" />
        <RecapSection title="Status Perkawinan" data={maritalRecap} type="pie" />
        <RecapSection title="Kelompok Usia" data={ageRecap} type="bar" />
        <RecapSection title="Indikator Pekerjaan" data={jobRecap.slice(0, 8)} type="bar" />
      </div>
    </div>
  );
};

