import { AgeGroup } from '../types';

export const calculateAge = (birthDate: string): number => {
  const today = new Date();
  const birth = new Date(birthDate);
  let age = today.getFullYear() - birth.getFullYear();
  const m = today.getMonth() - birth.getMonth();
  if (m < 0 || (m === 0 && today.getDate() < birth.getDate())) {
    age--;
  }
  return age;
};

export const getAgeGroup = (age: number): AgeGroup => {
  if (age <= 5) return 'Balita';
  if (age <= 12) return 'Anak';
  if (age <= 19) return 'Remaja';
  if (age <= 59) return 'Dewasa';
  return 'Lansia';
};

export const formatDate = (dateStr: string): string => {
  try {
    return new Date(dateStr).toLocaleDateString('id-ID', {
      day: '2-digit',
      month: 'long',
      year: 'numeric'
    });
  } catch (e) {
    return dateStr;
  }
};

export const downloadCSV = (data: any[], filename: string) => {
  if (data.length === 0) return;
  const headers = Object.keys(data[0]);
  const csvRows = [
    headers.join(','),
    ...data.map(row => headers.map(header => `"${row[header] || ''}"`).join(','))
  ];
  const blob = new Blob([csvRows.join('\n')], { type: 'text/csv;charset=utf-8;' });
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.setAttribute('hidden', '');
  a.setAttribute('href', url);
  a.setAttribute('download', `${filename}.csv`);
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
};

export const downloadTemplate = () => {
  const headers = [
    'dusun', 'rt', 'rw', 'noKK', 'nik', 'fullName', 
    'relationship', 'birthPlace', 'birthDate', 'gender', 
    'bloodType', 'maritalStatus', 'education', 'job', 
    'fatherName', 'motherName'
  ];
  const example = [
    'Ngumbul Krajan', '01', '01', '3316...', '3316...', 'Nama Lengkap',
    'Kepala Keluarga', 'Blora', '1990-01-01', 'Laki-laki',
    'O', 'Kawin', 'SMA', 'Petani', 'Nama Ayah', 'Nama Ibu'
  ];

  const csvContent = [headers.join(','), example.join(',')].join('\n');
  const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.setAttribute('href', url);
  a.setAttribute('download', 'Template_Import_SIGA.csv');
  document.body.appendChild(a);
  a.click();
  document.body.removeChild(a);
};

