    dusun: '',
    rw: '',
    rt: ''
  });

  const filteredResidents = useMemo(() => {
    return residents.filter(r => {
      const matchDusun = !filter.dusun || r.dusun === filter.dusun;
      const matchRW = !filter.rw || r.rw === filter.rw;
      const matchRT = !filter.rt || r.rt === filter.rt;
      return matchDusun && matchRW && matchRT;
    });
  }, [residents, filter]);

  const indicators = [
    { id: 'pendidikan', label: 'Pendidikan', icon: GraduationCap, color: 'bg-blue-500', key: 'education' },
    { id: 'pekerjaan', label: 'Pekerjaan', icon: Briefcase, color: 'bg-emerald-500', key: 'job' },
    { id: 'usia', label: 'Kelompok Usia', icon: Calendar, color: 'bg-amber-500', key: 'ageGroup' },
    { id: 'gender', label: 'Jenis Kelamin', icon: UserCircle, color: 'bg-indigo-500', key: 'gender' },
    { id: 'perkawinan', label: 'Status Perkawinan', icon: Heart, color: 'bg-pink-500', key: 'maritalStatus' },
    { id: 'wilayah', label: 'Sebaran Wilayah', icon: MapPin, color: 'bg-slate-700', key: 'dusun' },
