interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showInstructions, setShowInstructions] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);

  const [filters, setFilters] = useState({
    dusun: '',
    rw: '',
    rt: ''
  });

  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Menampilkan hanya Kepala Keluarga di tabel utama
  const headOfFamilies = useMemo(() => residents.filter(r => r.isHeadOfFamily), [residents]);

  const dusuns = useMemo(() => Array.from(new Set(residents.map(r => r.dusun))), [residents]);
  const rws = useMemo(() => Array.from(new Set(residents.filter(r => r.dusun === filters.dusun || !filters.dusun).map(r => r.rw))), [residents, filters.dusun]);
  const rts = useMemo(() => Array.from(new Set(residents.filter(r => (r.dusun === filters.dusun || !filters.dusun) && (r.rw === filters.rw || !filters.rw)).map(r => r.rt))), [residents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;

      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDelete = (id: string) => {
    const target = residents.find(r => r.id === id);
    if (!target) return;

    if (window.confirm(`Yakin ingin menghapus ${target.fullName}?`)) {
      setResidents(prev => prev.filter(r => r.id !== id));
      setSelectedIds(prev => prev.filter(i => i !== id));
    }
  };

  const handleDeleteMultiple = () => {
    if (window.confirm(`Yakin ingin menghapus ${selectedIds.length} data terpilih?`)) {
      setResidents(prev => prev.filter(r => !selectedIds.includes(r.id)));
      setSelectedIds([]);
    }
  };

  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  const parseCSV = (text: string): any[] => {
    const lines = text.split('\n').filter(line => line.trim() !== '');
    if (lines.length < 2) return [];

    // Header check - handle potential semicolon or comma
    const delimiter = lines[0].includes(';') ? ';' : ',';
    const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
    const dataRows = lines.slice(1);

    return dataRows.map((line, index) => {
      const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
      const obj: any = {};
      headers.forEach((header, i) => {
        obj[header] = values[i] || '';
      });
      return obj;
    });
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportProgress(10);

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        setImportProgress(30);
        const text = event.target?.result as string;
        const rawData = parseCSV(text);

        setImportProgress(60);

        const newResidents: Resident[] = rawData.map((item, index) => {
          const relationship = item['Status Hubungan dalam Keluarga'] || '';
          // Using 'Tanggal Lahir' directly as requested
          const birthDateRaw = item['Tanggal Lahir'] || '1990-01-01';

          return {
            id: `imported-${Date.now()}-${index}`,
            dusun: item['Dusun'] || 'Tidak Diketahui',
            rt: item['RT'] || '00',
            rw: item['RW'] || '00',
            noKK: item['No.KK'] || '',
            nik: item['NIK'] || '',
            fullName: item['Nama Lengkap'] || '',
            relationship: relationship,
            birthPlace: '', // Place of birth removed or left empty if not in CSV
            birthDate: birthDateRaw,
            gender: (item['Jenis Kelamin'] || '').includes('Perempuan') || (item['Jenis Kelamin'] || '').includes('2') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: relationship.toLowerCase().includes('kepala keluarga') || relationship.startsWith('1')
          };
        });

        setImportProgress(90);

        setTimeout(() => {
          setResidents(prev => [...prev, ...newResidents]);
          setIsImporting(false);
          setImportProgress(100);
          alert(`Berhasil mengimpor ${newResidents.length} data penduduk.`);
          if (fileInputRef.current) fileInputRef.current.value = '';
        }, 800);

      } catch (err) {
        console.error(err);
        alert('Gagal memproses file. Pastikan format CSV sesuai template.');
        setIsImporting(false);
      }
    };

    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      {/* Import Progress Overlay */}
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center space-y-6 border border-slate-200">
            <div className="relative inline-block">
               <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
               <div className="absolute inset-0 flex items-center justify-center text-xs font-bold text-blue-600">
                 {importProgress}%
               </div>
            </div>
            <div className="space-y-2">
              <h3 className="text-xl font-black text-slate-900">Mengunggah Master Data</h3>
              <p className="text-sm text-slate-500">Sistem sedang memvalidasi dan menyimpan data ke database lokal desa...</p>
            </div>
            <div className="w-full bg-slate-100 rounded-full h-3 overflow-hidden border border-slate-200 shadow-inner">
              <div 
                className="bg-gradient-to-r from-blue-500 to-blue-700 h-full transition-all duration-500 ease-out" 
                style={{ width: `${importProgress}%` }}
              ></div>
            </div>
          </div>
        </div>
      )}

      {/* Action Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-xl px-4 py-2.5 border border-slate-200 max-w-md focus-within:ring-2 focus-within:ring-blue-500/20 transition-all">
          <Search size={18} className="text-slate-400 mr-2" />
          <input 
            type="text" 
            placeholder="Cari Nama, NIK, atau No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={() => setShowInstructions(!showInstructions)}
            className={`flex items-center space-x-2 px-5 py-2.5 rounded-xl text-sm font-bold transition-all shadow-sm ${showInstructions ? 'bg-blue-600 text-white shadow-blue-200' : 'bg-white border border-slate-200 text-slate-700 hover:bg-slate-50'}`}
          >
            <BookOpen size={16} />
            <span>Format Master Data</span>
          </button>

          <button 
            onClick={() => downloadCSV(filteredData, 'Data_Penduduk_Ngumbul')}
            className="flex items-center space-x-2 px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-bold text-slate-700 hover:bg-slate-50 transition-all shadow-sm"
          >
            <Download size={16} />
            <span className="hidden sm:inline">Export CSV</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm font-bold text-blue-700 hover:bg-blue-100 transition-all cursor-pointer shadow-sm group">
            <Upload size={16} className="group-hover:-translate-y-0.5 transition-transform" />
            <span className="hidden sm:inline">Import Master Data</span>
            <input 
              ref={fileInputRef}
              type="file" 
              className="hidden" 
              onChange={handleImport} 
              accept=".csv" 
            />
          </label>

          <button className="flex items-center space-x-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold hover:bg-slate-800 transition-all shadow-md">
            <Plus size={16} />
            <span>Tambah Data</span>
          </button>
        </div>
      </div>

      {/* Detailed Import Instructions Box */}
      {showInstructions && (
        <div className="bg-white border-2 border-blue-100 rounded-2xl shadow-xl overflow-hidden animate-in slide-in-from-top-4 duration-300">
          <div className="p-4 bg-blue-600 text-white flex justify-between items-center">
            <div className="flex items-center space-x-2">
              <FileSpreadsheet size={20} />
              <h3 className="font-bold uppercase tracking-wider text-sm">Panduan Pengisian Master Data</h3>
            </div>
            <button onClick={() => setShowInstructions(false)} className="hover:bg-blue-700 p-1 rounded-lg transition-all">
              <X size={24} />
            </button>
          </div>

          <div className="p-6 overflow-y-auto max-h-[60vh] text-sm text-slate-700 space-y-6">
            <div className="flex items-center justify-between border-b pb-4 bg-slate-50 -mx-6 -mt-6 p-6 mb-4">
              <div className="flex items-center space-x-2 text-blue-800">
                 <AlertCircle size={20} />
                 <p className="font-bold">Gunakan template resmi untuk menghindari kesalahan pembacaan data.</p>
              </div>
              <button 
                onClick={downloadTemplate}
                className="flex items-center space-x-2 px-6 py-3 bg-green-600 text-white rounded-xl font-black hover:bg-green-700 transition-all shadow-lg shadow-green-200"
              >
                <Download size={18} />
                <span>Unduh Template CSV</span>
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              <div>
                <h4 className="font-black text-blue-700 uppercase text-[10px] mb-3 bg-blue-50 px-2 py-1 inline-block rounded">KODE STATUS HUBUNGAN</h4>
                <div className="text-[11px] bg-slate-50 p-4 rounded-xl space-y-1.5 border border-slate-100 font-medium">
                  <p>1. Kepala Keluarga</p>
                  <p>2. Istri</p>
                  <p>3. Anak Kandung/Tiri</p>
                  <p>4. Anak Angkat</p>
                  <p>5. Menantu</p>
                  <p>6. Cucu</p>
                  <p className="text-slate-400 italic mt-2">*Gunakan angka didepan atau teks lengkap.</p>
                </div>
              </div>
              <div>
                <h4 className="font-black text-blue-700 uppercase text-[10px] mb-3 bg-blue-50 px-2 py-1 inline-block rounded">TANGGAL LAHIR</h4>
                <div className="text-[11px] bg-slate-50 p-4 rounded-xl space-y-1.5 border border-slate-100 font-medium leading-relaxed">
                  <p className="font-bold text-slate-900">Format: YYYY-MM-DD</p>
                  <p>Contoh: <code className="bg-amber-100 px-1 rounded">1990-12-31</code></p>
                  <p className="mt-2 text-slate-500">Penting: Gunakan format tahun-bulan-hari yang benar agar usia terhitung otomatis.</p>
                </div>
              </div>
              <div>
                <h4 className="font-black text-blue-700 uppercase text-[10px] mb-3 bg-blue-50 px-2 py-1 inline-block rounded">KEPALA KELUARGA</h4>
                <div className="text-[11px] bg-slate-50 p-4 rounded-xl space-y-1.5 border border-slate-100 font-medium">
                  <p>Sistem secara otomatis mendeteksi baris dengan status "Kepala Keluarga" untuk ditampilkan di tabel utama.</p>
                  <p className="text-blue-600 font-bold mt-1">Satu KK hanya boleh memiliki 1 Kepala Keluarga.</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Filter Bar */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="relative">
          <select 
            className="w-full bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500/20 font-medium"
            value={filters.dusun}
            onChange={(e) => setFilters({...filters, dusun: e.target.value, rw: '', rt: ''})}
          >
            <option value="">Semua Dusun</option>
            {dusuns.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
          <Filter size={14} className="absolute right-4 top-3.5 text-slate-400 pointer-events-none" />
        </div>
        <div className="relative">
          <select 
            className="w-full bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500/20 font-medium"
            value={filters.rw}
            onChange={(e) => setFilters({...filters, rw: e.target.value, rt: ''})}
            disabled={!filters.dusun}
          >
            <option value="">Semua RW</option>
            {rws.sort().map(rw => <option key={rw} value={rw}>RW {rw}</option>)}
          </select>
          <Filter size={14} className="absolute right-4 top-3.5 text-slate-400 pointer-events-none" />
        </div>
        <div className="relative">
          <select 
            className="w-full bg-white border border-slate-200 rounded-xl px-4 py-2.5 text-sm appearance-none outline-none focus:ring-2 focus:ring-blue-500/20 font-medium"
            value={filters.rt}
            onChange={(e) => setFilters({...filters, rt: e.target.value})}
            disabled={!filters.rw}
          >
            <option value="">Semua RT</option>
            {rts.sort().map(rt => <option key={rt} value={rt}>RT {rt}</option>)}
          </select>
          <Filter size={14} className="absolute right-4 top-3.5 text-slate-400 pointer-events-none" />
        </div>

        {selectedIds.length > 0 && (
          <button 
            onClick={handleDeleteMultiple}
            className="flex items-center justify-center space-x-2 px-4 py-2 bg-red-600 text-white rounded-xl text-sm font-black hover:bg-red-700 transition-all shadow-lg shadow-red-100 animate-in zoom-in duration-200"
          >
            <Trash2 size={16} />
            <span>Hapus {selectedIds.length} Data</span>
          </button>
        )}
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4">
                  <button onClick={toggleSelectAll} className="text-slate-400 hover:text-blue-600 transition-colors">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? (
                      <CheckSquare size={20} className="text-blue-600" />
                    ) : (
                      <Square size={20} />
                    )}
                  </button>
                </th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah (Dusun/RT/RW)</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identitas (No. KK/NIK)</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Kepala Keluarga</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Usia / Jenis Kelamin</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan Utama</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right pr-6">Aksi Kelola</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.length > 0 ? filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-6 py-5">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300 hover:text-blue-600">
                      {selectedIds.includes(r.id) ? (
                        <CheckSquare size={20} className="text-blue-600" />
                      ) : (
                        <Square size={20} />
                      )}
                    </button>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm font-bold text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-500 font-mono mt-0.5">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline flex items-center" onClick={() => setViewingFamilyKK(r.noKK)}>
                      {r.noKK}
                    </div>
                    <div className="text-[11px] text-slate-400 font-mono mt-0.5 tracking-tighter">{r.nik}</div>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm font-black text-slate-800 uppercase tracking-tight">{r.fullName}</div>
                    <div className="flex items-center space-x-1 mt-1">
                       <span className="text-[9px] font-black text-white bg-blue-500 px-1.5 py-0.5 rounded-md uppercase tracking-tighter">KEPALA KELUARGA</span>
                    </div>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm text-slate-900 font-black">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase">Tahun</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender === 'Laki-laki' ? 'bg-indigo-100 text-indigo-700' : 'bg-pink-100 text-pink-700'}`}>
                      {r.gender}
                    </div>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm text-slate-600 font-medium">{r.job || '-'}</div>
                  </td>
                  <td className="px-4 py-5 text-right pr-6">
                    <div className="flex items-center justify-end space-x-1">
                      <button 
                        onClick={() => setViewingFamilyKK(r.noKK)}
                        className="p-2.5 text-slate-400 hover:text-blue-600 hover:bg-white hover:shadow-sm rounded-xl transition-all" 
                        title="Lihat Anggota Keluarga"
                      >
                        <Eye size={18} />
                      </button>
                      <button 
                        onClick={() => setEditingResident(r)}
                        className="p-2.5 text-slate-400 hover:text-amber-600 hover:bg-white hover:shadow-sm rounded-xl transition-all" 
                        title="Edit Profil"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button 
                        onClick={() => handleDelete(r.id)}
                        className="p-2.5 text-slate-400 hover:text-red-600 hover:bg-white hover:shadow-sm rounded-xl transition-all" 
                        title="Hapus Permanen"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={8} className="px-6 py-32 text-center">
                    <div className="flex flex-col items-center space-y-4 max-w-sm mx-auto">
                      <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center border-4 border-white shadow-inner">
                        <FileSpreadsheet size={40} className="text-slate-300" />
                      </div>
                      <div>
                        <h4 className="text-lg font-black text-slate-900">Database Kosong</h4>
                        <p className="text-sm text-slate-500 mt-1 leading-relaxed">
                          Belum ada data penduduk yang masuk. Silakan gunakan fitur <span className="font-bold text-blue-600">Import Master Data</span> untuk mengunggah data dari file CSV.
                        </p>
                      </div>
                      <button 
                         onClick={() => fileInputRef.current?.click()}
                         className="flex items-center space-x-2 px-6 py-2.5 bg-blue-600 text-white rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-100"
                      >
                        <Upload size={16} />
                        <span>Mulai Import Data</span>
                      </button>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Detail Modal */}
      {viewingFamilyKK && (
        <FamilyDetailModal 
          noKK={viewingFamilyKK} 
          residents={residents} 
          onClose={() => setViewingFamilyKK(null)} 
        />
      )}

      {/* Edit Modal */}
      {editingResident && (
        <EditResidentModal 
          resident={editingResident} 
          onClose={() => setEditingResident(null)} 
          onSave={handleEditSave} 
        />
      )}
    </div>
  );
};

export default PopulationManagement;

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Filter, 
  Download, 
  Upload, 
  Plus, 
  Trash2, 
  Edit2, 
  ChevronLeft,
  ChevronRight,
  Eye,
  CheckSquare,
  Square,
  Info,
  FileSpreadsheet,
  X,
  BookOpen,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { Resident, Gender, MaritalStatus, Education, BloodType } from '../types';
import { calculateAge, downloadCSV, downloadTemplate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showInstructions, setShowInstructions] = useState(false);
  const [isImporting, setIsImporting] = useState(false);
  const [importProgress, setImportProgress] = useState(0);

  const [filters, setFilters] = useState({
    dusun: '',
    rw: '',
    rt: ''
  });

  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Menampilkan hanya Kepala Keluarga di tabel utama
  const headOfFamilies = useMemo(() => residents.filter(r => r.isHeadOfFamily), [residents]);

  const dusuns = useMemo(() => Array.from(new Set(residents.map(r => r.dusun))), [residents]);
  const rws = useMemo(() => Array.from(new Set(residents.filter(r => r.dusun === filters.dusun || !filters.dusun).map(r => r.rw))), [residents, filters.dusun]);
  const rts = useMemo(() => Array.from(new Set(residents.filter(r => (r.dusun === filters.dusun || !filters.dusun) && (r.rw === filters.rw || !filters.rw)).map(r => r.rt))), [residents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;

      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDelete = (id: string) => {
    const target = residents.find(r => r.id === id);
    if (!target) return;

    if (window.confirm(`Yakin ingin menghapus ${target.fullName}?`)) {
      setResidents(prev => prev.filter(r => r.id !== id));
      setSelectedIds(prev => prev.filter(i => i !== id));
    }
  };

  const handleDeleteMultiple = () => {
    if (window.confirm(`Yakin ingin menghapus ${selectedIds.length} data terpilih?`)) {
      setResidents(prev => prev.filter(r => !selectedIds.includes(r.id)));
      setSelectedIds([]);
    }
  };

  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  const handleAddSave = (newResident: Resident) => {
    setResidents(prev => [...prev, newResident]);
    setIsAddModalOpen(false);
  };

  const parseCSV = (text: string): any[] => {
    const lines = text.split('\n').filter(line => line.trim() !== '');
    if (lines.length < 2) return [];

    // Header check - handle potential semicolon or comma
    const delimiter = lines[0].includes(';') ? ';' : ',';
    const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
    const dataRows = lines.slice(1);

    return dataRows.map((line, index) => {
      const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
      const obj: any = {};
      headers.forEach((header, i) => {
        obj[header] = values[i] || '';
      });
      return obj;
    });
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    setImportProgress(10);

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        setImportProgress(30);
        const text = event.target?.result as string;
        const rawData = parseCSV(text);

        setImportProgress(60);

        const newResidents: Resident[] = rawData.map((item, index) => {
          const relationship = item['Status Hubungan dalam Keluarga'] || '';
          // Using 'Tanggal Lahir' directly as requested
          const birthDateRaw = item['Tanggal Lahir'] || '1990-01-01';

          return {
            id: `imported-${Date.now()}-${index}`,
            dusun: item['Dusun'] || 'Tidak Diketahui',
            rt: item['RT'] || '00',
            rw: item['RW'] || '00',
            noKK: item['No.KK'] || '',
            nik: item['NIK'] || '',
            fullName: item['Nama Lengkap'] || '',
            relationship: relationship,
            birthPlace: '', 
            birthDate: birthDateRaw,
            gender: (item['Jenis Kelamin'] || '').includes('Perempuan') || (item['Jenis Kelamin'] || '').includes('2') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: relationship.toLowerCase().includes('kepala keluarga') || relationship.startsWith('1')
          };
        });

        setImportProgress(90);

        setTimeout(() => {
          setResidents(prev => [...prev, ...newResidents]);
          setIsImporting(false);
          setImportProgress(100);
          alert(`Berhasil mengimpor ${newResidents.length} data penduduk.`);
          if (fileInputRef.current) fileInputRef.current.value = '';
        }, 800);

      } catch (err) {
        console.error(err);
        alert('Gagal memproses file. Pastikan format CSV sesuai template.');
        setIsImporting(false);
      }
    };

    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
