import React, { useState } from 'react';
import { X, Save, UserPlus, Plus, Trash2, Users } from 'lucide-react';
import { Resident, Gender, MaritalStatus, Education, BloodType } from '../types';

interface AddResidentModalProps {
  onClose: () => void;
  onSave: (newResidents: Resident[]) => void;
}

interface MemberForm {
  nik: string;
  fullName: string;
  relationship: string;
  birthDate: string;
  gender: Gender;
  bloodType: BloodType;
  maritalStatus: MaritalStatus;
  education: Education;
  job: string;
  fatherName: string;
  motherName: string;
}

const AddResidentModal: React.FC<AddResidentModalProps> = ({ onClose, onSave }) => {
  // Data Kolektif Keluarga
  const [familyData, setFamilyData] = useState({
    noKK: '',
    dusun: '',
    rt: '',
    rw: ''
  });

  // Daftar Anggota dalam KK tersebut
  const [members, setMembers] = useState<MemberForm[]>([
    {
      nik: '',
      fullName: '',
      relationship: '1. Kepala Keluarga',
      birthDate: '',
      gender: 'Laki-laki',
      bloodType: 'Tidak Tahu',
      maritalStatus: 'Kawin',
      education: 'SMA',
      job: '',
      fatherName: '',
      motherName: '',
    }
  ]);

  const addMember = () => {
    setMembers([...members, {
      nik: '',
      fullName: '',
      relationship: '3. Anak',
      birthDate: '',
      gender: 'Laki-laki',
      bloodType: 'Tidak Tahu',
      maritalStatus: 'Belum Kawin',
      education: 'Tidak/Belum Sekolah',
      job: '',
      fatherName: '',
      motherName: '',
    }]);
  };

  const removeMember = (index: number) => {
    if (members.length > 1) {
      setMembers(members.filter((_, i) => i !== index));
    }
  };

  const handleFamilyChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFamilyData(prev => ({ ...prev, [name]: value }));
  };

  const handleMemberChange = (index: number, e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    const newMembers = [...members];
    newMembers[index] = { ...newMembers[index], [name]: value };
    setMembers(newMembers);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Validasi No KK
    if (!familyData.noKK || familyData.noKK.length < 5) {
      alert("Mohon isi No. KK dengan benar");
      return;
    }

    const timestamp = Date.now();
    const finalResidents: Resident[] = members.map((m, idx) => ({
      ...m,
      ...familyData,
      id: `manual-${timestamp}-${idx}`,
      birthPlace: '',
      isHeadOfFamily: m.relationship.toLowerCase().includes('kepala keluarga') || m.relationship.startsWith('1')
    }));

    onSave(finalResidents);
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-6xl max-h-[95vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-200">
        {/* Header Modal */}
        <div className="p-6 border-b border-slate-200 flex items-center justify-between bg-slate-900 text-white">
          <div className="flex items-center space-x-4">
            <div className="p-3 bg-blue-600 rounded-2xl shadow-lg shadow-blue-500/20">
              <Users size={24} />
            </div>
            <div>
              <h3 className="text-xl font-black tracking-tight">Input Data Satu Keluarga (KK)</h3>
              <p className="text-slate-400 text-xs font-medium uppercase tracking-widest">Manajemen Kartu Keluarga Baru</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-800 rounded-xl transition-all">
            <X size={24} />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-10">
          {/* BAGIAN 1: IDENTITAS KELUARGA */}
          <section className="space-y-6">
            <div className="flex items-center space-x-3 mb-2">
              <div className="w-1.5 h-6 bg-blue-600 rounded-full"></div>
              <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Identitas Kolektif Keluarga</h4>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6 bg-slate-50 p-6 rounded-3xl border border-slate-100 shadow-inner">
              <div className="md:col-span-1">
                <label className="block text-xs font-black text-slate-400 mb-2 uppercase">No. Kartu Keluarga (KK)</label>
                <input 
                  type="text" 
                  name="noKK" 
                  value={familyData.noKK} 
                  onChange={handleFamilyChange} 
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm" 
                  placeholder="3316..." 
                  required 
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 mb-2 uppercase">Dusun</label>
                <input 
                  type="text" 
                  name="dusun" 
                  value={familyData.dusun} 
                  onChange={handleFamilyChange} 
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm" 
                  placeholder="Contoh: Ngumbul Krajan" 
                  required 
                />
              </div>
              <div>
                <label className="block text-xs font-black text-slate-400 mb-2 uppercase">RT</label>
                <input 
                  type="text" 
                  name="rt" 
                  value={familyData.rt} 
                  onChange={handleFamilyChange} 
                  className="w-full bg-white border border-slate-200 rounded-xl px-4 py-3 text-sm font-bold focus:ring-4 focus:ring-blue-500/10 outline-none transition-all shadow-sm text-center" 
                  placeholder="01" 
                  required 
                />
              </div>
              <div>
