                      <select name="relationship" value={member.relationship} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all bg-transparent">
                        <option value="1. Kepala Keluarga">Kepala Keluarga</option>
