                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-tighter">Tanggal Lahir</label>
                      <input type="date" name="birthDate" value={member.birthDate} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all" />
                    </div>
                    <div>
                      <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-tighter">JK</label>
                      <select name="gender" value={member.gender} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all bg-transparent">
                        <option value="Laki-laki">Laki-laki</option>
                        <option value="Perempuan">Perempuan</option>
                      </select>
                    </div>

                    {/* Baris Kedua untuk Detail Lebih Lanjut */}
                    <div className="md:col-span-1">
                      <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-tighter">Pekerjaan</label>
                      <input type="text" name="job" value={member.job} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all" placeholder="Pekerjaan" />
                    </div>
                    <div className="md:col-span-1">
                      <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-tighter">Pendidikan</label>
                      <select name="education" value={member.education} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all bg-transparent text-xs">
                        <option value="SD">SD</option>
                        <option value="SMP">SMP</option>
                        <option value="SMA">SMA</option>
                        <option value="Sarjana">Sarjana</option>
                        <option value="Tidak/Belum Sekolah">Tidak Sekolah</option>
                      </select>
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-tighter">Ayah Kandung</label>
                      <input type="text" name="fatherName" value={member.fatherName} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all" placeholder="Nama Ayah" />
                    </div>
                    <div className="md:col-span-2">
                      <label className="block text-[10px] font-black text-slate-400 mb-1 uppercase tracking-tighter">Ibu Kandung</label>
                      <input type="text" name="motherName" value={member.motherName} onChange={(e) => handleMemberChange(index, e)} className="w-full border-b-2 border-slate-100 focus:border-blue-500 py-2 text-sm font-bold outline-none transition-all" placeholder="Nama Ibu" />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </form>

        <div className="p-8 border-t border-slate-100 bg-slate-50 flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center space-x-2 text-slate-500">
            <Info size={16} />
            <p className="text-xs font-medium italic">Satu KK akan disimpan sekaligus dengan data wilayah yang sama.</p>
          </div>
          <div className="flex items-center space-x-3">
            <button type="button" onClick={onClose} className="px-6 py-3 border-2 border-slate-200 rounded-2xl text-sm font-black text-slate-600 hover:bg-slate-100 transition-all">Batal</button>
            <button type="submit" onClick={handleSubmit} className="px-10 py-3 bg-slate-900 text-white rounded-2xl text-sm font-black hover:bg-slate-800 shadow-xl shadow-slate-200 transition-all flex items-center space-x-2">
