import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Filter, 
  Download, 
  Upload, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  FileSpreadsheet,
  X,
  BookOpen,
  Loader2,
  AlertCircle
} from 'lucide-react';
import { Resident, Gender, MaritalStatus, Education, BloodType } from '../types';
import { calculateAge, downloadCSV, downloadTemplate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [showInstructions, setShowInstructions] = useState(false);
  const [isImporting, setIsImporting] = useState(false);

  const [filters, setFilters] = useState({
    dusun: '',
    rw: '',
    rt: ''
  });

  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const headOfFamilies = useMemo(() => residents.filter(r => r.isHeadOfFamily), [residents]);

  const dusuns = useMemo(() => Array.from(new Set(residents.map(r => r.dusun))), [residents]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      return matchSearch && matchDusun;
    });
  }, [headOfFamilies, searchTerm, filters.dusun]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDeleteFamily = (resident: Resident) => {
    if (window.confirm(`Yakin ingin menghapus seluruh keluarga ${resident.fullName} (No. KK: ${resident.noKK})?`)) {
      setResidents(prev => prev.filter(r => r.noKK !== resident.noKK));
      setSelectedIds(prev => prev.filter(i => i !== resident.id));
    }
  };

  const handleDeleteMultiple = () => {
    const selectedResidents = headOfFamilies.filter(r => selectedIds.includes(r.id));
    const kksToDelete = selectedResidents.map(r => r.noKK);

    if (window.confirm(`Yakin ingin menghapus ${selectedIds.length} keluarga terpilih beserta seluruh anggotanya?`)) {
      setResidents(prev => prev.filter(r => !kksToDelete.includes(r.noKK)));
      setSelectedIds([]);
    }
  };

  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  const handleAddSave = (newResidents: Resident[]) => {
    setResidents(prev => [...prev, ...newResidents]);
    setIsAddModalOpen(false);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
        const newResidents: Resident[] = lines.slice(1).map((line, index) => {
          const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => item[h] = values[i] || '');
          const rel = item['Status Hubungan dalam Keluarga'] || '';
          return {
            id: `imported-${Date.now()}-${index}`,
            dusun: item['Dusun'] || '-',
            rt: item['RT'] || '-',
            rw: item['RW'] || '-',
            noKK: item['No.KK'] || '-',
            nik: item['NIK'] || '-',
            fullName: item['Nama Lengkap'] || '-',
            relationship: rel,
            birthPlace: '', 
            birthDate: item['Tanggal Lahir'] || '1990-01-01',
            gender: (item['Jenis Kelamin'] || '').includes('P') || (item['Jenis Kelamin'] || '').includes('2') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: rel.toLowerCase().includes('kepala keluarga') || rel.startsWith('1')
          };
        });
        setResidents(prev => [...prev, ...newResidents]);
        setIsImporting(false);
        alert(`Berhasil mengimpor ${newResidents.length} data.`);
      } catch (err) {
        alert('Gagal impor CSV.');
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center border border-slate-200">
             <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
             <h3 className="text-xl font-black text-slate-900 mt-4">Memproses Data...</h3>
          </div>
        </div>
      )}

      {/* Action Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-2xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-xl px-4 py-2.5 border border-slate-200 max-w-md">
          <Search size={18} className="text-slate-400 mr-2" />
          <input 
            type="text" 
            placeholder="Cari Nama, NIK, atau No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={() => setShowInstructions(!showInstructions)}
            className="flex items-center space-x-2 px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-sm font-bold text-slate-700 hover:bg-slate-50 transition-all"
          >
            <BookOpen size={16} />
            <span>Format Data</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-2.5 bg-blue-50 border border-blue-200 rounded-xl text-sm font-bold text-blue-700 hover:bg-blue-100 transition-all cursor-pointer">
            <Upload size={16} />
            <span className="hidden sm:inline">Import CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleImport} accept=".csv" />
          </label>

          <button 
            onClick={() => setIsAddModalOpen(true)}
            className="flex items-center space-x-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl text-sm font-bold hover:bg-slate-800 transition-all"
          >
            <Plus size={16} />
            <span>Tambah KK</span>
          </button>
        </div>
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12">
                  <button onClick={toggleSelectAll} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-28">Aksi</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Kepala Keluarga</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.length > 0 ? filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all">
                  <td className="px-6 py-5">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                    </button>
                  </td>
                  <td className="px-4 py-5">
                    <div className="flex items-center justify-center space-x-2">
                      <button 
                        onClick={() => setViewingFamilyKK(r.noKK)}
                        className="p-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-600 hover:text-white transition-all" 
                        title="Lihat Anggota Keluarga"
                      >
                        <Eye size={18} />
                      </button>
                      <button 
                        onClick={() => handleDeleteFamily(r)}
                        className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-600 hover:text-white transition-all" 
                        title="Hapus Keluarga"
                      >
                        <Trash2 size={18} />
                      </button>
                    </div>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm font-bold text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-500">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-5">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline" onClick={() => setViewingFamilyKK(r.noKK)}>{r.noKK}</div>
                    <div className="text-[11px] text-slate-400 font-mono tracking-tighter">{r.nik}</div>
                  </td>
                  <td className="px-4 py-5 text-sm font-black text-slate-800 uppercase">{r.fullName}</td>
                  <td className="px-4 py-5 text-center">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender === 'Laki-laki' ? 'bg-indigo-100 text-indigo-700' : 'bg-pink-100 text-pink-700'}`}>
                      {r.gender === 'Laki-laki' ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-4 py-5 text-sm text-slate-600">{r.job || '-'}</td>
                </tr>
              )) : (
                <tr><td colSpan={7} className="px-6 py-20 text-center text-slate-400 font-bold uppercase tracking-widest">Database Kosong</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={handleEditSave} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={handleAddSave} />}
    </div>
  );
};

