            </div>
          </div>
        </div>

        {/* Footer (No Print) */}
        <div className="p-8 border-t border-slate-100 bg-white flex justify-between items-center no-print">
          <div className="flex items-center space-x-2 text-slate-400 font-bold uppercase tracking-widest text-[9px]">
             <CheckCircle2 size={16} className="text-emerald-500" />
             <span>Integrasi Data Penduduk Desa Ngumbul · Kecamatan Todanan</span>
          </div>
          <button 
            onClick={onClose}
            className="px-12 py-4 bg-slate-900 text-white rounded-[1.5rem] text-sm font-black hover:bg-slate-800 transition-all shadow-xl shadow-slate-200"
          >
            Tutup Rincian
          </button>
        </div>

        {/* Edit Modal (Nested) */}
        {editingMember && (
          <EditResidentModal 
            resident={editingMember} 
            onClose={() => setEditingMember(null)} 
            onSave={handleUpdateMember} 
          />
        )}

        {/* Add Member Modal (Nested) */}
        {isAddingMember && (
          <InternalAddMemberModal 
            noKK={noKK}
            familyBase={headOfFamily}
            onClose={() => setIsAddingMember(false)}
            onSave={handleAddMember}
          />
        )}
      </div>
    </div>
  );
};

