import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  Upload,
  BookOpen,
  Loader2
} from 'lucide-react';
import { Resident, BloodType, MaritalStatus, Education } from '../types';
import { calculateAge, downloadTemplate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [filters, setFilters] = useState({ dusun: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);
  const dusuns = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))), [activeResidents]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);
      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      return matchSearch && matchDusun;
    });
  }, [headOfFamilies, searchTerm, filters.dusun]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDeleteFamily = (resident: Resident) => {
    if (window.confirm(`Yakin ingin menghapus seluruh keluarga ${resident.fullName} (No. KK: ${resident.noKK})?`)) {
      setResidents(prev => prev.filter(r => r.noKK !== resident.noKK));
      setSelectedIds(prev => prev.filter(i => i !== resident.id));
    }
  };

  const handleDeleteMultiple = () => {
    const kksToDelete = headOfFamilies.filter(r => selectedIds.includes(r.id)).map(r => r.noKK);
    if (window.confirm(`Hapus ${selectedIds.length} keluarga terpilih?`)) {
      setResidents(prev => prev.filter(r => !kksToDelete.includes(r.noKK)));
      setSelectedIds([]);
    }
  };

  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  const handleAddSave = (newResidents: Resident[]) => {
    const withStatus = newResidents.map(r => ({ ...r, status: 'Aktif' as const }));
    setResidents(prev => [...prev, ...withStatus]);
    setIsAddModalOpen(false);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
        const newResidents: Resident[] = lines.slice(1).map((line, index) => {
          const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => item[h] = values[i] || '');
          const rel = item['Status Hubungan dalam Keluarga'] || '';
          return {
            id: `imp-${Date.now()}-${index}`,
            dusun: item['Dusun'] || '-',
            rt: item['RT'] || '-',
            rw: item['RW'] || '-',
            noKK: item['No.KK'] || '-',
            nik: item['NIK'] || '-',
            fullName: item['Nama Lengkap'] || '-',
            relationship: rel,
            birthPlace: '', 
            birthDate: item['Tanggal Lahir'] || '1990-01-01',
            gender: (item['Jenis Kelamin'] || '').includes('P') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: rel.toLowerCase().includes('kepala keluarga') || rel.startsWith('1'),
            status: 'Aktif'
          };
        });
        setResidents(prev => [...prev, ...newResidents]);
        setIsImporting(false);
        alert(`Berhasil mengimpor ${newResidents.length} data.`);
      } catch (err) {
        alert('Gagal impor CSV.');
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
             <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
             <h3 className="text-xl font-black text-slate-900 mt-4">MEMPROSES DATA...</h3>
          </div>
        </div>
      )}

      {/* Action Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-2xl px-5 py-3 border border-slate-200 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Kepala Keluarga..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={downloadTemplate}
            className="flex items-center space-x-2 px-5 py-3 bg-white border border-slate-200 rounded-2xl text-xs font-black text-slate-700 hover:bg-slate-50 transition-all"
          >
            <BookOpen size={18} />
            <span>FORMAT DATA</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-3 bg-blue-50 border border-blue-200 rounded-2xl text-xs font-black text-blue-700 hover:bg-blue-100 transition-all cursor-pointer">
            <Upload size={18} />
            <span>IMPORT CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleImport} accept=".csv" />
          </label>

          <button 
            onClick={() => setIsAddModalOpen(true)}
            className="flex items-center space-x-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-xs font-black hover:bg-slate-800 transition-all shadow-lg"
          >
            <Plus size={18} />
            <span>TAMBAH KK</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <select 
          className="bg-white border border-slate-200 rounded-2xl px-4 py-3 text-sm font-bold outline-none"
          value={filters.dusun}
          onChange={(e) => setFilters({ dusun: e.target.value })}
        >
          <option value="">Semua Dusun</option>
          {dusuns.map(d => <option key={d} value={d}>{d}</option>)}
        </select>
        {selectedIds.length > 0 && (
          <button onClick={handleDeleteMultiple} className="bg-red-600 text-white rounded-2xl px-4 py-3 text-xs font-black flex items-center justify-center space-x-2 animate-in zoom-in">
            <Trash2 size={16} />
            <span>HAPUS {selectedIds.length} KK</span>
          </button>
        )}
      </div>

      {/* Table Container */}
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 w-12 text-center">
                  <button onClick={toggleSelectAll} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-28">Aksi</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Kepala Keluarga</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all">
                  <td className="px-6 py-6 text-center">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={22} className="text-blue-600" /> : <Square size={22} />}
                    </button>
                  </td>
                  <td className="px-4 py-6">
                    <div className="flex items-center justify-center space-x-2">
                      <button 
                        onClick={() => setViewingFamilyKK(r.noKK)}
                        className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm" 
                        title="Rincian"
                      >
                        <Eye size={20} />
