                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">NIK</label>
                   <input type="text" value={m.nik} onChange={e => setM({...m, nik: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 outline-none font-bold" required placeholder="NIK..."/>
