                <div>
                   <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Tgl Lahir</label>
                   <input type="date" value={m.birthDate} onChange={e => setM({...m, birthDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-3 outline-none font-bold" required/>
                </div>
             </div>
             <div className="pt-6 flex justify-end space-x-4">
