import React, { useState, useMemo } from 'react';
import { Search, MapPin, Skull, PlaneLanding, History, Trash2, Calendar } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, formatDate } from '../utils/helpers';

interface ArchivedResidentsProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const ArchivedResidents: React.FC<ArchivedResidentsProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');

  const archivedData = useMemo(() => {
    return residents.filter(r => r.status !== 'Aktif' && (
      r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
      r.nik.includes(searchTerm) ||
      r.noKK.includes(searchTerm)
    ));
  }, [residents, searchTerm]);

  const restoreResident = (id: string) => {
    if (window.confirm("Pulihkan penduduk ini ke status Aktif?")) {
      setResidents(prev => prev.map(r => r.id === id ? { ...r, status: 'Aktif', deathDate: undefined, moveDate: undefined, moveDestination: undefined } : r));
    }
  };

  const deletePermanently = (id: string) => {
    if (window.confirm("Hapus data ini secara permanen? Tindakan ini tidak dapat dibatalkan.")) {
      setResidents(prev => prev.filter(r => r.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-2xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex-1 flex items-center bg-slate-100 rounded-xl px-4 py-2.5 border border-slate-200 max-w-md">
          <Search size={18} className="text-slate-400 mr-2" />
          <input 
            type="text" 
            placeholder="Cari data arsip (Nama, NIK, KK)..."
            className="bg-transparent border-none outline-none text-sm w-full font-medium"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="text-xs font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-4 py-2 rounded-lg border border-slate-100">
          Total Arsip: {archivedData.length} Jiwa
        </div>
      </div>

      <div className="bg-white rounded-3xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1000px]">
            <thead className="bg-slate-900 text-white">
              <tr>
                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest">Identitas</th>
                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest">Biodata</th>
                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest">Status & Tanggal</th>
                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest">Keterangan</th>
                <th className="px-6 py-4 text-[10px] font-black uppercase tracking-widest text-center">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {archivedData.length > 0 ? archivedData.map((r) => (
                <tr key={r.id} className="hover:bg-slate-50 transition-all group">
                  <td className="px-6 py-5">
                    <div className="text-sm font-black text-slate-900 font-mono tracking-tighter">{r.nik}</div>
                    <div className="text-[10px] text-slate-400 font-bold uppercase">{r.noKK}</div>
                  </td>
                  <td className="px-6 py-5">
                    <div className="text-sm font-black uppercase text-slate-800">{r.fullName}</div>
                    <div className="text-[10px] text-slate-500 font-medium italic">{calculateAge(r.birthDate)} Thn · {r.gender}</div>
                  </td>
                  <td className="px-6 py-5">
                    <div className="flex flex-col space-y-1">
                      <span className={`px-4 py-1.5 rounded-full text-[10px] font-black uppercase flex items-center space-x-2 w-fit ${
                        r.status === 'Meninggal' ? 'bg-rose-100 text-rose-700' : 'bg-amber-100 text-amber-700'
                      }`}>
                        {r.status === 'Meninggal' ? <Skull size={12} /> : <PlaneLanding size={12} />}
                        <span>{r.status}</span>
                      </span>
                      <div className="flex items-center text-[10px] font-bold text-slate-400 mt-1 uppercase">
                         <Calendar size={12} className="mr-1" />
                         {formatDate(r.status === 'Meninggal' ? r.deathDate! : r.moveDate!)}
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-5">
                    {r.status === 'Pindah' ? (
                      <div className="flex items-start space-x-2">
                        <MapPin size={14} className="text-slate-400 mt-0.5 shrink-0" />
                        <div>
                          <div className="text-[10px] font-black text-slate-400 uppercase tracking-tighter">Tujuan Pindah:</div>
                          <div className="text-xs font-bold text-slate-600 italic">{r.moveDestination || '-'}</div>
                        </div>
                      </div>
                    ) : (
                      <div className="text-xs text-slate-400 italic font-medium">Data arsip kematian penduduk</div>
                    )}
                  </td>
                  <td className="px-6 py-5">
                    <div className="flex items-center justify-center space-x-2">
                       <button 
                         onClick={() => restoreResident(r.id)}
                         className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                         title="Pulihkan Data"
                       >
                         <History size={18} />
                       </button>
                       <button 
                         onClick={() => deletePermanently(r.id)}
                         className="p-2.5 bg-rose-50 text-rose-400 hover:bg-red-600 hover:text-white transition-all shadow-sm"
                         title="Hapus Permanen"
                       >
                         <Trash2 size={18} />
                       </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr><td colSpan={5} className="px-6 py-20 text-center text-slate-400 font-black uppercase tracking-widest">Tidak ada data arsip.</td></tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default ArchivedResidents;

import React, { useState } from 'react';
import { X, User, Printer, CheckCircle2, UserPlus, Save, Skull, PlaneLanding, ArrowUpRight, Trash2, MapPin, Calendar, AlertCircle } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge } from '../utils/helpers';
import EditResidentModal from './EditResidentModal';

interface FamilyDetailModalProps {
  noKK: string;
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
  onClose: () => void;
}

const FamilyDetailModal: React.FC<FamilyDetailModalProps> = ({ noKK, residents, setResidents, onClose }) => {
  const [editingMember, setEditingMember] = useState<Resident | null>(null);
  const [isAddingMember, setIsAddingMember] = useState(false);
  const [statusAction, setStatusAction] = useState<{ member: Resident, type: 'Meninggal' | 'Pindah' } | null>(null);

  const familyMembers = residents.filter(r => r.noKK === noKK && r.status === 'Aktif');
  const headOfFamily = familyMembers.find(r => r.isHeadOfFamily) || familyMembers[0];

  const handleUpdateMember = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingMember(null);
  };

  const handleAddMember = (newMember: Resident) => {
    setResidents(prev => [...prev, { ...newMember, status: 'Aktif' }]);
    setIsAddingMember(false);
  };

  const finalizeStatusChange = (data: { date: string, destination?: string }) => {
    if (!statusAction) return;

    setResidents(prev => prev.map(r => {
      if (r.id === statusAction.member.id) {
        return { 
          ...r, 
          status: statusAction.type,
          deathDate: statusAction.type === 'Meninggal' ? data.date : undefined,
          moveDate: statusAction.type === 'Pindah' ? data.date : undefined,
          moveDestination: statusAction.type === 'Pindah' ? data.destination : undefined
        };
      }
      return r;
    }));
    setStatusAction(null);

    // Jika yang pindah/meninggal adalah kepala keluarga tunggal, mungkin ingin memberikan notifikasi
    if (statusAction.member.isHeadOfFamily) {
      alert("Kepala Keluarga telah diarsipkan. Harap tentukan Kepala Keluarga baru untuk anggota keluarga yang tersisa agar tetap muncul di daftar utama.");
    }
  };

  const deleteMember = (member: Resident) => {
    if (window.confirm(`PERINGATAN: Hapus data ${member.fullName} secara permanen dari sistem? Tindakan ini tidak dapat dibatalkan.`)) {
      setResidents(prev => prev.filter(r => r.id !== member.id));
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-6xl max-h-[92vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-300 border border-slate-200">

        {/* Header */}
        <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-white no-print">
          <div className="flex items-center space-x-6">
            <div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-slate-200">
              <User size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Daftar Anggota Keluarga</h3>
              <p className="text-slate-400 text-[10px] font-bold font-mono tracking-widest mt-2">NO. KK: {noKK}</p>
            </div>
          </div>
          <div className="flex items-center space-x-3">
            <button 
              onClick={() => setIsAddingMember(true)}
              className="flex items-center space-x-2 px-6 py-3 bg-emerald-600 text-white rounded-2xl text-xs font-black hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-500/10"
            >
              <UserPlus size={18} />
              <span>TAMBAH ANGGOTA</span>
            </button>
            <button onClick={() => window.print()} className="p-3 bg-slate-100 text-slate-600 hover:bg-slate-200 rounded-2xl transition-all">
              <Printer size={20} />
            </button>
            <button onClick={onClose} className="p-3 bg-slate-100 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/20">

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 no-print">
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">Kepala Keluarga</p>
                <p className="text-md font-black text-slate-900 uppercase truncate max-w-[150px]">{headOfFamily?.fullName || '-'}</p>
              </div>
              <CheckCircle2 size={18} className="text-blue-500" />
            </div>
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">Total Jiwa Aktif</p>
                <p className="text-lg font-black text-slate-900">{familyMembers.length} Orang</p>
              </div>
              <ArrowUpRight size={18} className="text-slate-200" />
            </div>
