import React, { useState } from 'react';
import { X, User, Printer, CheckCircle2, UserPlus, Save, Skull, ArrowUpRight, Trash2, Calendar, AlertCircle } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge } from '../utils/helpers';
import EditResidentModal from './EditResidentModal';

interface FamilyDetailModalProps {
  noKK: string;
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
  onClose: () => void;
}

const FamilyDetailModal: React.FC<FamilyDetailModalProps> = ({ noKK, residents, setResidents, onClose }) => {
  const [editingMember, setEditingMember] = useState<Resident | null>(null);
  const [isAddingMember, setIsAddingMember] = useState(false);
  const [statusAction, setStatusAction] = useState<{ member: Resident, type: 'Meninggal' } | null>(null);

  const familyMembers = residents.filter(r => r.noKK === noKK && r.status === 'Aktif');
  const headOfFamily = familyMembers.find(r => r.isHeadOfFamily) || familyMembers[0];

  const handleUpdateMember = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingMember(null);
  };

  const handleAddMember = (newMember: Resident) => {
    setResidents(prev => [...prev, { ...newMember, status: 'Aktif' }]);
    setIsAddingMember(false);
  };

  const finalizeStatusChange = (data: { date: string }) => {
    if (!statusAction) return;

    setResidents(prev => prev.map(r => {
      if (r.id === statusAction.member.id) {
        return { 
          ...r, 
          status: 'Meninggal',
          deathDate: data.date
        };
      }
      return r;
    }));
    setStatusAction(null);

    if (statusAction.member.isHeadOfFamily && familyMembers.length > 1) {
      alert("Kepala Keluarga telah diarsipkan (Meninggal Dunia). Harap tentukan Kepala Keluarga baru dari anggota yang tersisa.");
    }
  };

  const deleteMember = (member: Resident) => {
    if (window.confirm(`PERINGATAN: Hapus data ${member.fullName} secara permanen dari sistem?`)) {
      setResidents(prev => prev.filter(r => r.id !== member.id));
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-6xl max-h-[92vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-300 border border-slate-200">

        {/* Header */}
        <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-white no-print">
          <div className="flex items-center space-x-6">
            <div className="w-14 h-14 bg-slate-900 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-slate-200">
              <User size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Daftar Anggota Keluarga</h3>
              <p className="text-slate-400 text-[10px] font-bold font-mono tracking-widest mt-2 uppercase">NO. KK: {noKK}</p>
            </div>
          </div>
          <div className="flex items-center space-x-3">
            <button 
              onClick={() => setIsAddingMember(true)}
              className="flex items-center space-x-2 px-6 py-3 bg-emerald-600 text-white rounded-2xl text-xs font-black hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-500/10"
            >
              <UserPlus size={18} />
              <span>TAMBAH ANGGOTA</span>
            </button>
            <button onClick={() => window.print()} className="p-3 bg-slate-100 text-slate-600 hover:bg-slate-200 rounded-2xl transition-all">
              <Printer size={20} />
            </button>
            <button onClick={onClose} className="p-3 bg-slate-100 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* Content */}
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/20">

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 no-print">
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">Kepala Keluarga</p>
                <p className="text-md font-black text-slate-900 uppercase truncate max-w-[150px]">{headOfFamily?.fullName || '-'}</p>
              </div>
              <CheckCircle2 size={18} className="text-blue-500" />
            </div>
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">Total Jiwa Aktif</p>
                <p className="text-lg font-black text-slate-900">{familyMembers.length} Orang</p>
              </div>
              <ArrowUpRight size={18} className="text-slate-200" />
            </div>
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex items-center justify-between">
              <div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-widest mb-1">Wilayah / RT</p>
                <p className="text-md font-black text-slate-900">{headOfFamily?.dusun || '-'} / RT {headOfFamily?.rt || '-'}</p>
              </div>
              <ArrowUpRight size={18} className="text-slate-200" />
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between mb-2 px-2">
               <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest">Jiwa Terdaftar Aktif</h4>
               <span className="text-[10px] text-blue-600 font-bold bg-blue-50 px-3 py-1 rounded-full animate-pulse">* Klik NIK untuk Edit Data Individu</span>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {familyMembers.length > 0 ? familyMembers.sort((a,b) => (a.isHeadOfFamily ? -1 : 1)).map((m) => (
                <div key={m.id} className="bg-white p-2 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md hover:border-blue-200 transition-all duration-300">
                  <div className="flex flex-col md:flex-row md:items-center">
                    <div className={`px-6 py-4 md:w-44 text-center md:text-left ${m.isHeadOfFamily ? 'bg-slate-900 text-white shadow-lg' : 'bg-slate-50 text-slate-400'} rounded-2xl md:mr-6`}>
                      <span className="text-[9px] font-black uppercase tracking-widest leading-none">{m.relationship.includes('.') ? m.relationship.split('. ')[1] : m.relationship}</span>
                    </div>

                    <div className="flex-1 p-4 grid grid-cols-2 md:grid-cols-4 gap-4 items-center">
                      <div>
                        <button onClick={() => setEditingMember(m)} className="text-xs font-black font-mono text-blue-600 hover:underline">
                          {m.nik}
                        </button>
                        <h5 className="text-sm font-black text-slate-900 uppercase mt-1 truncate">{m.fullName}</h5>
                      </div>

                      <div className="text-center md:text-left">
                        <p className="text-[8px] text-slate-400 font-black uppercase mb-1 tracking-tighter">Jenis Kelamin</p>
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${m.gender.includes('Perempuan') || m.gender.includes('2') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                          {m.gender.includes('Laki-laki') || m.gender.includes('1') ? 'Laki-laki' : 'Perempuan'}
                        </span>
                      </div>

                      <div className="text-center md:text-left">
                        <p className="text-[8px] text-slate-400 font-black uppercase mb-1 tracking-tighter">Usia</p>
                        <p className="text-sm font-black text-slate-900">{calculateAge(m.birthDate)} <span className="font-normal text-slate-400">Thn</span></p>
                      </div>

                      <div className="flex justify-center md:justify-end space-x-2">
                         <button 
                           onClick={() => setStatusAction({ member: m, type: 'Meninggal' })}
                           className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-rose-600 transition-all shadow-sm group"
                           title="Meninggal Dunia"
                         >
                            <Skull size={18} className="group-hover:animate-pulse" />
                         </button>
                         <button 
                           onClick={() => deleteMember(m)}
                           className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"
                           title="Hapus Permanen"
                         >
                            <Trash2 size={18} />
                         </button>
                      </div>
                    </div>
                  </div>
                </div>
              )) : (
                <div className="text-center py-20 bg-white rounded-[2rem] border border-dashed border-slate-200 text-slate-400 font-black uppercase tracking-widest text-xs">Tidak ada data anggota keluarga aktif.</div>
              )}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-8 border-t border-slate-100 bg-white flex justify-between items-center no-print">
          <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">SIGA Ngumbul - Terintegrasi Desa Ngumbul</div>
          <button onClick={onClose} className="px-12 py-4 bg-slate-900 text-white rounded-[1.5rem] text-sm font-black hover:bg-slate-800 shadow-xl transition-all">
            Tutup Rincian
          </button>
        </div>

        {editingMember && <EditResidentModal resident={editingMember} onClose={() => setEditingMember(null)} onSave={handleUpdateMember} />}
        {isAddingMember && <InternalAddMemberModal noKK={noKK} familyBase={headOfFamily} onClose={() => setIsAddingMember(false)} onSave={handleAddMember} />}
        {statusAction && <DeathStatusModal member={statusAction.member} onClose={() => setStatusAction(null)} onConfirm={finalizeStatusChange} />}
      </div>
    </div>
  );
};

