import React, { useState, useMemo } from 'react';
import { Search, MapPin, Skull, PlaneLanding, History, Trash2, Calendar, FileText, Eye } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, formatDate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';

interface ArchivedResidentsProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const ArchivedResidents: React.FC<ArchivedResidentsProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [subTab, setSubTab] = useState<'Meninggal' | 'Pindah'>('Meninggal');
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);

  const filteredArchivedData = useMemo(() => {
    return residents.filter(r => {
      const matchStatus = r.status === subTab;
      // Jika tab Pindah, hanya tampilkan Kepala Keluarga saja
      const matchLevel = subTab === 'Pindah' ? r.isHeadOfFamily : true;
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);

      return matchStatus && matchLevel && matchSearch;
    });
  }, [residents, searchTerm, subTab]);

  const restoreData = (item: Resident) => {
    const msg = subTab === 'Pindah' 
      ? `Pulihkan seluruh keluarga ${item.fullName} (KK: ${item.noKK}) ke status Aktif?`
      : `Pulihkan ${item.fullName} ke status Aktif?`;

    if (window.confirm(msg)) {
      setResidents(prev => prev.map(r => {
        const shouldRestore = subTab === 'Pindah' ? r.noKK === item.noKK : r.id === item.id;
        if (shouldRestore) {
          return { 
            ...r, 
            status: 'Aktif', 
            deathDate: undefined, 
            moveDate: undefined, 
            moveDestination: undefined 
          };
        }
        return r;
      }));
    }
  };

  const deletePermanently = (item: Resident) => {
    const msg = subTab === 'Pindah' 
      ? `Hapus PERMANEN seluruh data keluarga ${item.fullName} (KK: ${item.noKK})? Tindakan ini tidak bisa dibatalkan.`
      : `Hapus PERMANEN data ${item.fullName}? Tindakan ini tidak bisa dibatalkan.`;

    if (window.confirm(msg)) {
      setResidents(prev => prev.filter(r => {
        const shouldDelete = subTab === 'Pindah' ? r.noKK === item.noKK : r.id === item.id;
        return !shouldDelete;
      }));
    }
  };

  return (
    <div className="space-y-6">
      {/* Sub Navigation Tabs */}
      <div className="flex items-center space-x-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-200 w-fit">
        <button 
          onClick={() => setSubTab('Meninggal')}
          className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase transition-all ${
            subTab === 'Meninggal' 
              ? 'bg-rose-600 text-white shadow-lg shadow-rose-200' 
              : 'text-slate-400 hover:bg-slate-50'
          }`}
        >
          <Skull size={16} />
          <span>Data Kematian</span>
        </button>
        <button 
          onClick={() => setSubTab('Pindah')}
          className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase transition-all ${
            subTab === 'Pindah' 
              ? 'bg-amber-500 text-white shadow-lg shadow-amber-200' 
              : 'text-slate-400 hover:bg-slate-50'
          }`}
        >
          <PlaneLanding size={16} />
          <span>Data Kepindahan (Keluarga)</span>
        </button>
      </div>

      <div className="bg-white p-4 rounded-3xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex-1 flex items-center bg-slate-50 rounded-2xl px-5 py-3 border border-slate-100 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-slate-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder={`Cari ${subTab === 'Pindah' ? 'Kepala Keluarga' : 'penduduk'}...`}
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex items-center space-x-4">
           <div className="text-right">
              <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest leading-none mb-1">Total {subTab === 'Pindah' ? 'KK Pindah' : 'Jiwa Meninggal'}</p>
              <p className="text-xl font-black text-slate-900 leading-none">{filteredArchivedData.length} <span className="text-xs font-normal">{subTab === 'Pindah' ? 'Keluarga' : 'Jiwa'}</span></p>
           </div>
           <button onClick={() => window.print()} className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-slate-800 transition-all">
              <FileText size={20} />
           </button>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1000px]">
            <thead className={`${subTab === 'Meninggal' ? 'bg-rose-50' : 'bg-amber-50'} border-b border-slate-100`}>
              <tr>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">Identitas {subTab === 'Pindah' ? 'KK' : ''}</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">{subTab === 'Pindah' ? 'Kepala Keluarga' : 'Nama Lengkap'}</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">Usia / JK</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">
                  {subTab === 'Meninggal' ? 'Tanggal Meninggal' : 'Tanggal Pindah'}
                </th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">
                  {subTab === 'Meninggal' ? 'Keterangan' : 'Tujuan Pindah'}
                </th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredArchivedData.length > 0 ? filteredArchivedData.map((r) => (
                <tr key={r.id} className="hover:bg-slate-50 transition-all group">
                  <td className="px-6 py-6">
                    <div className="text-[10px] font-bold text-slate-400 font-mono tracking-tighter mb-1">{r.noKK}</div>
                    <div className="text-[10px] text-slate-400 font-medium italic">{r.nik}</div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="text-sm font-black uppercase text-slate-800">{r.fullName}</div>
                    {subTab === 'Pindah' && (
                       <div className="text-[10px] text-slate-500 font-bold uppercase mt-0.5">{r.dusun} · RT {r.rt}/RW {r.rw}</div>
                    )}
                  </td>
                  <td className="px-6 py-6">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="font-normal text-slate-400">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender.includes('Perempuan') || r.gender.includes('2') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                      {r.gender.includes('Laki-laki') || r.gender.includes('1') ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex items-center text-sm font-bold text-slate-700">
                      <Calendar size={16} className="mr-2 text-slate-400" />
                      {formatDate(subTab === 'Meninggal' ? r.deathDate! : r.moveDate!)}
                    </div>
                  </td>
                  <td className="px-6 py-6">
                    {subTab === 'Pindah' ? (
                      <div className="flex items-start space-x-2 bg-slate-50 p-3 rounded-2xl border border-slate-100 max-w-xs">
                        <MapPin size={16} className="text-amber-500 mt-0.5 shrink-0" />
                        <div className="text-xs font-bold text-slate-600 leading-relaxed">{r.moveDestination || 'Tujuan tidak diisi'}</div>
                      </div>
                    ) : (
                      <div className="flex items-center space-x-2 text-xs font-bold text-slate-400 italic">
                        <Skull size={14} />
                        <span>Arsip Kematian</span>
                      </div>
                    )}
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex items-center justify-center space-x-2 opacity-100 md:opacity-0 group-hover:opacity-100 transition-opacity">
                       {subTab === 'Pindah' && (
                         <button 
                           onClick={() => setViewingFamilyKK(r.noKK)}
                           className="p-3 bg-slate-100 text-slate-600 rounded-2xl hover:bg-slate-900 hover:text-white transition-all shadow-sm"
                           title="Lihat Anggota Keluarga"
                         >
                           <Eye size={18} />
                         </button>
                       )}
                       <button 
                         onClick={() => restoreData(r)}
                         className="p-3 bg-blue-50 text-blue-600 rounded-2xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"
                         title="Pulihkan Data"
                       >
                         <History size={18} />
                       </button>
                       <button 
                         onClick={() => deletePermanently(r)}
                         className="p-3 bg-rose-50 text-rose-400 hover:bg-red-600 hover:text-white transition-all shadow-sm"
                         title="Hapus Permanen"
                       >
                         <Trash2 size={18} />
                       </button>
                    </div>
                  </td>
                </tr>
              )) : (
                <tr>
                  <td colSpan={6} className="px-6 py-24 text-center">
                    <div className="flex flex-col items-center space-y-3">
                       <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center text-slate-200">
                          {subTab === 'Meninggal' ? <Skull size={32} /> : <PlaneLanding size={32} />}
                       </div>
                       <p className="text-slate-400 font-black uppercase tracking-widest text-xs">Data {subTab.toLowerCase()} tidak ditemukan.</p>
                    </div>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {viewingFamilyKK && (
        <FamilyDetailModal 
          noKK={viewingFamilyKK} 
          residents={residents} 
          setResidents={setResidents} 
          onClose={() => setViewingFamilyKK(null)} 
        />
      )}
    </div>
  );
};

export default ArchivedResidents;

import React, { useState } from 'react';
