                      <div>
                        {currentViewStatus === 'Aktif' ? (
                          <button onClick={() => setEditingMember(m)} className="text-xs font-black font-mono text-blue-600 hover:underline">
                            {m.nik}
                          </button>
                        ) : (
                          <div className="text-xs font-black font-mono text-slate-400">{m.nik}</div>
                        )}
                        <h5 className="text-sm font-black text-slate-900 uppercase mt-1 truncate">{m.fullName}</h5>
                      </div>

                      <div className="text-center md:text-left">
                        <p className="text-[8px] text-slate-400 font-black uppercase mb-1 tracking-tighter">Jenis Kelamin</p>
                        <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase ${m.gender.includes('Perempuan') || m.gender.includes('2') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                          {m.gender.includes('Laki-laki') || m.gender.includes('1') ? 'L' : 'P'}
                        </span>
                      </div>

                      <div className="text-center md:text-left">
                        <p className="text-[8px] text-slate-400 font-black uppercase mb-1 tracking-tighter">Usia</p>
                        <p className="text-sm font-black text-slate-900">{calculateAge(m.birthDate)} <span className="font-normal text-slate-400">Thn</span></p>
                      </div>

                      <div className="flex justify-center md:justify-end space-x-2">
                         {currentViewStatus === 'Aktif' && (
                           <>
                             <button 
                               onClick={() => setStatusAction({ member: m, type: 'Meninggal' })}
                               className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-rose-600 transition-all shadow-sm group"
                               title="Meninggal Dunia"
                             >
                                <Skull size={18} className="group-hover:animate-pulse" />
                             </button>
                             <button 
                               onClick={() => deleteMember(m)}
                               className="p-3 bg-rose-50 text-rose-600 rounded-2xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"
                               title="Hapus Permanen"
                             >
                                <Trash2 size={18} />
                             </button>
                           </>
                         )}
                         {currentViewStatus === 'Pindah' && (
                           <div className="text-[9px] font-black text-slate-300 uppercase italic">Arsip Pindah</div>
                         )}
                      </div>
                    </div>
                  </div>
                </div>
              )) : (
                <div className="text-center py-20 bg-white rounded-[2rem] border border-dashed border-slate-200 text-slate-400 font-black uppercase tracking-widest text-xs">Tidak ada data anggota keluarga aktif.</div>
              )}
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="p-8 border-t border-slate-100 bg-white flex justify-between items-center no-print">
          <div className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">SIGA Ngumbul - Administrasi Desa</div>
          <button onClick={onClose} className={`px-12 py-4 ${currentViewStatus === 'Pindah' ? 'bg-amber-500' : 'bg-slate-900'} text-white rounded-[1.5rem] text-sm font-black hover:opacity-90 shadow-xl transition-all`}>
            Tutup Rincian
          </button>
        </div>

        {editingMember && <EditResidentModal resident={editingMember} onClose={() => setEditingMember(null)} onSave={handleUpdateMember} />}
        {isAddingMember && <InternalAddMemberModal noKK={noKK} familyBase={headOfFamily} onClose={() => setIsAddingMember(false)} onSave={handleAddMember} />}
        {statusAction && <DeathStatusModal member={statusAction.member} onClose={() => setStatusAction(null)} onConfirm={finalizeStatusChange} />}
      </div>
    </div>
  );
};

