import React, { useState, useMemo } from 'react';
import { Search, MapPin, Skull, PlaneLanding, History, Trash2, Calendar, FileText, Eye } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, formatDate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';

interface ArchivedResidentsProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const ArchivedResidents: React.FC<ArchivedResidentsProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [subTab, setSubTab] = useState<'Meninggal' | 'Pindah'>('Meninggal');
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);

  const filteredArchivedData = useMemo(() => {
    return residents.filter(r => {
      const matchStatus = r.status === subTab;
      const matchLevel = subTab === 'Pindah' ? r.isHeadOfFamily : true;
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);
      return matchStatus && matchLevel && matchSearch;
    });
  }, [residents, searchTerm, subTab]);

  const restoreData = (item: Resident) => {
    const msg = subTab === 'Pindah' 
      ? `Pulihkan seluruh keluarga ${item.fullName} (KK: ${item.noKK})?`
      : `Pulihkan ${item.fullName} ke status Aktif?`;

    if (window.confirm(msg)) {
      setResidents(prev => prev.map(r => {
        const shouldRestore = subTab === 'Pindah' ? r.noKK === item.noKK : r.id === item.id;
        if (shouldRestore) {
          return { 
            ...r, 
            status: 'Aktif', 
            deathDate: undefined, 
            moveDate: undefined, 
            moveDestination: undefined 
          };
        }
        return r;
      }));
    }
  };

  const deletePermanently = (item: Resident) => {
    const msg = subTab === 'Pindah' 
      ? `Hapus PERMANEN keluarga ${item.fullName}? Data tidak dapat dipulihkan!`
      : `Hapus PERMANEN data ${item.fullName}? Data tidak dapat dipulihkan!`;

    if (window.confirm(msg)) {
      setResidents(prev => prev.filter(r => {
        const shouldDelete = subTab === 'Pindah' ? r.noKK === item.noKK : r.id === item.id;
        return !shouldDelete;
      }));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-200 w-fit">
        <button onClick={() => setSubTab('Meninggal')} className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase transition-all ${subTab === 'Meninggal' ? 'bg-rose-600 text-white' : 'text-slate-400'}`}>
          <Skull size={16} />
          <span>Data Kematian</span>
        </button>
        <button onClick={() => setSubTab('Pindah')} className={`flex items-center space-x-2 px-6 py-2.5 rounded-xl text-xs font-black uppercase transition-all ${subTab === 'Pindah' ? 'bg-amber-500 text-white' : 'text-slate-400'}`}>
          <PlaneLanding size={16} />
          <span>Data Pindah (KK)</span>
        </button>
      </div>

      <div className="bg-white p-4 rounded-3xl shadow-sm border border-slate-200 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex-1 flex items-center bg-slate-50 rounded-2xl px-5 py-3 border border-slate-100 max-w-md">
          <Search size={18} className="text-slate-400 mr-3" />
          <input type="text" placeholder={`Cari di arsip...`} className="bg-transparent border-none outline-none text-sm w-full font-bold" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1000px]">
            <thead className={`${subTab === 'Meninggal' ? 'bg-rose-50' : 'bg-amber-50'} border-b border-slate-100`}>
              <tr>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">No. KK / NIK</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">Nama</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">Tgl {subTab}</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500">Ket / Tujuan</th>
                <th className="px-6 py-5 text-[10px] font-black uppercase tracking-widest text-slate-500 text-center">Aksi</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredArchivedData.map((r) => (
                <tr key={r.id} className="hover:bg-slate-50 transition-all group">
                  <td className="px-6 py-6">
                    <div className="text-[10px] font-bold text-slate-400 font-mono">{r.noKK}</div>
                    <div className="text-[10px] text-slate-300">{r.nik}</div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="text-sm font-black uppercase text-slate-800">{r.fullName}</div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="text-sm font-bold text-slate-700">{formatDate(subTab === 'Meninggal' ? r.deathDate! : r.moveDate!)}</div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="text-xs font-bold text-slate-500 max-w-xs truncate">{subTab === 'Pindah' ? r.moveDestination : 'Kematian Penduduk'}</div>
                  </td>
                  <td className="px-6 py-6">
                    <div className="flex items-center justify-center space-x-2">
                       {subTab === 'Pindah' && <button onClick={() => setViewingFamilyKK(r.noKK)} className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all"><Eye size={16} /></button>}
                       <button onClick={() => restoreData(r)} className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all"><History size={16} /></button>
                       <button onClick={() => deletePermanently(r)} className="p-2.5 bg-rose-50 text-rose-400 rounded-xl hover:bg-red-600 hover:text-white transition-all"><Trash2 size={16} /></button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
    </div>
  );
};

