            <div>
              <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">{currentViewStatus === 'Pindah' ? 'Arsip Pindah' : 'Daftar Keluarga'}</h3>
              <p className="text-slate-400 text-[10px] font-bold font-mono tracking-widest mt-2 uppercase">KK: {noKK}</p>
            </div>
          </div>
          <div className="flex items-center space-x-3">
            {currentViewStatus === 'Aktif' && (
              <button onClick={() => setIsAddingMember(true)} className="flex items-center space-x-2 px-6 py-3 bg-emerald-600 text-white rounded-2xl text-[10px] font-black hover:bg-emerald-700 transition-all uppercase tracking-widest">
                <UserPlus size={16} />
                <span>Tambah Jiwa</span>
              </button>
