          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/20">
          <div className="grid grid-cols-1 gap-4">
            {familyMembers.length > 0 ? familyMembers.map((m) => (
              <div key={m.id} className="bg-white p-3 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row md:items-center">
                <div className={`px-6 py-4 md:w-44 text-center md:text-left ${m.isHeadOfFamily ? (currentViewStatus === 'Pindah' ? 'bg-amber-500' : 'bg-slate-900') : 'bg-slate-100 text-slate-400'} text-white rounded-2xl md:mr-6 font-black text-[10px] uppercase tracking-widest`}>
                  {m.relationship.split('. ')[1] || m.relationship}
                </div>
                <div className="flex-1 p-2 grid grid-cols-2 md:grid-cols-4 gap-4 items-center">
                  <div>
                    <button onClick={() => setEditingMember(m)} className="text-xs font-black text-blue-600 hover:underline">{m.nik}</button>
                    <h5 className="text-sm font-black text-slate-900 uppercase truncate">{m.fullName}</h5>
                  </div>
                  <div className="text-xs font-bold text-slate-500 uppercase">{m.gender}</div>
                  <div className="text-sm font-black text-slate-900">{calculateAge(m.birthDate)} <span className="text-[10px] font-normal text-slate-400">Thn</span></div>
                  <div className="flex justify-end space-x-2">
                    {currentViewStatus === 'Aktif' && (
                      <>
                        <button onClick={() => setDeathConfirm(m)} className="p-2.5 bg-slate-100 text-slate-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all"><Skull size={16} /></button>
                        <button onClick={() => deleteMember(m)} className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all"><Trash2 size={16} /></button>
                      </>
                    )}
                  </div>
                </div>
              </div>
            )) : <div className="text-center py-20 text-slate-400 font-black uppercase text-xs tracking-widest">Tidak ada data aktif.</div>}
          </div>
        </div>

        {editingMember && <EditResidentModal resident={editingMember} onClose={() => setEditingMember(null)} onSave={handleUpdateMember} />}
        {isAddingMember && <InternalAddMemberModal noKK={noKK} familyBase={headOfFamily} onClose={() => setIsAddingMember(false)} onSave={handleAddMember} />}
        {deathConfirm && <DeathModal member={deathConfirm} onClose={() => setDeathConfirm(null)} onConfirm={archiveDeath} />}
      </div>
    </div>
  );
};

