const App: React.FC = () => {
  // Gunakan lazy initialization untuk mencegah data terhapus saat start-up
  const [residents, setResidents] = useState<Resident[]>(() => {
    const saved = localStorage.getItem('siga_residents');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Migrasi status jika belum ada
        return parsed.map((r: any) => ({ ...r, status: r.status || 'Aktif' }));
      } catch (e) {
        console.error("Gagal memuat data penduduk:", e);
        return initialResidents;
      }
    }
    return initialResidents;
  });

  const [config, setConfig] = useState<AppConfig>(() => {
    const saved = localStorage.getItem('siga_config');
    if (saved) {
      try {
        return JSON.parse(saved);
      } catch (e) {
        return {
          appName: 'SIGA Ngumbul',
          subtitle: 'Kec. Todanan, Kab. Blora',
          logoUrl: 'https://upload.wikimedia.org/wikipedia/commons/1/1d/Lambang_Kabupaten_Blora.png',
          developerInfo: 'Tim TI Desa Ngumbul 2024'
        };
      }
    }
    return {
      appName: 'SIGA Ngumbul',
      subtitle: 'Kec. Todanan, Kab. Blora',
      logoUrl: 'https://upload.wikimedia.org/wikipedia/commons/1/1d/Lambang_Kabupaten_Blora.png',
      developerInfo: 'Tim TI Desa Ngumbul 2024'
    };
  });

  const [activeTab, setActiveTab] = useState('dashboard');

  // Simpan data setiap kali ada perubahan pada state residents
  useEffect(() => {
    localStorage.setItem('siga_residents', JSON.stringify(residents));
  }, [residents]);

  // Simpan konfigurasi setiap kali ada perubahan pada state config
  useEffect(() => {
    localStorage.setItem('siga_config', JSON.stringify(config));
  }, [config]);

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return <Dashboard residents={residents.filter(r => r.status === 'Aktif')} />;
      case 'penduduk':
        return <PopulationManagement residents={residents} setResidents={setResidents} />;
      case 'arsip':
        return <ArchivedResidents residents={residents} setResidents={setResidents} />;
      case 'rekap':
        return <RecapIndicators residents={residents.filter(r => r.status === 'Aktif')} />;
      case 'profil':
        return <AppSettings config={config} setConfig={setConfig} />;
      default:
        return <Dashboard residents={residents.filter(r => r.status === 'Aktif')} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab} config={config}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  Upload,
  BookOpen,
  Loader2,
  PlaneLanding,
  Calendar,
  MapPin,
  X,
  AlertCircle,
  Edit3,
  Filter
} from 'lucide-react';
import { Resident, BloodType, MaritalStatus, Education } from '../types';
import { calculateAge, downloadTemplate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [filters, setFilters] = useState({ dusun: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [movingFamily, setMovingFamily] = useState<Resident | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);
  const dusuns = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))), [activeResidents]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const s = searchTerm.toLowerCase();
      const matchSearch = 
        r.fullName.toLowerCase().includes(s) ||
        r.nik.includes(s) ||
        r.noKK.includes(s);
      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      return matchSearch && matchDusun;
    });
  }, [headOfFamilies, searchTerm, filters.dusun]);

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length && filteredData.length > 0) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDeleteFamily = (resident: Resident) => {
    if (window.confirm(`Hapus seluruh data keluarga ${resident.fullName} (No. KK: ${resident.noKK}) secara permanen?`)) {
      const targetKK = resident.noKK;
      setResidents(prev => prev.filter(r => r.noKK !== targetKK));
      setSelectedIds(prev => prev.filter(i => i !== resident.id));
    }
  };

  const handleDeleteMultiple = () => {
    const kksToDelete = headOfFamilies
      .filter(r => selectedIds.includes(r.id))
      .map(r => r.noKK);

    if (kksToDelete.length === 0) return;

    if (window.confirm(`Hapus ${kksToDelete.length} keluarga terpilih beserta seluruh anggotanya secara permanen?`)) {
      setResidents(prev => prev.filter(r => !kksToDelete.includes(r.noKK)));
      setSelectedIds([]);
    }
  };

  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  const handleAddSave = (newResidents: Resident[]) => {
    setResidents(prev => [...prev, ...newResidents]);
    setIsAddModalOpen(false);
  };

  const finalizeMoveFamily = (data: { date: string, destination: string }) => {
    if (!movingFamily) return;
    const targetKK = movingFamily.noKK;
    setResidents(prev => prev.map(r => {
      if (r.noKK === targetKK) {
        return { 
          ...r, 
          status: 'Pindah',
          moveDate: data.date,
          moveDestination: data.destination
        };
      }
      return r;
    }));
    setMovingFamily(null);
    setSelectedIds(prev => prev.filter(i => i !== movingFamily.id));
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
        const newResidents: Resident[] = lines.slice(1).map((line, index) => {
          const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => item[h] = values[i] || '');
          const rel = item['Status Hubungan dalam Keluarga'] || '';
          return {
            id: `imp-${Date.now()}-${index}`,
            dusun: item['Dusun'] || '-',
            rt: item['RT'] || '-',
            rw: item['RW'] || '-',
            noKK: (item['No.KK'] || '').replace(/\D/g, ''),
            nik: (item['NIK'] || '').replace(/\D/g, ''),
            fullName: (item['Nama Lengkap'] || '-').toUpperCase(),
            relationship: rel,
            birthPlace: '', 
            birthDate: item['Tanggal Lahir'] || '1990-01-01',
            gender: (item['Jenis Kelamin'] || '').includes('P') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: rel.toLowerCase().includes('kepala keluarga') || rel.startsWith('1'),
            status: 'Aktif'
          };
        });
        setResidents(prev => [...prev, ...newResidents]);
        setIsImporting(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      } catch (err) {
        alert('Format file CSV tidak sesuai atau rusak.');
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
             <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
             <h3 className="text-xl font-black text-slate-900 mt-4 tracking-widest uppercase">Sinkronisasi Data...</h3>
          </div>
        </div>
      )}

      {/* Baris Pencarian & Tombol Aksi */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-2xl px-5 py-3 border border-slate-200 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Kepala Keluarga / NIK / No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={downloadTemplate}
            className="flex items-center space-x-2 px-5 py-3 bg-white border border-slate-200 rounded-2xl text-[10px] font-black text-slate-700 hover:bg-slate-50 transition-all uppercase tracking-widest"
          >
            <BookOpen size={16} />
            <span>Format Data</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-3 bg-blue-50 border border-blue-200 rounded-2xl text-[10px] font-black text-blue-700 hover:bg-blue-100 transition-all cursor-pointer uppercase tracking-widest">
            <Upload size={16} />
            <span>Import CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleImport} accept=".csv" />
          </label>

          <button 
            onClick={() => setIsAddModalOpen(true)}
            className="flex items-center space-x-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black hover:bg-slate-800 transition-all shadow-lg uppercase tracking-widest"
          >
            <Plus size={16} />
            <span>Tambah KK</span>
          </button>
        </div>
      </div>

      <div className="flex flex-wrap items-center gap-3">
        <div className="flex items-center bg-white border border-slate-200 rounded-2xl px-4 py-2">
           <Filter size={14} className="text-slate-400 mr-2" />
           <select 
             className="bg-transparent text-xs font-black outline-none uppercase tracking-tighter"
             value={filters.dusun}
             onChange={(e) => setFilters({ dusun: e.target.value })}
           >
             <option value="">Semua Dusun</option>
             {dusuns.map(d => <option key={d} value={d}>{d}</option>)}
           </select>
        </div>
        {selectedIds.length > 0 && (
          <button onClick={handleDeleteMultiple} className="bg-red-600 text-white rounded-2xl px-5 py-2.5 text-[10px] font-black flex items-center justify-center space-x-2 animate-in zoom-in uppercase tracking-widest">
            <Trash2 size={14} />
            <span>Hapus {selectedIds.length} KK Terpilih</span>
          </button>
        )}
      </div>

      {/* Tabel Data Penduduk */}
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 w-12 text-center">
                  <button onClick={toggleSelectAll} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-44">Opsi KK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Kepala Keluarga</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-6 py-6 text-center">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={22} className="text-blue-600" /> : <Square size={22} />}
                    </button>
                  </td>
                  <td className="px-4 py-6">
                    <div className="flex items-center justify-center space-x-1.5">
                      <button 
                        onClick={() => setViewingFamilyKK(r.noKK)}
                        className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm" 
                        title="Rincian Anggota"
                      >
                        <Eye size={16} />
                      </button>
                      <button 
                        onClick={() => setEditingResident(r)}
                        className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm" 
                        title="Edit Kepala Keluarga"
                      >
                        <Edit3 size={16} />
                      </button>
                      <button 
                        onClick={() => setMovingFamily(r)}
                        className="p-2.5 bg-amber-50 text-amber-600 rounded-xl hover:bg-amber-600 hover:text-white transition-all shadow-sm"
                        title="Pindah Keluarga"
                      >
                        <PlaneLanding size={16} />
                      </button>
                      <button 
                        onClick={() => handleDeleteFamily(r)} 
                        className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"
                        title="Hapus KK"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-400 font-bold uppercase tracking-tighter">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline" onClick={() => setViewingFamilyKK(r.noKK)}>{r.noKK}</div>
                    <div className="text-[11px] text-slate-400 font-mono tracking-tighter">{r.nik}</div>
                  </td>
                  <td className="px-4 py-6 text-sm font-black text-slate-800 uppercase">{r.fullName}</td>
                  <td className="px-4 py-6 text-center">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender.includes('Perempuan') || r.gender.includes('2') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                      {r.gender.includes('Laki-laki') || r.gender.includes('1') ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-4 py-6 text-sm text-slate-500 font-medium truncate max-w-[150px]">{r.job || '-'}</td>
                </tr>
              ))}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Data tidak ditemukan atau filter tidak sesuai.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={handleEditSave} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={handleAddSave} />}
      {movingFamily && <MoveFamilyConfirmModal family={movingFamily} onClose={() => setMovingFamily(null)} onConfirm={finalizeMoveFamily} />}
    </div>
  );
};

const MoveFamilyConfirmModal: React.FC<{ family: Resident, onClose: () => void, onConfirm: (d: { date: string, destination: string }) => void }> = ({ family, onClose, onConfirm }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [destination, setDestination] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination.trim()) return alert("Harap isi alamat tujuan kepindahan!");
    onConfirm({ date, destination });
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in zoom-in-95">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden border border-slate-200">
        <div className="p-6 bg-amber-500 text-white flex justify-between items-center">
           <div className="flex items-center space-x-3">
             <PlaneLanding size={24} />
             <h4 className="font-black text-sm uppercase tracking-widest">Proses Kepindahan Keluarga</h4>
           </div>
           <button onClick={onClose}><X size={24}/></button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-6">
           <div className="text-center bg-amber-50 p-6 rounded-3xl border border-amber-100">
              <p className="text-lg font-black text-slate-900 uppercase leading-tight">{family.fullName}</p>
              <p className="text-xs font-mono text-slate-500 mt-1 uppercase">No. KK: {family.noKK}</p>
           </div>
           <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Tanggal Pindah</label>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 outline-none font-bold focus:bg-white transition-all" required />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Alamat Tujuan Lengkap</label>
                <textarea value={destination} onChange={e => setDestination(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 outline-none font-bold text-sm h-24 resize-none focus:bg-white transition-all" placeholder="Contoh: Desa Karangsono, RT 01 RW 01..." required />
              </div>
           </div>
           <div className="pt-4">
              <button type="submit" className="w-full py-4 rounded-[1.5rem] text-sm font-black text-white bg-amber-500 hover:bg-amber-600 shadow-xl transition-all uppercase tracking-widest">Arsipkan Seluruh Keluarga</button>
           </div>
        </form>
      </div>
    </div>
  );
};

export default PopulationManagement;

import React, { useState } from 'react';
import { X, User, Printer, CheckCircle2, UserPlus, Save, Skull, ArrowUpRight, Trash2, Calendar, AlertCircle } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge } from '../utils/helpers';
import EditResidentModal from './EditResidentModal';

interface FamilyDetailModalProps {
  noKK: string;
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
  onClose: () => void;
}

const FamilyDetailModal: React.FC<FamilyDetailModalProps> = ({ noKK, residents, setResidents, onClose }) => {
  const [editingMember, setEditingMember] = useState<Resident | null>(null);
  const [isAddingMember, setIsAddingMember] = useState(false);
  const [deathConfirm, setDeathConfirm] = useState<Resident | null>(null);

  // Mencari referensi status keluarga (Aktif/Pindah)
  const headRef = residents.find(r => r.noKK === noKK && r.isHeadOfFamily);
  const currentViewStatus = headRef?.status || 'Aktif';

  // Filter anggota berdasarkan No KK dan status yang relevan
  const familyMembers = residents.filter(r => r.noKK === noKK && r.status === currentViewStatus);
  const headOfFamily = familyMembers.find(r => r.isHeadOfFamily) || familyMembers[0];

  const deleteMember = (member: Resident) => {
    if (window.confirm(`PERINGATAN: Hapus data ${member.fullName} secara PERMANEN dari sistem? Tindakan ini tidak dapat dibatalkan.`)) {
      setResidents(prev => {
        const updated = prev.filter(r => r.id !== member.id);
        // Jika anggota yang dihapus adalah yang terakhir dalam KK ini di tampilan modal, tutup modal
        const remainingInKK = updated.filter(r => r.noKK === noKK && r.status === currentViewStatus);
        if (remainingInKK.length === 0) {
          onClose();
        }
        return updated;
      });
    }
  };

  const archiveDeath = (date: string) => {
    if (!deathConfirm) return;
    setResidents(prev => prev.map(r => 
      r.id === deathConfirm.id ? { ...r, status: 'Meninggal', deathDate: date } : r
    ));
    setDeathConfirm(null);
  };

  const handleUpdateMember = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingMember(null);
  };

  const handleAddMember = (newMember: Resident) => {
    setResidents(prev => [...prev, { ...newMember, status: 'Aktif' }]);
    setIsAddingMember(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in duration-300">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-6xl max-h-[92vh] overflow-hidden flex flex-col border border-slate-200 animate-in zoom-in-95">

        {/* Header Modal */}
        <div className="p-8 border-b border-slate-100 flex items-center justify-between no-print">
          <div className="flex items-center space-x-6">
            <div className={`w-14 h-14 ${currentViewStatus === 'Pindah' ? 'bg-amber-500' : 'bg-slate-900'} rounded-2xl flex items-center justify-center text-white shadow-xl`}>
              <User size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">
                {currentViewStatus === 'Pindah' ? 'Rincian Keluarga (Pindah)' : 'Daftar Anggota Keluarga'}
              </h3>
              <p className="text-slate-400 text-[10px] font-bold font-mono tracking-widest mt-2 uppercase">NO. KK: {noKK}</p>
            </div>
          </div>
          <div className="flex items-center space-x-3">
            {currentViewStatus === 'Aktif' && (
              <button 
                onClick={() => setIsAddingMember(true)} 
                className="flex items-center space-x-2 px-6 py-3 bg-emerald-600 text-white rounded-2xl text-[10px] font-black hover:bg-emerald-700 transition-all uppercase tracking-widest shadow-lg shadow-emerald-200"
              >
                <UserPlus size={16} />
                <span>Tambah Anggota</span>
              </button>
            )}
            <button onClick={() => window.print()} className="p-3 bg-slate-100 text-slate-600 hover:bg-slate-200 rounded-2xl transition-all" title="Cetak Data">
              <Printer size={20} />
            </button>
            <button onClick={onClose} className="p-3 bg-slate-100 text-slate-400 hover:text-rose-500 hover:bg-rose-50 rounded-2xl transition-all">
              <X size={24} />
            </button>
          </div>
        </div>

        {/* List Anggota Keluarga */}
        <div className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/20">
          <div className="grid grid-cols-1 gap-4">
            {familyMembers.length > 0 ? familyMembers.sort((a,b) => (a.isHeadOfFamily ? -1 : 1)).map((m) => (
              <div key={m.id} className="bg-white p-3 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row md:items-center hover:border-blue-200 transition-all group">
                {/* Label Hubungan */}
                <div className={`px-6 py-4 md:w-48 text-center md:text-left rounded-2xl md:mr-6 font-black text-[10px] uppercase tracking-widest shadow-sm ${
                  m.isHeadOfFamily 
                    ? (currentViewStatus === 'Pindah' ? 'bg-amber-500 text-white' : 'bg-slate-900 text-white') 
                    : 'bg-slate-100 text-slate-700'
                }`}>
                  {m.relationship.includes('. ') ? m.relationship.split('. ')[1] : m.relationship}
                </div>

                {/* Info Utama */}
                <div className="flex-1 p-2 grid grid-cols-2 md:grid-cols-4 gap-4 items-center">
                  <div>
                    <button 
                      onClick={() => currentViewStatus === 'Aktif' && setEditingMember(m)} 
                      className={`text-xs font-black font-mono ${currentViewStatus === 'Aktif' ? 'text-blue-600 hover:underline' : 'text-slate-400'}`}
                    >
                      {m.nik}
                    </button>
                    <h5 className="text-sm font-black text-slate-900 uppercase truncate mt-0.5">{m.fullName}</h5>
                  </div>

                  <div className="text-center md:text-left">
                    <p className="text-[8px] text-slate-400 font-black uppercase mb-0.5">L/P</p>
                    <span className="text-xs font-bold text-slate-600 uppercase">{m.gender.includes('Laki') || m.gender.includes('1') ? 'Laki-laki' : 'Perempuan'}</span>
                  </div>

                  <div className="text-center md:text-left">
                    <p className="text-[8px] text-slate-400 font-black uppercase mb-0.5">Usia</p>
                    <p className="text-sm font-black text-slate-900">{calculateAge(m.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase tracking-tighter">Tahun</span></p>
                  </div>

                  {/* Tombol Aksi Anggota */}
                  <div className="flex justify-end space-x-2">
                    {currentViewStatus === 'Aktif' && (
                      <>
                        <button 
                          onClick={() => setDeathConfirm(m)} 
                          className="p-2.5 bg-slate-50 text-slate-400 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm"
                          title="Lapor Kematian"
                        >
                          <Skull size={16} />
                        </button>
                        <button 
                          onClick={() => deleteMember(m)} 
                          className="p-2.5 bg-rose-50 text-rose-400 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"
                          title="Hapus Permanen"
                        >
                          <Trash2 size={16} />
                        </button>
                      </>
                    )}
                    {currentViewStatus === 'Pindah' && (
                       <span className="text-[9px] font-black text-slate-300 uppercase italic tracking-widest">Data Arsip</span>
                    )}
                  </div>
                </div>
              </div>
            )) : (
              <div className="text-center py-24 bg-white rounded-[3rem] border border-dashed border-slate-200">
                <Users size={48} className="mx-auto text-slate-200 mb-4" />
                <p className="text-slate-400 font-black uppercase text-xs tracking-[0.2em]">Tidak ada anggota keluarga aktif ditemukan.</p>
              </div>
            )}
          </div>
        </div>

        {/* Footer Modal */}
        <div className="p-8 border-t border-slate-100 bg-white flex justify-between items-center no-print">
          <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest italic">Pembaruan data akan langsung tersimpan di sistem.</p>
          <button onClick={onClose} className={`px-12 py-4 ${currentViewStatus === 'Pindah' ? 'bg-amber-500' : 'bg-slate-900'} text-white rounded-[1.5rem] text-sm font-black hover:opacity-90 shadow-xl transition-all uppercase tracking-widest`}>
            Tutup Dialog
          </button>
        </div>

        {/* Sub-modals */}
        {editingMember && <EditResidentModal resident={editingMember} onClose={() => setEditingMember(null)} onSave={handleUpdateMember} />}
        {isAddingMember && <InternalAddMemberModal noKK={noKK} familyBase={headOfFamily} onClose={() => setIsAddingMember(false)} onSave={handleAddMember} />}
        {deathConfirm && <DeathModal member={deathConfirm} onClose={() => setDeathConfirm(null)} onConfirm={archiveDeath} />}
      </div>
    </div>
  );
};

