                      <button 
                        onClick={() => setEditingResident(r)}
                        className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm" 
                        title="Edit Kepala Keluarga"
                      >
                        <Edit3 size={16} />
