             <div className="pt-4 flex justify-end space-x-3">
                <button type="button" onClick={onClose} className="px-8 py-4 text-xs font-black text-slate-400 uppercase tracking-widest hover:text-slate-600">Batal</button>
                <button type="submit" className="px-10 py-4 bg-emerald-600 text-white rounded-2xl text-xs font-black uppercase tracking-widest shadow-xl shadow-emerald-500/20 hover:bg-emerald-700 transition-all">Simpan Anggota</button>
             </div>
          </form>
       </div>
    </div>
  );
};

export default FamilyDetailModal;

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  Upload,
  BookOpen,
  Loader2,
  PlaneLanding,
  Calendar,
  MapPin,
  X,
  AlertCircle,
  Edit3,
  Filter,
  Download,
  RefreshCcw
} from 'lucide-react';
import { Resident, BloodType, MaritalStatus, Education } from '../types';
import { calculateAge, downloadTemplate, downloadCSV } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [filters, setFilters] = useState({ dusun: '', rw: '', rt: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [movingFamily, setMovingFamily] = useState<Resident | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);

  // Data untuk filter bertingkat
  const dusunList = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))).sort(), [activeResidents]);

  const rwList = useMemo(() => {
    const filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    return Array.from(new Set(filtered.map(r => r.rw))).sort();
  }, [activeResidents, filters.dusun]);

  const rtList = useMemo(() => {
    let filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    if (filters.rw) filtered = filtered.filter(r => r.rw === filters.rw);
    return Array.from(new Set(filtered.map(r => r.rt))).sort();
  }, [activeResidents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const s = searchTerm.toLowerCase();
      const matchSearch = 
        r.fullName.toLowerCase().includes(s) ||
        r.nik.includes(s) ||
        r.noKK.includes(s);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;

      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const handleDownloadBNBA = () => {
    // Ambil daftar No. KK yang saat ini tampil di tabel (hasil filter/search)
    const displayedKKs = new Set(filteredData.map(r => r.noKK.trim()));

    // Filter semua penduduk aktif yang memiliki No. KK dalam daftar tersebut
    const residentsToExport = activeResidents
      .filter(r => displayedKKs.has(r.noKK.trim()))
      .sort((a, b) => {
        // Urutkan berdasarkan Dusun -> RW -> RT -> No KK -> Hubungan Keluarga
        if (a.dusun !== b.dusun) return a.dusun.localeCompare(b.dusun);
        if (a.rw !== b.rw) return a.rw.localeCompare(b.rw);
        if (a.rt !== b.rt) return a.rt.localeCompare(b.rt);
        if (a.noKK !== b.noKK) return a.noKK.localeCompare(b.noKK);
        return a.relationship.localeCompare(b.relationship);
      });

    if (residentsToExport.length === 0) {
      alert("Tidak ada data untuk diunduh sesuai filter saat ini.");
      return;
    }

    const dataToExport = residentsToExport.map(r => ({
      'Dusun': r.dusun,
      'RW': r.rw,
      'RT': r.rt,
      'No. KK': r.noKK,
      'NIK': r.nik,
      'Nama Lengkap': r.fullName,
      'Hubungan': r.relationship,
      'Tgl Lahir': r.birthDate,
      'Usia': calculateAge(r.birthDate),
      'JK': r.gender,
      'Gol. Darah': r.bloodType,
      'Status': r.maritalStatus,
      'Pendidikan': r.education,
      'Pekerjaan': r.job
    }));

    const filterInfo = filters.dusun ? `_${filters.dusun}` : '_SemuaWilayah';
    downloadCSV(dataToExport, `BNBA_Ngumbul_Filtered${filterInfo}_${new Date().toISOString().split('T')[0]}`);
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length && filteredData.length > 0) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  const handleDeleteFamily = (resident: Resident) => {
    if (window.confirm(`Hapus seluruh data keluarga ${resident.fullName} (No. KK: ${resident.noKK}) secara permanen?`)) {
      const targetKK = resident.noKK;
      setResidents(prev => prev.filter(r => r.noKK !== targetKK));
      setSelectedIds(prev => prev.filter(i => i !== resident.id));
    }
  };

  const handleDeleteMultiple = () => {
    const kksToDelete = headOfFamilies
      .filter(r => selectedIds.includes(r.id))
      .map(r => r.noKK);

    if (kksToDelete.length === 0) return;

    if (window.confirm(`Hapus ${kksToDelete.length} keluarga terpilih beserta seluruh anggotanya secara permanen?`)) {
      setResidents(prev => prev.filter(r => !kksToDelete.includes(r.noKK)));
      setSelectedIds([]);
    }
  };

  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  const handleAddSave = (newResidents: Resident[]) => {
    setResidents(prev => [...prev, ...newResidents]);
    setIsAddModalOpen(false);
  };

  const finalizeMoveFamily = (data: { date: string, destination: string }) => {
    if (!movingFamily) return;
    const targetKK = movingFamily.noKK;
    setResidents(prev => prev.map(r => {
      if (r.noKK === targetKK) {
        return { 
          ...r, 
          status: 'Pindah',
          moveDate: data.date,
          moveDestination: data.destination
        };
      }
      return r;
    }));
    setMovingFamily(null);
    setSelectedIds(prev => prev.filter(i => i !== movingFamily.id));
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
        const newResidents: Resident[] = lines.slice(1).map((line, index) => {
          const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => item[h] = values[i] || '');
          const rel = item['Status Hubungan dalam Keluarga'] || '';
          return {
            id: `imp-${Date.now()}-${index}`,
            dusun: item['Dusun'] || '-',
            rt: item['RT'] || '-',
            rw: item['RW'] || '-',
            noKK: (item['No.KK'] || '').replace(/\D/g, ''),
            nik: (item['NIK'] || '').replace(/\D/g, ''),
            fullName: (item['Nama Lengkap'] || '-').toUpperCase(),
            relationship: rel,
            birthPlace: '', 
            birthDate: item['Tanggal Lahir'] || '1990-01-01',
            gender: (item['Jenis Kelamin'] || '').includes('P') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: rel.toLowerCase().includes('kepala keluarga') || rel.startsWith('1'),
            status: 'Aktif'
          };
        });
        setResidents(prev => [...prev, ...newResidents]);
        setIsImporting(false);
        if (fileInputRef.current) fileInputRef.current.value = '';
      } catch (err) {
        alert('Format file CSV tidak sesuai atau rusak.');
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
             <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
             <h3 className="text-xl font-black text-slate-900 mt-4 tracking-widest uppercase">Sinkronisasi Data...</h3>
          </div>
        </div>
      )}

      {/* Baris Pencarian & Tombol Aksi */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-2xl px-5 py-3 border border-slate-200 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Kepala Keluarga / NIK / No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={handleDownloadBNBA}
            className="flex items-center space-x-2 px-5 py-3 bg-emerald-50 border border-emerald-200 rounded-2xl text-[10px] font-black text-emerald-700 hover:bg-emerald-100 transition-all uppercase tracking-widest shadow-sm shadow-emerald-100"
          >
            <Download size={16} />
            <span>Download BNBA</span>
          </button>

          <button 
            onClick={downloadTemplate}
            className="flex items-center space-x-2 px-5 py-3 bg-white border border-slate-200 rounded-2xl text-[10px] font-black text-slate-700 hover:bg-slate-50 transition-all uppercase tracking-widest"
          >
            <BookOpen size={16} />
            <span>Format Data</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-3 bg-blue-50 border border-blue-200 rounded-2xl text-[10px] font-black text-blue-700 hover:bg-blue-100 transition-all cursor-pointer uppercase tracking-widest">
            <Upload size={16} />
            <span>Import CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleImport} accept=".csv" />
          </label>

          <button 
            onClick={() => setIsAddModalOpen(true)}
            className="flex items-center space-x-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black hover:bg-slate-800 transition-all shadow-lg uppercase tracking-widest"
          >
            <Plus size={16} />
            <span>Tambah KK</span>
          </button>
        </div>
      </div>

      {/* Filter Bertingkat */}
      <div className="flex flex-wrap items-center gap-3 bg-white p-3 rounded-[2rem] border border-slate-200 shadow-sm">
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[150px]">
           <MapPin size={14} className="text-slate-400 mr-2" />
           <select 
             className="bg-transparent text-xs font-black outline-none uppercase tracking-tighter w-full"
             value={filters.dusun}
             onChange={(e) => setFilters({ ...filters, dusun: e.target.value, rw: '', rt: '' })}
           >
             <option value="">Pilih Dusun</option>
             {dusunList.map(d => <option key={d} value={d}>{d}</option>)}
           </select>
        </div>

        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RW</span>
           <select 
             className="bg-transparent text-xs font-black outline-none w-full"
             value={filters.rw}
             onChange={(e) => setFilters({ ...filters, rw: e.target.value, rt: '' })}
             disabled={!filters.dusun}
           >
             <option value="">Semua</option>
             {rwList.map(rw => <option key={rw} value={rw}>{rw}</option>)}
           </select>
        </div>

        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RT</span>
           <select 
             className="bg-transparent text-xs font-black outline-none w-full"
             value={filters.rt}
             onChange={(e) => setFilters({ ...filters, rt: e.target.value })}
             disabled={!filters.rw}
           >
             <option value="">Semua</option>
             {rtList.map(rt => <option key={rt} value={rt}>{rt}</option>)}
           </select>
        </div>

        <button 
          onClick={() => setFilters({ dusun: '', rw: '', rt: '' })}
          className="p-2.5 text-slate-400 hover:text-slate-900 transition-all"
          title="Reset Filter"
        >
          <RefreshCcw size={16} />
        </button>

        <div className="ml-auto flex items-center gap-3">
          {selectedIds.length > 0 && (
            <button onClick={handleDeleteMultiple} className="bg-red-600 text-white rounded-xl px-5 py-2 text-[10px] font-black flex items-center justify-center space-x-2 animate-in zoom-in uppercase tracking-widest shadow-lg shadow-red-200">
              <Trash2 size={14} />
              <span>Hapus {selectedIds.length} KK</span>
            </button>
          )}
        </div>
      </div>

      {/* Tabel Data Penduduk */}
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 w-12 text-center">
                  <button onClick={toggleSelectAll} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-44">Opsi KK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Kepala Keluarga</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-6 py-6 text-center">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={22} className="text-blue-600" /> : <Square size={22} />}
                    </button>
                  </td>
                  <td className="px-4 py-6">
                    <div className="flex items-center justify-center space-x-1.5">
                      <button 
                        onClick={() => setViewingFamilyKK(r.noKK)}
                        className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm" 
                        title="Rincian Anggota"
                      >
                        <Eye size={16} />
                      </button>
                      <button 
                        onClick={() => setEditingResident(r)}
                        className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm" 
                        title="Edit Kepala Keluarga"
                      >
                        <Edit3 size={16} />
                      </button>
                      <button 
                        onClick={() => setMovingFamily(r)}
                        className="p-2.5 bg-amber-50 text-amber-600 rounded-xl hover:bg-amber-600 hover:text-white transition-all shadow-sm"
                        title="Pindah Keluarga"
                      >
                        <PlaneLanding size={16} />
                      </button>
                      <button 
                        onClick={() => handleDeleteFamily(r)} 
                        className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"
                        title="Hapus KK"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-400 font-bold uppercase tracking-tighter">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline" onClick={() => setViewingFamilyKK(r.noKK)}>{r.noKK}</div>
                    <div className="text-[11px] text-slate-400 font-mono tracking-tighter">{r.nik}</div>
                  </td>
                  <td className="px-4 py-6 text-sm font-black text-slate-800 uppercase">{r.fullName}</td>
                  <td className="px-4 py-6 text-center">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender.includes('Perempuan') || r.gender.includes('2') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                      {r.gender.includes('Laki-laki') || r.gender.includes('1') ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-4 py-6 text-sm text-slate-500 font-medium truncate max-w-[150px]">{r.job || '-'}</td>
                </tr>
              ))}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-20 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Data tidak ditemukan atau filter tidak sesuai.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={handleEditSave} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={handleAddSave} />}
      {movingFamily && <MoveFamilyConfirmModal family={movingFamily} onClose={() => setMovingFamily(null)} onConfirm={finalizeMoveFamily} />}
    </div>
  );
};

const MoveFamilyConfirmModal: React.FC<{ family: Resident, onClose: () => void, onConfirm: (d: { date: string, destination: string }) => void }> = ({ family, onClose, onConfirm }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [destination, setDestination] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!destination.trim()) return alert("Harap isi alamat tujuan kepindahan!");
    onConfirm({ date, destination });
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in zoom-in-95">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden border border-slate-200">
        <div className="p-6 bg-amber-500 text-white flex justify-between items-center">
           <div className="flex items-center space-x-3">
             <PlaneLanding size={24} />
             <h4 className="font-black text-sm uppercase tracking-widest">Proses Kepindahan Keluarga</h4>
           </div>
           <button onClick={onClose}><X size={24}/></button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-6">
           <div className="text-center bg-amber-50 p-6 rounded-3xl border border-amber-100">
              <p className="text-lg font-black text-slate-900 uppercase leading-tight">{family.fullName}</p>
              <p className="text-xs font-mono text-slate-500 mt-1 uppercase">No. KK: {family.noKK}</p>
           </div>
           <div className="space-y-4">
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Tanggal Pindah</label>
                <input type="date" value={date} onChange={e => setDate(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 outline-none font-bold focus:bg-white transition-all" required />
              </div>
              <div>
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Alamat Tujuan Lengkap</label>
                <textarea value={destination} onChange={e => setDestination(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 outline-none font-bold text-sm h-24 resize-none focus:bg-white transition-all" placeholder="Contoh: Desa Karangsono, RT 01 RW 01..." required />
              </div>
           </div>
           <div className="pt-4">
              <button type="submit" className="w-full py-4 rounded-[1.5rem] text-sm font-black text-white bg-amber-500 hover:bg-amber-600 shadow-xl transition-all uppercase tracking-widest">Arsipkan Seluruh Keluarga</button>
           </div>
        </form>
      </div>
    </div>
  );
};

export default PopulationManagement;

export type Gender = 'Laki-laki' | 'Perempuan';
export type MaritalStatus = 'Kawin' | 'Belum Kawin' | 'Cerai Hidup' | 'Cerai Mati';
export type Education = 'Tidak/Belum Sekolah' | 'SD' | 'SMP' | 'SMA' | 'Diploma' | 'Sarjana' | 'Pascasarjana';
export type BloodType = 'A' | 'B' | 'AB' | 'O' | 'Tidak Tahu';
export type ResidentStatus = 'Aktif' | 'Meninggal' | 'Pindah' | 'Terhapus';

export interface Resident {
  id: string;
  dusun: string;
  rt: string;
  rw: string;
  noKK: string;
  nik: string;
  fullName: string;
  relationship: string;
  birthPlace: string;
  birthDate: string;
  gender: Gender;
  bloodType: BloodType;
  maritalStatus: MaritalStatus;
  education: Education;
  job: string;
  fatherName: string;
  motherName: string;
  isHeadOfFamily: boolean;
  status: ResidentStatus;
  deathDate?: string;
  moveDate?: string;
  moveDestination?: string;
  deleteDate?: string;
  deleteReason?: string;
}

export interface AppConfig {
  appName: string;
  subtitle: string;
  logoUrl: string;
  developerInfo: string;
}

export type AgeGroup = 'Balita' | 'Anak' | 'Remaja' | 'Dewasa' | 'Lansia';

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  Upload,
  BookOpen,
  Loader2,
  PlaneLanding,
  Calendar,
  MapPin,
  X,
  AlertCircle,
  Edit3,
  Filter,
  Download,
  RefreshCcw,
  MessageSquare
} from 'lucide-react';
import { Resident, BloodType, MaritalStatus, Education } from '../types';
import { calculateAge, downloadTemplate, downloadCSV } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [filters, setFilters] = useState({ dusun: '', rw: '', rt: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [movingFamily, setMovingFamily] = useState<Resident | null>(null);
  const [deletingFamily, setDeletingFamily] = useState<{item: Resident, ids?: string[]} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);

  const dusunList = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))).sort(), [activeResidents]);

  const rwList = useMemo(() => {
    const filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    return Array.from(new Set(filtered.map(r => r.rw))).sort();
  }, [activeResidents, filters.dusun]);

  const rtList = useMemo(() => {
    let filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    if (filters.rw) filtered = filtered.filter(r => r.rw === filters.rw);
    return Array.from(new Set(filtered.map(r => r.rt))).sort();
  }, [activeResidents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const s = searchTerm.toLowerCase();
      const matchSearch = 
        r.fullName.toLowerCase().includes(s) ||
        r.nik.includes(s) ||
        r.noKK.includes(s);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;

      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const handleDownloadBNBA = () => {
    const displayedKKs = new Set(filteredData.map(r => r.noKK.trim()));
    const residentsToExport = activeResidents
      .filter(r => displayedKKs.has(r.noKK.trim()))
      .sort((a, b) => {
        if (a.dusun !== b.dusun) return a.dusun.localeCompare(b.dusun);
        if (a.rw !== b.rw) return a.rw.localeCompare(b.rw);
        if (a.rt !== b.rt) return a.rt.localeCompare(b.rt);
        if (a.noKK !== b.noKK) return a.noKK.localeCompare(b.noKK);
        return a.relationship.localeCompare(b.relationship);
      });

    if (residentsToExport.length === 0) return alert("Tidak ada data untuk diunduh.");

    const dataToExport = residentsToExport.map(r => ({
      'Dusun': r.dusun, 'RW': r.rw, 'RT': r.rt, 'No. KK': r.noKK, 'NIK': r.nik, 
      'Nama Lengkap': r.fullName, 'Hubungan': r.relationship, 'Tgl Lahir': r.birthDate,
      'Usia': calculateAge(r.birthDate), 'JK': r.gender, 'Gol. Darah': r.bloodType,
      'Status': r.maritalStatus, 'Pendidikan': r.education, 'Pekerjaan': r.job
    }));

    downloadCSV(dataToExport, `BNBA_Filtered_Ngumbul_${new Date().toISOString().split('T')[0]}`);
  };

  const finalizeDelete = (reason: string) => {
    if (!deletingFamily) return;

    let kksToUpdate: string[] = [];
    if (deletingFamily.ids) {
      // Multiple delete
      kksToUpdate = headOfFamilies
        .filter(r => deletingFamily.ids!.includes(r.id))
        .map(r => r.noKK);
    } else {
      // Single delete
      kksToUpdate = [deletingFamily.item.noKK];
    }

    setResidents(prev => prev.map(r => {
      if (kksToUpdate.includes(r.noKK) && r.status === 'Aktif') {
        return { 
          ...r, 
          status: 'Terhapus', 
          deleteDate: new Date().toISOString().split('T')[0],
          deleteReason: reason
        };
      }
      return r;
    }));

    setDeletingFamily(null);
    setSelectedIds([]);
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length && filteredData.length > 0) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  return (
    <div className="space-y-6">
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
             <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
             <h3 className="text-xl font-black text-slate-900 mt-4 tracking-widest uppercase">Sinkronisasi Data...</h3>
          </div>
        </div>
      )}

      {/* Action Bars */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-2xl px-5 py-3 border border-slate-200 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Kepala Keluarga / NIK / No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button onClick={handleDownloadBNBA} className="flex items-center space-x-2 px-5 py-3 bg-emerald-50 border border-emerald-200 rounded-2xl text-[10px] font-black text-emerald-700 hover:bg-emerald-100 transition-all uppercase tracking-widest shadow-sm">
            <Download size={16} />
            <span>Download BNBA</span>
          </button>

          <button onClick={downloadTemplate} className="flex items-center space-x-2 px-5 py-3 bg-white border border-slate-200 rounded-2xl text-[10px] font-black text-slate-700 hover:bg-slate-50 transition-all uppercase tracking-widest">
            <BookOpen size={16} />
            <span>Format Data</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-3 bg-blue-50 border border-blue-200 rounded-2xl text-[10px] font-black text-blue-700 hover:bg-blue-100 transition-all cursor-pointer uppercase tracking-widest">
            <Upload size={16} />
            <span>Import CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={(e) => {}} accept=".csv" />
          </label>

          <button onClick={() => setIsAddModalOpen(true)} className="flex items-center space-x-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black hover:bg-slate-800 transition-all shadow-lg uppercase tracking-widest">
            <Plus size={16} />
            <span>Tambah KK</span>
          </button>
        </div>
      </div>

      {/* Filter Bertingkat */}
      <div className="flex flex-wrap items-center gap-3 bg-white p-3 rounded-[2rem] border border-slate-200 shadow-sm">
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[150px]">
           <MapPin size={14} className="text-slate-400 mr-2" />
           <select className="bg-transparent text-xs font-black outline-none uppercase w-full" value={filters.dusun} onChange={(e) => setFilters({ ...filters, dusun: e.target.value, rw: '', rt: '' })}>
             <option value="">Pilih Dusun</option>
             {dusunList.map(d => <option key={d} value={d}>{d}</option>)}
           </select>
        </div>
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RW</span>
           <select className="bg-transparent text-xs font-black outline-none w-full" value={filters.rw} onChange={(e) => setFilters({ ...filters, rw: e.target.value, rt: '' })} disabled={!filters.dusun}>
             <option value="">Semua</option>
             {rwList.map(rw => <option key={rw} value={rw}>{rw}</option>)}
           </select>
        </div>
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RT</span>
           <select className="bg-transparent text-xs font-black outline-none w-full" value={filters.rt} onChange={(e) => setFilters({ ...filters, rt: e.target.value })} disabled={!filters.rw}>
             <option value="">Semua</option>
             {rtList.map(rt => <option key={rt} value={rt}>{rt}</option>)}
           </select>
        </div>
        <button onClick={() => setFilters({ dusun: '', rw: '', rt: '' })} className="p-2.5 text-slate-400 hover:text-slate-900 transition-all"><RefreshCcw size={16} /></button>

        <div className="ml-auto">
          {selectedIds.length > 0 && (
            <button onClick={() => setDeletingFamily({ item: residents[0], ids: selectedIds })} className="bg-rose-600 text-white rounded-xl px-5 py-2 text-[10px] font-black flex items-center space-x-2 uppercase tracking-widest shadow-lg shadow-rose-200">
              <Trash2 size={14} />
              <span>Hapus {selectedIds.length} KK</span>
            </button>
          )}
        </div>
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 w-12 text-center">
                  <button onClick={toggleSelectAll} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-44">Opsi KK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Kepala Keluarga</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-6 py-6 text-center">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={22} className="text-blue-600" /> : <Square size={22} />}
                    </button>
                  </td>
                  <td className="px-4 py-6">
                    <div className="flex items-center justify-center space-x-1.5">
                      <button onClick={() => setViewingFamilyKK(r.noKK)} className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"><Eye size={16} /></button>
                      <button onClick={() => setEditingResident(r)} className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm"><Edit3 size={16} /></button>
                      <button onClick={() => setMovingFamily(r)} className="p-2.5 bg-amber-50 text-amber-600 rounded-xl hover:bg-amber-600 hover:text-white transition-all shadow-sm"><PlaneLanding size={16} /></button>
                      <button onClick={() => setDeletingFamily({ item: r })} className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"><Trash2 size={16} /></button>
                    </div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-400 font-bold uppercase">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline" onClick={() => setViewingFamilyKK(r.noKK)}>{r.noKK}</div>
                    <div className="text-[11px] text-slate-400 font-mono tracking-tighter">{r.nik}</div>
                  </td>
                  <td className="px-4 py-6 text-sm font-black text-slate-800 uppercase">{r.fullName}</td>
                  <td className="px-4 py-6 text-center">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender.includes('Perempuan') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                      {r.gender.includes('Laki-laki') ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-4 py-6 text-sm text-slate-500 font-medium truncate max-w-[150px]">{r.job || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={handleEditSave} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={handleAddSave} />}
      {deletingFamily && <DeleteConfirmModal item={deletingFamily.item} isMultiple={!!deletingFamily.ids} count={deletingFamily.ids?.length} onClose={() => setDeletingFamily(null)} onConfirm={finalizeDelete} />}
      {movingFamily && <MoveFamilyConfirmModal family={movingFamily} onClose={() => setMovingFamily(null)} onConfirm={(d) => {}} />}
    </div>
  );
};

const DeleteConfirmModal: React.FC<{ item: Resident, isMultiple: boolean, count?: number, onClose: () => void, onConfirm: (reason: string) => void }> = ({ item, isMultiple, count, onClose, onConfirm }) => {
  const [reason, setReason] = useState('');
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in zoom-in-95">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden border border-slate-200">
        <div className="p-6 bg-rose-600 text-white flex justify-between items-center uppercase font-black tracking-widest text-sm">
           <div className="flex items-center space-x-3"><Trash2 size={20} /><span>Konfirmasi Penghapusan</span></div>
           <button onClick={onClose}><X size={24}/></button>
        </div>
        <div className="p-8 space-y-6">
           <div className="bg-rose-50 p-6 rounded-3xl border border-rose-100 text-center">
              <p className="text-xs font-black text-rose-600 uppercase tracking-widest mb-1">Data Akan Dipindahkan ke Arsip Terhapus</p>
              <h5 className="text-lg font-black text-slate-900 uppercase leading-tight">
                {isMultiple ? `${count} Kepala Keluarga Terpilih` : item.fullName}
              </h5>
           </div>
           <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Alasan Penghapusan Data</label>
              <textarea 
                value={reason} 
                onChange={e => setReason(e.target.value)} 
                className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 outline-none font-bold text-sm h-32 resize-none focus:bg-white transition-all" 
                placeholder="Contoh: Kesalahan input data, Duplikasi data, Atas permintaan penduduk..."
                required 
              />
           </div>
           <button 
             onClick={() => reason.trim() ? onConfirm(reason) : alert("Harap isi alasan penghapusan!")} 
             className="w-full py-4 bg-rose-600 text-white rounded-2xl font-black text-sm uppercase tracking-widest shadow-xl shadow-rose-200 hover:bg-rose-700 transition-all"
           >
             Pindahkan ke Arsip Terhapus
           </button>
        </div>
      </div>
    </div>
  );
};

const MoveFamilyConfirmModal: React.FC<{ family: Resident, onClose: () => void, onConfirm: (d: { date: string, destination: string }) => void }> = ({ family, onClose, onConfirm }) => {
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [destination, setDestination] = useState('');
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onConfirm({ date, destination });
  };
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden border border-slate-200">
        <div className="p-6 bg-amber-500 text-white flex justify-between items-center font-black text-sm uppercase">
           <span>Proses Kepindahan Keluarga</span>
           <button onClick={onClose}><X size={24}/></button>
        </div>
        <form onSubmit={handleSubmit} className="p-8 space-y-6">
           <div className="text-center bg-amber-50 p-6 rounded-3xl border border-amber-100"><p className="text-lg font-black text-slate-900 uppercase leading-tight">{family.fullName}</p></div>
           <div>
             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Alamat Tujuan Lengkap</label>
             <textarea value={destination} onChange={e => setDestination(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-3 outline-none font-bold text-sm h-24 resize-none" placeholder="Tujuan pindah..." required />
           </div>
           <button type="submit" className="w-full py-4 bg-amber-500 text-white rounded-2xl font-black uppercase shadow-xl transition-all">Simpan Arsip</button>
        </form>
      </div>
    </div>
  );
};

export default PopulationManagement;

import React, { useState, useMemo } from 'react';
import { Search, MapPin, Skull, PlaneLanding, History, Trash2, Calendar, FileText, Eye, AlertTriangle, MessageSquare } from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, formatDate } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';

interface ArchivedResidentsProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const ArchivedResidents: React.FC<ArchivedResidentsProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [subTab, setSubTab] = useState<'Meninggal' | 'Pindah' | 'Terhapus'>('Meninggal');
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);

  const filteredArchivedData = useMemo(() => {
    return residents.filter(r => {
      const matchStatus = r.status === subTab;
      // Untuk Pindah dan Terhapus (jika dihapus satu keluarga), tampilkan kepala keluarga saja di list utama
      // kecuali untuk Terhapus yang individual, kita tampilkan semua baris saja agar transparan
      const matchLevel = (subTab === 'Pindah' || subTab === 'Terhapus') ? r.isHeadOfFamily : true;
      const matchSearch = 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm);
      return matchStatus && matchLevel && matchSearch;
    });
  }, [residents, searchTerm, subTab]);

  const restoreData = (item: Resident) => {
    const msg = (subTab === 'Pindah' || subTab === 'Terhapus')
      ? `Pulihkan data keluarga ${item.fullName} (KK: ${item.noKK}) ke status Aktif?`
      : `Pulihkan ${item.fullName} ke status Aktif?`;

    if (window.confirm(msg)) {
      setResidents(prev => prev.map(r => {
        const shouldRestore = (subTab === 'Pindah' || subTab === 'Terhapus') ? r.noKK === item.noKK : r.id === item.id;
        if (shouldRestore && r.status === subTab) {
          return { 
            ...r, 
            status: 'Aktif', 
            deathDate: undefined, 
            moveDate: undefined, 
            moveDestination: undefined,
            deleteDate: undefined,
            deleteReason: undefined
          };
        }
        return r;
      }));
    }
  };

  const deletePermanently = (item: Resident) => {
    const msg = (subTab === 'Pindah' || subTab === 'Terhapus')
      ? `Hapus PERMANEN keluarga ${item.fullName}? Data akan benar-benar dibuang dari sistem!`
      : `Hapus PERMANEN data ${item.fullName}? Data akan benar-benar dibuang dari sistem!`;

    if (window.confirm(msg)) {
      setResidents(prev => prev.filter(r => {
        const shouldDelete = (subTab === 'Pindah' || subTab === 'Terhapus') ? r.noKK === item.noKK : r.id === item.id;
        // Hanya hapus yang berstatus sesuai tab saat ini
        if (shouldDelete && r.status === subTab) return false;
        return true;
      }));
    }
  };

  const tabConfigs = {
    Meninggal: { color: 'bg-rose-600', icon: Skull, label: 'Data Kematian' },
    Pindah: { color: 'bg-amber-500', icon: PlaneLanding, label: 'Data Pindah (KK)' },
    Terhapus: { color: 'bg-slate-700', icon: AlertTriangle, label: 'Riwayat Terhapus' }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center space-x-2 bg-white p-2 rounded-2xl shadow-sm border border-slate-200 w-fit overflow-x-auto">
        {(Object.keys(tabConfigs) as Array<keyof typeof tabConfigs>).map(tabKey => {
          const Config = tabConfigs[tabKey];
          return (
            <button 
              key={tabKey}
              onClick={() => setSubTab(tabKey)} 
