interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [filters, setFilters] = useState({ dusun: '', rw: '', rt: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [movingFamily, setMovingFamily] = useState<Resident | null>(null);
  const [deletingFamily, setDeletingFamily] = useState<{item: Resident, ids?: string[]} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);

  const dusunList = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))).sort(), [activeResidents]);

  const rwList = useMemo(() => {
    const filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    return Array.from(new Set(filtered.map(r => r.rw))).sort();
  }, [activeResidents, filters.dusun]);

  const rtList = useMemo(() => {
    let filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    if (filters.rw) filtered = filtered.filter(r => r.rw === filters.rw);
    return Array.from(new Set(filtered.map(r => r.rt))).sort();
  }, [activeResidents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const s = searchTerm.toLowerCase();
      const matchSearch = 
        r.fullName.toLowerCase().includes(s) ||
        r.nik.includes(s) ||
        r.noKK.includes(s);

      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;

      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const handleDownloadBNBA = () => {
    const displayedKKs = new Set(filteredData.map(r => r.noKK.trim()));
    const residentsToExport = activeResidents
      .filter(r => displayedKKs.has(r.noKK.trim()))
      .sort((a, b) => {
        if (a.dusun !== b.dusun) return a.dusun.localeCompare(b.dusun);
        if (a.rw !== b.rw) return a.rw.localeCompare(b.rw);
        if (a.rt !== b.rt) return a.rt.localeCompare(b.rt);
        if (a.noKK !== b.noKK) return a.noKK.localeCompare(b.noKK);
        return a.relationship.localeCompare(b.relationship);
      });

    if (residentsToExport.length === 0) return alert("Tidak ada data untuk diunduh.");

    const dataToExport = residentsToExport.map(r => ({
      'Dusun': r.dusun, 'RW': r.rw, 'RT': r.rt, 'No. KK': r.noKK, 'NIK': r.nik, 
      'Nama Lengkap': r.fullName, 'Hubungan': r.relationship, 'Tgl Lahir': r.birthDate,
      'Usia': calculateAge(r.birthDate), 'JK': r.gender, 'Gol. Darah': r.bloodType,
      'Status': r.maritalStatus, 'Pendidikan': r.education, 'Pekerjaan': r.job
    }));

    downloadCSV(dataToExport, `BNBA_Filtered_Ngumbul_${new Date().toISOString().split('T')[0]}`);
  };

  const finalizeDelete = (reason: string) => {
    if (!deletingFamily) return;

    let kksToUpdate: string[] = [];
    if (deletingFamily.ids) {
      // Multiple delete
      kksToUpdate = headOfFamilies
        .filter(r => deletingFamily.ids!.includes(r.id))
        .map(r => r.noKK);
    } else {
      // Single delete
      kksToUpdate = [deletingFamily.item.noKK];
    }

    setResidents(prev => prev.map(r => {
      if (kksToUpdate.includes(r.noKK) && r.status === 'Aktif') {
        return { 
          ...r, 
          status: 'Terhapus', 
          deleteDate: new Date().toISOString().split('T')[0],
          deleteReason: reason
        };
      }
      return r;
    }));

    setDeletingFamily(null);
    setSelectedIds([]);
  };

  const toggleSelect = (id: string) => {
    setSelectedIds(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const toggleSelectAll = () => {
    if (selectedIds.length === filteredData.length && filteredData.length > 0) {
      setSelectedIds([]);
    } else {
      setSelectedIds(filteredData.map(r => r.id));
    }
  };

  // Fix: Added handleEditSave function to handle resident updates
  const handleEditSave = (updated: Resident) => {
    setResidents(prev => prev.map(r => r.id === updated.id ? updated : r));
    setEditingResident(null);
  };

  // Fix: Added handleAddSave function to handle adding new residents
  const handleAddSave = (newResidents: Resident[]) => {
    setResidents(prev => [...prev, ...newResidents]);
    setIsAddModalOpen(false);
  };

  return (
    <div className="space-y-6">
      {isImporting && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md">
          <div className="bg-white p-10 rounded-3xl shadow-2xl w-full max-w-md text-center">
             <Loader2 className="mx-auto text-blue-600 animate-spin" size={64} />
             <h3 className="text-xl font-black text-slate-900 mt-4 tracking-widest uppercase">Sinkronisasi Data...</h3>
          </div>
        </div>
      )}

      {/* Action Bars */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
        <div className="flex-1 flex items-center bg-slate-100 rounded-2xl px-5 py-3 border border-slate-200 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Kepala Keluarga / NIK / No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button onClick={handleDownloadBNBA} className="flex items-center space-x-2 px-5 py-3 bg-emerald-50 border border-emerald-200 rounded-2xl text-[10px] font-black text-emerald-700 hover:bg-emerald-100 transition-all uppercase tracking-widest shadow-sm">
            <Download size={16} />
            <span>Download BNBA</span>
          </button>

          <button onClick={downloadTemplate} className="flex items-center space-x-2 px-5 py-3 bg-white border border-slate-200 rounded-2xl text-[10px] font-black text-slate-700 hover:bg-slate-50 transition-all uppercase tracking-widest">
            <BookOpen size={16} />
            <span>Format Data</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-3 bg-blue-50 border border-blue-200 rounded-2xl text-[10px] font-black text-blue-700 hover:bg-blue-100 transition-all cursor-pointer uppercase tracking-widest">
            <Upload size={16} />
            <span>Import CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={(e) => {}} accept=".csv" />
          </label>

          <button onClick={() => setIsAddModalOpen(true)} className="flex items-center space-x-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black hover:bg-slate-800 transition-all shadow-lg uppercase tracking-widest">
            <Plus size={16} />
            <span>Tambah KK</span>
          </button>
        </div>
      </div>

      {/* Filter Bertingkat */}
      <div className="flex flex-wrap items-center gap-3 bg-white p-3 rounded-[2rem] border border-slate-200 shadow-sm">
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[150px]">
           <MapPin size={14} className="text-slate-400 mr-2" />
           <select className="bg-transparent text-xs font-black outline-none uppercase w-full" value={filters.dusun} onChange={(e) => setFilters({ ...filters, dusun: e.target.value, rw: '', rt: '' })}>
             <option value="">Pilih Dusun</option>
             {dusunList.map(d => <option key={d} value={d}>{d}</option>)}
           </select>
        </div>
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RW</span>
           <select className="bg-transparent text-xs font-black outline-none w-full" value={filters.rw} onChange={(e) => setFilters({ ...filters, rw: e.target.value, rt: '' })} disabled={!filters.dusun}>
             <option value="">Semua</option>
             {rwList.map(rw => <option key={rw} value={rw}>{rw}</option>)}
           </select>
        </div>
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RT</span>
           <select className="bg-transparent text-xs font-black outline-none w-full" value={filters.rt} onChange={(e) => setFilters({ ...filters, rt: e.target.value })} disabled={!filters.rw}>
             <option value="">Semua</option>
             {rtList.map(rt => <option key={rt} value={rt}>{rt}</option>)}
           </select>
        </div>
        <button onClick={() => setFilters({ dusun: '', rw: '', rt: '' })} className="p-2.5 text-slate-400 hover:text-slate-900 transition-all"><RefreshCcw size={16} /></button>

        <div className="ml-auto">
          {selectedIds.length > 0 && (
            <button onClick={() => setDeletingFamily({ item: residents[0], ids: selectedIds })} className="bg-rose-600 text-white rounded-xl px-5 py-2 text-[10px] font-black flex items-center space-x-2 uppercase tracking-widest shadow-lg shadow-rose-200">
              <Trash2 size={14} />
              <span>Hapus {selectedIds.length} KK</span>
            </button>
          )}
        </div>
      </div>

      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1200px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 w-12 text-center">
                  <button onClick={toggleSelectAll} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-44">Opsi KK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Kepala Keluarga</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-6 py-6 text-center">
                    <button onClick={() => toggleSelect(r.id)} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={22} className="text-blue-600" /> : <Square size={22} />}
                    </button>
                  </td>
                  <td className="px-4 py-6">
                    <div className="flex items-center justify-center space-x-1.5">
                      <button onClick={() => setViewingFamilyKK(r.noKK)} className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"><Eye size={16} /></button>
                      <button onClick={() => setEditingResident(r)} className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm"><Edit3 size={16} /></button>
                      <button onClick={() => setMovingFamily(r)} className="p-2.5 bg-amber-50 text-amber-600 rounded-xl hover:bg-amber-600 hover:text-white transition-all shadow-sm"><PlaneLanding size={16} /></button>
                      <button onClick={() => setDeletingFamily({ item: r })} className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"><Trash2 size={16} /></button>
                    </div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-400 font-bold uppercase">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline" onClick={() => setViewingFamilyKK(r.noKK)}>{r.noKK}</div>
                    <div className="text-[11px] text-slate-400 font-mono tracking-tighter">{r.nik}</div>
                  </td>
                  <td className="px-4 py-6 text-sm font-black text-slate-800 uppercase">{r.fullName}</td>
                  <td className="px-4 py-6 text-center">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400 uppercase">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender.includes('Perempuan') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                      {r.gender.includes('Laki-laki') ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-4 py-6 text-sm text-slate-500 font-medium truncate max-w-[150px]">{r.job || '-'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={handleEditSave} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={handleAddSave} />}
      {deletingFamily && <DeleteConfirmModal item={deletingFamily.item} isMultiple={!!deletingFamily.ids} count={deletingFamily.ids?.length} onClose={() => setDeletingFamily(null)} onConfirm={finalizeDelete} />}
      {movingFamily && <MoveFamilyConfirmModal family={movingFamily} onClose={() => setMovingFamily(null)} onConfirm={(d) => {}} />}
    </div>
  );
};

