export default PopulationManagement;

import React, { useState, useMemo } from 'react';
import { 
  Users, 
  Baby, 
  UserRound, 
  UserCheck, 
  Briefcase, 
  GraduationCap,
  MapPin,
  Home,
  Layers,
  X,
  ArrowRight,
  Info
} from 'lucide-react';
import { 
  PieChart, 
  Pie, 
  Cell, 
  ResponsiveContainer, 
  Tooltip, 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid,
  Legend
} from 'recharts';
import { Resident } from '../types';
import { calculateAge, getAgeGroup } from '../utils/helpers';

interface DashboardProps {
  residents: Resident[];
}

interface DrillDownState {
  title: string;
  type: 'gender' | 'age' | 'dusun';
  value: string;
  breakdown: { label: string, value: number, sublabel?: string }[];
}

const Dashboard: React.FC<DashboardProps> = ({ residents }) => {
  const [drillDown, setDrillDown] = useState<DrillDownState | null>(null);

  // Data Aggregations
  const totalResidents = residents.length;
  const totalKK = useMemo(() => new Set(residents.map(r => r.noKK)).size, [residents]);
  const totalRT = useMemo(() => new Set(residents.map(r => `${r.dusun}-${r.rt}`)).size, [residents]);
  const totalDusun = useMemo(() => new Set(residents.map(r => r.dusun)).size, [residents]);

  const maleCount = residents.filter(r => r.gender.includes('Laki')).length;
  const femaleCount = residents.filter(r => r.gender.includes('Perempuan')).length;

  const ageData = useMemo(() => residents.reduce((acc, r) => {
    const group = getAgeGroup(calculateAge(r.birthDate));
    acc[group] = (acc[group] || 0) + 1;
    return acc;
  }, {} as Record<string, number>), [residents]);

  const dusunData = useMemo(() => residents.reduce((acc, r) => {
    acc[r.dusun] = (acc[r.dusun] || 0) + 1;
    return acc;
  }, {} as Record<string, number>), [residents]);

  const genderChartData = [
    { name: 'Laki-laki', value: maleCount, color: '#1e40af' }, // Deep Navy
    { name: 'Perempuan', value: femaleCount, color: '#db2777' }, // Pink-Rose
  ];

  const dusunChartData = Object.entries(dusunData)
    .map(([name, count]) => ({ name, count }))
    .sort((a, b) => b.count - a.count);

  const ageChartData = Object.entries(ageData).map(([name, value]) => ({ name, value }));

  // Drill down logic
  const handleGenderClick = (entry: any) => {
    const genderName = entry.name;
    const genderResidents = residents.filter(r => r.gender.includes(genderName.includes('Laki') ? 'Laki' : 'Perempuan'));

    const breakdown = Object.entries(
      genderResidents.reduce((acc, r) => {
        acc[r.dusun] = (acc[r.dusun] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    ).map(([dusun, count]) => ({ label: dusun, value: count, sublabel: 'Jiwa' }));

    setDrillDown({
      title: `Sebaran ${genderName} per Dusun`,
      type: 'gender',
      value: genderName,
      breakdown: breakdown.sort((a, b) => b.value - a.value)
    });
  };

  const handleDusunClick = (data: any) => {
    if (!data || !data.activeLabel) return;
    const dusunName = data.activeLabel;
    const dusunResidents = residents.filter(r => r.dusun === dusunName);

    const m = dusunResidents.filter(r => r.gender.includes('Laki')).length;
    const f = dusunResidents.filter(r => r.gender.includes('Perempuan')).length;

    setDrillDown({
      title: `Rincian Penduduk Dusun ${dusunName}`,
      type: 'dusun',
      value: dusunName,
      breakdown: [
        { label: 'Laki-laki', value: m, sublabel: 'Jiwa' },
        { label: 'Perempuan', value: f, sublabel: 'Jiwa' }
      ]
    });
  };

  const handleAgeClick = (data: any) => {
    if (!data || !data.activeLabel) return;
    const ageGroup = data.activeLabel;
    const targetResidents = residents.filter(r => getAgeGroup(calculateAge(r.birthDate)) === ageGroup);

    const breakdown = Object.entries(
      targetResidents.reduce((acc, r) => {
        acc[r.dusun] = (acc[r.dusun] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    ).map(([dusun, count]) => ({ label: dusun, value: count, sublabel: 'Jiwa' }));

    setDrillDown({
      title: `Sebaran ${ageGroup} per Dusun`,
      type: 'age',
      value: ageGroup,
      breakdown: breakdown.sort((a, b) => b.value - a.value)
    });
  };

  const StatCard = ({ icon: Icon, label, value, colorClass, delay }: any) => (
    <div 
      className={`bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200 flex items-center space-x-5 animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-both`}
      style={{ animationDelay: `${delay}ms` }}
    >
      <div className={`p-4 rounded-2xl ${colorClass} transition-all hover:rotate-6 duration-300 shadow-lg shadow-current/10`}>
        <Icon size={28} />
      </div>
      <div>
        <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">{label}</p>
        <p className="text-3xl font-black text-slate-900 tracking-tighter">{value}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-8 pb-10">
      {/* Top Indicators */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard icon={Users} label="Total Penduduk" value={totalResidents} colorClass="bg-blue-600 text-white" delay={0} />
        <StatCard icon={Home} label="Total KK" value={totalKK} colorClass="bg-slate-900 text-white" delay={100} />
        <StatCard icon={Layers} label="Total RT/RW" value={totalRT} colorClass="bg-emerald-600 text-white" delay={200} />
        <StatCard icon={MapPin} label="Total Dusun" value={totalDusun} colorClass="bg-amber-500 text-white" delay={300} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Gender Distribution Pie */}
        <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-200 animate-in fade-in duration-1000">
          <div className="flex items-center justify-between mb-8">
             <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center">
               <Users className="mr-3 text-blue-600" size={20} />
               Gender
             </h3>
             <div className="p-2 bg-slate-50 rounded-lg text-slate-400">
                <Info size={14} />
             </div>
          </div>
          <div className="h-[300px] cursor-pointer">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={genderChartData}
                  cx="50%"
                  cy="50%"
                  innerRadius={70}
                  outerRadius={100}
                  paddingAngle={8}
                  dataKey="value"
                  animationDuration={1500}
                  onClick={handleGenderClick}
                >
                  {genderChartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} className="outline-none hover:opacity-80 transition-opacity" />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)', fontWeight: 'bold' }}
                />
                <Legend verticalAlign="bottom" iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <p className="text-center text-[10px] text-slate-400 font-bold uppercase mt-4 tracking-widest">Klik segmen untuk rincian wilayah</p>
        </div>

        {/* Dusun Bar Chart */}
