} from 'recharts';
import { Resident } from '../types';
import { calculateAge, getAgeGroup } from '../utils/helpers';

interface DashboardProps {
  residents: Resident[];
}

interface DrillDownState {
  title: string;
  type: 'gender' | 'age' | 'dusun';
  value: string;
  breakdown: { label: string, value: number, sublabel?: string }[];
}

const Dashboard: React.FC<DashboardProps> = ({ residents }) => {
  const [drillDown, setDrillDown] = useState<DrillDownState | null>(null);

  // Data Aggregations
  const totalResidents = residents.length;
  const totalKK = useMemo(() => new Set(residents.map(r => r.noKK)).size, [residents]);
  const totalRT = useMemo(() => new Set(residents.map(r => `${r.dusun}-${r.rt}`)).size, [residents]);
  const totalDusun = useMemo(() => new Set(residents.map(r => r.dusun)).size, [residents]);

  const maleCount = residents.filter(r => r.gender.includes('Laki')).length;
  const femaleCount = residents.filter(r => r.gender.includes('Perempuan')).length;

  const ageData = useMemo(() => residents.reduce((acc, r) => {
    const group = getAgeGroup(calculateAge(r.birthDate));
    acc[group] = (acc[group] || 0) + 1;
    return acc;
  }, {} as Record<string, number>), [residents]);

  const dusunData = useMemo(() => residents.reduce((acc, r) => {
    acc[r.dusun] = (acc[r.dusun] || 0) + 1;
    return acc;
