    // Fix: Explicitly treat count as number for subtraction to avoid TS arithmetic error
    .sort((a, b) => Number(b.count) - Number(a.count));

  const ageChartData = Object.entries(ageData).map(([name, value]) => ({ name, value }));

  // Drill down logic
  const handleGenderClick = (entry: any) => {
    const genderName = entry.name;
    const genderResidents = residents.filter(r => r.gender.includes(genderName.includes('Laki') ? 'Laki' : 'Perempuan'));

    const breakdown = Object.entries(
      genderResidents.reduce((acc, r) => {
        acc[r.dusun] = (acc[r.dusun] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    ).map(([dusun, count]) => ({ label: dusun, value: count, sublabel: 'Jiwa' }));

    setDrillDown({
      title: `Sebaran ${genderName} per Dusun`,
      type: 'gender',
      value: genderName,
      // Fix: Explicitly treat value as number for subtraction to avoid TS arithmetic error
      breakdown: breakdown.sort((a, b) => Number(b.value) - Number(a.value))
    });
  };

  const handleDusunClick = (data: any) => {
    if (!data || !data.activeLabel) return;
    const dusunName = data.activeLabel;
    const dusunResidents = residents.filter(r => r.dusun === dusunName);

    const m = dusunResidents.filter(r => r.gender.includes('Laki')).length;
    const f = dusunResidents.filter(r => r.gender.includes('Perempuan')).length;

    setDrillDown({
