      ]
    });
  };

  const handleAgeClick = (data: any) => {
    if (!data || !data.activeLabel) return;
    const ageGroup = data.activeLabel;
    const targetResidents = residents.filter(r => getAgeGroup(calculateAge(r.birthDate)) === ageGroup);

    const breakdown = Object.entries(
