          <p className="text-center text-[10px] text-slate-400 font-bold uppercase mt-4 tracking-widest">Klik segmen untuk rincian wilayah</p>
        </div>

        {/* Dusun Bar Chart */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-200 animate-in fade-in duration-1000">
           <div className="flex items-center justify-between mb-8">
             <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest flex items-center">
               <MapPin className="mr-3 text-emerald-600" size={20} />
