                   <Tooltip cursor={{ fill: '#f8fafc' }} />
                   <Bar 
                     dataKey="count" 
                     fill="#10b981" 
                     radius={[0, 10, 10, 0]} 
                     barSize={24}
                     animationDuration={1500}
                   >
                     {dusunChartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#10b981' : '#059669'} />
