          </div>
          <p className="text-center text-[10px] text-slate-400 font-bold uppercase mt-4 tracking-widest">Klik batang grafik untuk rincian gender</p>
        </div>

        {/* Age Groups Bar Chart */}
        <div className="lg:col-span-3 bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-200 animate-in fade-in duration-1000">
          <div className="flex items-center justify-between mb-8">
