  const [reason, setReason] = useState('');
  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md animate-in zoom-in-95">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-sm overflow-hidden border border-slate-200">
        <div className="p-6 bg-rose-600 text-white font-black text-sm uppercase tracking-widest flex items-center">
           <Trash2 size={18} className="mr-3" />
           <span>Hapus Anggota</span>
        </div>
        <div className="p-8 space-y-6">
           <div className="text-center bg-rose-50 p-4 rounded-2xl border border-rose-100">
              <p className="text-[10px] text-rose-600 font-black uppercase mb-1 tracking-widest">Akan Dipindahkan Ke Arsip</p>
              <p className="text-md font-black uppercase text-slate-900 leading-tight">{member.fullName}</p>
           </div>
           <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Alasan Penghapusan</label>
              <textarea value={reason} onChange={e => setReason(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 font-bold text-sm h-24 resize-none focus:bg-white transition-all" placeholder="Alasan..." required />
           </div>
