          </div>
        </div>

        <div className="flex items-center space-x-3">
          <select 
            className="bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 text-sm outline-none focus:ring-2 focus:ring-blue-500/20"
            value={filter.dusun}
            onChange={(e) => setFilter({...filter, dusun: e.target.value})}
          >
            <option value="">Semua Wilayah</option>
            {Array.from(new Set(residents.map(r => r.dusun))).map(d => <option key={d} value={d}>{d}</option>)}
          </select>
          <button onClick={() => window.print()} className="p-2.5 bg-slate-900 text-white rounded-lg hover:bg-slate-800 transition-all shadow-sm">
            <Printer size={18} />
          </button>
