          <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 bg-slate-50 border-b border-slate-100 font-bold text-sm text-slate-700">
              Tabel Rekapitulasi (Klik Baris untuk BNBA)
            </div>
            <div className="p-2">
              {currentIndicatorData.sort((a,b) => b.value - a.value).map((item, idx) => (
                <button 
                  key={idx} 
                  onClick={() => setSelectedBNBA({ label: activeIndicator?.label || '', value: item.name })}
