import React, { useState, useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  PieChart, 
  Pie, 
  Cell,
  Legend
} from 'recharts';
import { 
  Filter, 
  GraduationCap, 
  Briefcase, 
  Calendar, 
  Heart, 
  MapPin, 
  UserCircle,
  ArrowLeft,
  ChevronRight,
  Printer,
  X,
  FileText,
  Download,
  Users
} from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, getAgeGroup, formatDate } from '../utils/helpers';

interface RecapIndicatorsProps {
  residents: Resident[];
}

// Definisi indikator di luar komponen agar tidak re-render terus menerus
const INDICATORS_CONFIG = [
  { id: 'pendidikan', label: 'Pendidikan', icon: GraduationCap, color: 'bg-blue-500', key: 'education' },
  { id: 'pekerjaan', label: 'Pekerjaan', icon: Briefcase, color: 'bg-emerald-500', key: 'job' },
  { id: 'usia', label: 'Kelompok Usia', icon: Calendar, color: 'bg-amber-500', key: 'ageGroup' },
  { id: 'gender', label: 'Jenis Kelamin', icon: UserCircle, color: 'bg-indigo-500', key: 'gender' },
  { id: 'perkawinan', label: 'Status Perkawinan', icon: Heart, color: 'bg-pink-500', key: 'maritalStatus' },
  { id: 'wilayah', label: 'Sebaran Wilayah', icon: MapPin, color: 'bg-slate-700', key: 'dusun' },
];

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#64748b', '#1e293b'];

const RecapIndicators: React.FC<RecapIndicatorsProps> = ({ residents = [] }) => {
  const [selectedIndicator, setSelectedIndicator] = useState<string | null>(null);
  const [selectedBNBA, setSelectedBNBA] = useState<{ label: string, value: string } | null>(null);
  const [filter, setFilter] = useState({
    dusun: '',
    rw: '',
    rt: ''
  });

  const filteredResidents = useMemo(() => {
    return residents.filter(r => {
      const matchDusun = !filter.dusun || r.dusun === filter.dusun;
      const matchRW = !filter.rw || r.rw === filter.rw;
      const matchRT = !filter.rt || r.rt === filter.rt;
      return matchDusun && matchRW && matchRT;
    });
  }, [residents, filter]);

  const getRecapData = (key: string) => {
    if (!filteredResidents.length) return [];

    const counts = filteredResidents.reduce((acc, r) => {
      let val: string = 'Tidak Terdefinisi';
      if (key === 'ageGroup') {
        val = getAgeGroup(calculateAge(r.birthDate));
      } else if (key in r) {
        val = String(r[key as keyof Resident] || 'Tidak Terdefinisi');
      }
      acc[val] = (acc[val] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.entries(counts)
      .map(([name, value]) => ({ name, value }))
      .sort((a, b) => b.value - a.value);
  };

  const currentIndicatorData = useMemo(() => {
    if (!selectedIndicator) return [];
    const item = INDICATORS_CONFIG.find(i => i.id === selectedIndicator);
    return item ? getRecapData(item.key) : [];
  }, [selectedIndicator, filteredResidents]);

  const bnbaData = useMemo(() => {
    if (!selectedBNBA || !selectedIndicator) return [];
    const item = INDICATORS_CONFIG.find(i => i.id === selectedIndicator);
    if (!item) return [];

    return filteredResidents.filter(r => {
      if (item.key === 'ageGroup') {
        return getAgeGroup(calculateAge(r.birthDate)) === selectedBNBA.value;
      }
      return String(r[item.key as keyof Resident] || 'Tidak Terdefinisi') === selectedBNBA.value;
    });
  }, [selectedBNBA, selectedIndicator, filteredResidents]);

  // Jika belum memilih indikator utama
  if (!selectedIndicator) {
    return (
      <div className="space-y-8 animate-in fade-in duration-500">
        <div className="text-center space-y-2">
          <h2 className="text-2xl font-black text-slate-900 uppercase tracking-tight">Indikator Rekapitulasi Penduduk</h2>
          <p className="text-slate-500 font-medium">Klik pada indikator untuk melihat rincian By Name By Address (BNBA)</p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {INDICATORS_CONFIG.map((item) => {
            const Icon = item.icon;
            return (
              <button
                key={item.id}
                onClick={() => setSelectedIndicator(item.id)}
                className="group bg-white p-8 rounded-3xl shadow-sm border border-slate-200 hover:border-blue-500 hover:shadow-2xl hover:shadow-blue-500/10 transition-all flex flex-col items-center text-center space-y-5 transform hover:-translate-y-2"
              >
                <div className={`${item.color} text-white p-6 rounded-2xl shadow-lg transition-all group-hover:rotate-6 duration-300`}>
                  <Icon size={32} />
                </div>
                <div>
                  <h3 className="text-lg font-black text-slate-800 uppercase tracking-tighter">{item.label}</h3>
                  <p className="text-[10px] text-slate-400 font-black uppercase tracking-widest mt-2 border-t border-slate-50 pt-2">Lihat Grafik & Data</p>
                </div>
                <ChevronRight className="text-slate-200 group-hover:text-blue-600 transition-colors" />
              </button>
            );
          })}
        </div>
      </div>
    );
  }

  const activeIndicator = INDICATORS_CONFIG.find(i => i.id === selectedIndicator);
  const ActiveIcon = activeIndicator?.icon || Users;

  return (
    <div className="space-y-6 animate-in slide-in-from-right-4 duration-500">
