        <div className="flex items-center space-x-5">
          <button 
            onClick={() => setSelectedIndicator(null)}
            className="p-3 bg-slate-100 hover:bg-slate-200 rounded-2xl transition-all text-slate-600"
          >
            <ArrowLeft size={24} />
          </button>
          <div className={`${activeIndicator?.color || 'bg-slate-900'} text-white p-4 rounded-2xl shadow-md`}>
            <ActiveIcon size={24} />
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter">Rekap {activeIndicator?.label}</h2>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Desa Ngumbul, Kec. Todanan</p>
          </div>
        </div>

        <div className="flex items-center flex-wrap gap-3">
          <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2">
            <MapPin size={14} className="text-slate-400 mr-2" />
            <select 
              className="bg-transparent text-xs font-black uppercase outline-none"
              value={filter.dusun}
              onChange={(e) => setFilter({...filter, dusun: e.target.value})}
            >
              <option value="">Seluruh Dusun</option>
              {Array.from(new Set(residents.map(r => r.dusun))).sort().map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <button onClick={() => window.print()} className="flex items-center space-x-2 px-5 py-2.5 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg">
            <Printer size={16} />
            <span>Cetak Rekap</span>
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Sidebar Table */}
        <div className="lg:col-span-1 space-y-6">
          <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-5 bg-slate-50 border-b border-slate-100 font-black text-[10px] text-slate-400 uppercase tracking-widest">
              Tabel Distribusi Data
            </div>
            <div className="p-3 max-h-[500px] overflow-y-auto">
              {currentIndicatorData.length > 0 ? currentIndicatorData.map((item, idx) => (
                <button 
                  key={idx} 
                  onClick={() => setSelectedBNBA({ label: activeIndicator?.label || '', value: item.name })}
                  className="w-full flex items-center justify-between p-4 rounded-2xl hover:bg-blue-50 transition-all border-b border-slate-50 last:border-0 group"
                >
                  <div className="flex items-center space-x-4">
                    <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                    <span className="text-xs font-black text-slate-600 uppercase group-hover:text-blue-700">{item.name}</span>
                  </div>
                  <div className="flex items-center space-x-3">
                    <span className="text-sm font-black text-slate-900">{item.value} <span className="text-[10px] font-normal text-slate-400">Jiwa</span></span>
                    <ChevronRight size={14} className="text-slate-300 group-hover:text-blue-600" />
                  </div>
                </button>
              )) : (
                <div className="p-10 text-center text-[10px] font-black text-slate-300 uppercase">Data tidak tersedia</div>
              )}

              <div className="p-5 bg-blue-50/50 mt-4 rounded-2xl flex justify-between items-center border border-blue-100">
                 <span className="text-[10px] font-black text-blue-700 uppercase">Total Populasi</span>
                 <span className="text-xl font-black text-blue-900">{filteredResidents.length}</span>
              </div>
            </div>
          </div>
        </div>

        {/* Visual Chart */}
        <div className="lg:col-span-2">
          <div className="bg-white p-10 rounded-[2.5rem] shadow-sm border border-slate-200 h-full flex flex-col">
            <h3 className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] mb-10 flex items-center">
              <BarChart size={16} className="mr-3" />
              Visualisasi {activeIndicator?.label}
            </h3>
            <div className="flex-1 min-h-[450px]">
              <ResponsiveContainer width="100%" height="100%">
                {selectedIndicator === 'perkawinan' || selectedIndicator === 'gender' ? (
                  <PieChart>
                    <Pie
                      data={currentIndicatorData}
                      innerRadius={90}
                      outerRadius={140}
                      paddingAngle={8}
                      dataKey="value"
                      animationDuration={1500}
                      onClick={(data) => data && setSelectedBNBA({ label: activeIndicator?.label || '', value: data.name })}
                      className="cursor-pointer"
                    >
                      {currentIndicatorData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} stroke="white" strokeWidth={4} />
                      ))}
                    </Pie>
                    <Tooltip contentStyle={{ borderRadius: '16px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)', fontWeight: '900', fontSize: '12px' }} />
                    <Legend verticalAlign="bottom" height={36} iconType="circle" />
                  </PieChart>
                ) : (
                  <BarChart 
                    data={currentIndicatorData} 
                    layout="vertical"
                    onClick={(data: any) => {
                      if (data && data.activeLabel) {
                        setSelectedBNBA({ label: activeIndicator?.label || '', value: String(data.activeLabel) });
                      }
                    }}
                    className="cursor-pointer"
                  >
                    <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                    <XAxis type="number" hide />
                    <YAxis dataKey="name" type="category" width={140} tick={{ fontSize: 10, fontWeight: 900, fill: '#64748b' }} axisLine={false} tickLine={false} />
                    <Tooltip cursor={{ fill: '#f8fafc' }} />
                    <Bar 
                      dataKey="value" 
                      fill="#3b82f6" 
                      radius={[0, 12, 12, 0]} 
                      animationDuration={1500}
                      barSize={32}
                    >
                      {currentIndicatorData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                      ))}
                    </Bar>
                  </BarChart>
                )}
              </ResponsiveContainer>
            </div>
            <p className="text-center text-[10px] text-slate-400 font-bold uppercase mt-8 tracking-widest animate-pulse">Klik segmen grafik untuk rincian penduduk (BNBA)</p>
          </div>
        </div>
      </div>

      {/* BNBA Modal */}
      {selectedBNBA && (
