      let val: string = 'Tidak Terdefinisi';
      if (key === 'ageGroup') {
        val = getAgeGroup(calculateAge(r.birthDate));
      } else if (key in r) {
        val = String(r[key as keyof Resident] || 'Tidak Terdefinisi');
      }
      acc[val] = (acc[val] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.entries(counts)
      .map(([name, value]) => ({ name, value }))
      // Fix: Explicitly treat value as number for subtraction to avoid TS arithmetic error
      .sort((a, b) => Number(b.value) - Number(a.value));
  };

  const currentIndicatorData = useMemo(() => {
