              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-24 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Data tidak ditemukan.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* FORMAT RESMI PRINT PDF - HANYA MUNCUL SAAT DI CETAK */}
      <div className="print-only">
        {/* Kop Surat Resmi */}
        <div className="report-header">
           <img src="https://upload.wikimedia.org/wikipedia/commons/1/1d/Lambang_Kabupaten_Blora.png" alt="Blora Logo" />
