              <h1>PEMERINTAH KABUPATEN BLORA</h1>
              <h2>KECAMATAN TODANAN - DESA NGUMBUL</h2>
              <p>Alamat: Jl. Raya Todanan-Ngumbul KM. 05, Desa Ngumbul, Kec. Todanan, Kab. Blora (58256)</p>
              <p>Email: desangumbul.blora@gmail.com | Website: https://ngumbul-todanan.desa.id</p>
           </div>
        </div>

        <div className="report-title">
           DAFTAR PENDUDUK BY NAME BY ADDRESS (BNBA)
        </div>

        <div className="report-meta">
           <div>
              <strong>Wilayah:</strong> {filters.dusun || 'KESELURUHAN DESA'} {filters.rw ? `/ RW ${filters.rw}` : ''} {filters.rt ? `/ RT ${filters.rt}` : ''}
           </div>
           <div className="text-right">
              <strong>Kondisi Data Per Tanggal:</strong> {new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}
           </div>
        </div>

        <table>
           <thead>
              <tr>
                 <th className="w-8">NO</th>
                 <th>NAMA LENGKAP</th>
                 <th>NIK</th>
                 <th>NOMOR KK</th>
                 <th>ALAMAT (DUSUN/RW/RT)</th>
