                    <td className="font-mono">{r.noKK}</td>
                    <td className="text-center">{r.dusun} / {r.rw} / {r.rt}</td>
                    <td className="text-center">{r.gender.includes('Laki') ? 'L' : 'P'}</td>
                    <td className="text-center">{calculateAge(r.birthDate)}</td>
                    <td className="text-[7pt]">{r.relationship.includes('. ') ? r.relationship.split('. ')[1] : r.relationship}</td>
                    <td className="text-[7pt]">{r.education.includes('. ') ? r.education.split('. ')[1] : r.education}</td>
                    <td className="text-[7pt] uppercase">{r.job.includes('. ') ? r.job.split('. ')[1] : r.job}</td>
                 </tr>
              )) : (
                <tr><td colSpan={10} className="text-center italic py-4 text-xs uppercase">Data Tidak Tersedia</td></tr>
              )}
           </tbody>
        </table>

        {/* Tanda Tangan Resmi */}
        <div className="signature-section">
           <div className="signature-box">
              <p>Ngumbul, {new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}</p>
              <p className="font-bold">KEPALA DESA NGUMBUL</p>
              <div className="signature-space"></div>
              <p className="signature-name">SULARNO</p>
              <p className="text-[8pt] italic">Sistem SIGA Ngumbul - Kabupaten Blora</p>
           </div>
        </div>
      </div>

      {/* Modals Section */}
      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={handleEditSave} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={handleAddSave} />}
      {deletingFamily && <DeleteConfirmModal item={deletingFamily.item} onClose={() => setDeletingFamily(null)} onConfirm={(reason) => {
          setResidents(prev => prev.map(r => r.noKK === deletingFamily.item.noKK ? {...r, status: 'Terhapus', deleteDate: new Date().toISOString().split('T')[0], deleteReason: reason} : r));
          setDeletingFamily(null);
      }} />}
    </div>
  );
};

