           <div>
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest block mb-2">Alasan Penghapusan</label>
              <textarea value={reason} onChange={e => setReason(e.target.value)} className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-5 py-4 outline-none font-bold text-sm h-32 resize-none focus:bg-white transition-all" placeholder="Contoh: Kesalahan input..." required />
           </div>
           <button onClick={() => reason.trim() ? onConfirm(reason) : alert("Isi alasan!")} className="w-full py-4 bg-rose-600 text-white rounded-2xl font-black text-sm uppercase shadow-xl hover:bg-rose-700 transition-all">Pindahkan ke Arsip Terhapus</button>
        </div>
      </div>
    </div>
  );
};

