import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  Upload,
  BookOpen,
  Loader2,
  MapPin,
  X,
  Edit3,
  Download,
  RefreshCcw,
  Printer,
  Info
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Resident, BloodType, MaritalStatus, Education, ResidentStatus } from '../types';
import { calculateAge, downloadTemplate, downloadCSV } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [isPreparingPDF, setIsPreparingPDF] = useState(false);
  const [filters, setFilters] = useState({ dusun: '', rw: '', rt: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [deletingFamily, setDeletingFamily] = useState<{item: Resident, ids?: string[]} | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);

  const dusunList = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))).sort(), [activeResidents]);

  const rwList = useMemo(() => {
    const filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    return Array.from(new Set(filtered.map(r => r.rw))).sort();
  }, [activeResidents, filters.dusun]);

  const rtList = useMemo(() => {
    let filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    if (filters.rw) filtered = filtered.filter(r => r.rw === filters.rw);
    return Array.from(new Set(filtered.map(r => r.rt))).sort();
  }, [activeResidents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const s = searchTerm.toLowerCase();
      const matchSearch = r.fullName.toLowerCase().includes(s) || r.nik.includes(s) || r.noKK.includes(s);
      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;
      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const residentsToExport = useMemo(() => {
    const displayedKKs = new Set(filteredData.map(r => r.noKK.trim()));
    return activeResidents
      .filter(r => displayedKKs.has(r.noKK.trim()))
      .sort((a, b) => {
        if (a.dusun !== b.dusun) return a.dusun.localeCompare(b.dusun);
        if (a.rw !== b.rw) return a.rw.localeCompare(b.rw);
        if (a.rt !== b.rt) return a.rt.localeCompare(b.rt);
        if (a.noKK !== b.noKK) return a.noKK.localeCompare(b.noKK);
        return a.relationship.localeCompare(b.relationship);
      });
  }, [filteredData, activeResidents]);

  const handleDownloadPDF = async () => {
    if (residentsToExport.length === 0) return alert("Tidak ada data untuk dicetak.");
    setIsPreparingPDF(true);

    try {
      const doc = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4'
      });

      const addHeader = (data: any) => {
        doc.setFontSize(14);
        doc.setFont('helvetica', 'bold');
        doc.text('PEMERINTAH KABUPATEN BLORA', 148.5, 15, { align: 'center' });
        doc.setFontSize(12);
        doc.text('KECAMATAN TODANAN - DESA NGUMBUL', 148.5, 21, { align: 'center' });
        doc.setFontSize(8);
        doc.setFont('helvetica', 'normal');
        doc.text('Alamat: Jl. Raya Todanan-Ngumbul KM. 05, Desa Ngumbul, Kec. Todanan, Kab. Blora (58256)', 148.5, 26, { align: 'center' });
        doc.setLineWidth(0.5);
        doc.line(20, 28, 277, 28);
        doc.setLineWidth(0.1);
        doc.line(20, 29, 277, 29);

        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.text('DAFTAR PENDUDUK BY NAME BY ADDRESS (BNBA)', 148.5, 38, { align: 'center' });

        doc.setFontSize(8);
        doc.setFont('helvetica', 'normal');
        doc.text(`Wilayah: ${filters.dusun || 'Seluruh Desa'} ${filters.rw ? '/ RW ' + filters.rw : ''} ${filters.rt ? '/ RT ' + filters.rt : ''}`, 20, 45);
        doc.text(`Tanggal Cetak: ${new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}`, 277, 45, { align: 'right' });
      };

      const tableData = residentsToExport.map((r, idx) => [
        idx + 1,
        r.fullName.toUpperCase(),
        r.nik,
        r.noKK,
        `${r.dusun} / ${r.rw} / ${r.rt}`,
        r.gender.includes('Laki') ? 'L' : 'P',
        calculateAge(r.birthDate),
        r.relationship.split('. ').pop() || r.relationship,
        r.education.split('. ').pop() || r.education,
        r.job.split('. ').pop()?.toUpperCase() || r.job.toUpperCase()
      ]);

      autoTable(doc, {
        head: [['NO', 'NAMA LENGKAP', 'NIK', 'NOMOR KK', 'ALAMAT (DS/RW/RT)', 'JK', 'USIA', 'HUBUNGAN', 'PENDIDIKAN', 'PEKERJAAN']],
        body: tableData,
        startY: 50,
        styles: { fontSize: 7, cellPadding: 1.5, lineColor: [0, 0, 0], lineWidth: 0.1 },
        headStyles: { fillColor: [230, 230, 230], textColor: [0, 0, 0], fontStyle: 'bold', halign: 'center' },
        columnStyles: {
          0: { halign: 'center', cellWidth: 8 },
          1: { fontStyle: 'bold', cellWidth: 45 },
          5: { halign: 'center', cellWidth: 8 },
          6: { halign: 'center', cellWidth: 10 },
        },
        margin: { top: 50, bottom: 40 },
        didDrawPage: (data) => {
          if (data.pageNumber === 1) {
            addHeader(data);
          }
        }
      });

      const finalY = (doc as any).lastAutoTable.finalY || 150;
      const signatureY = finalY + 15;

      let currentY: number;
      if (signatureY > 170) {
        doc.addPage();
        currentY = 20;
      } else {
        currentY = signatureY;
      }

      const dateStr = `Ngumbul, ${new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}`;
      doc.setFontSize(9);
      doc.text(dateStr, 230, currentY, { align: 'center' });
      doc.setFont('helvetica', 'bold');
      doc.text('KEPALA DESA NGUMBUL', 230, currentY + 5, { align: 'center' });
      doc.text('SULARNO', 230, currentY + 25, { align: 'center' });
      doc.setLineWidth(0.2);
      doc.line(210, currentY + 26, 250, currentY + 26);

      doc.save(`BNBA_Ngumbul_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (error) {
      console.error("PDF Generation Error:", error);
      alert("Gagal membuat PDF. Pastikan koneksi internet stabil.");
    } finally {
      setIsPreparingPDF(false);
    }
  };

  const handleDownloadCSV = () => {
    if (residentsToExport.length === 0) return alert("Tidak ada data untuk diekspor.");
    const dataToExport = residentsToExport.map(r => ({
      'Dusun': r.dusun, 'RW': r.rw, 'RT': r.rt, 'No. KK': r.noKK, 'NIK': r.nik, 
      'Nama Lengkap': r.fullName, 'Hubungan': r.relationship, 'Tgl Lahir': r.birthDate,
      'Usia': calculateAge(r.birthDate), 'JK': r.gender, 'Gol. Darah': r.bloodType,
      'Status': r.maritalStatus, 'Pendidikan': r.education, 'Pekerjaan': r.job
    }));
    downloadCSV(dataToExport, `BNBA_Ngumbul_${new Date().toISOString().split('T')[0]}`);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
        const newResidents: Resident[] = lines.slice(1).map((line, index) => {
          const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => item[h] = values[i] || '');
          const rel = item['Status Hubungan dalam Keluarga'] || item['Hubungan'] || '';
          return {
            id: `imp-${Date.now()}-${index}`,
            dusun: item['Dusun'] || '-',
            rt: item['RT'] || '-',
            rw: item['RW'] || '-',
            noKK: (item['No.KK'] || item['No. KK'] || '').replace(/\D/g, '').slice(0, 16),
            nik: (item['NIK'] || '').replace(/\D/g, '').slice(0, 16),
            fullName: (item['Nama Lengkap'] || '-').toUpperCase(),
            relationship: rel,
            birthPlace: item['Tempat Lahir'] || '', 
            birthDate: item['Tanggal Lahir'] || item['Tgl Lahir'] || '1990-01-01',
            gender: (item['Jenis Kelamin'] || item['JK'] || '').includes('P') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || item['Gol. Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || item['Status'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || item['Pendidikan'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: rel.toLowerCase().includes('kepala keluarga') || rel.startsWith('1'),
            status: 'Aktif' as ResidentStatus
          };
        });
        setResidents(prev => [...prev, ...newResidents]);
        setIsImporting(false);
        alert(`Berhasil mengimpor ${newResidents.length} data penduduk.`);
        if (fileInputRef.current) fileInputRef.current.value = '';
      } catch (err) {
        alert('Gagal mengimpor file.');
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-6">
      {(isImporting || isPreparingPDF) && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md no-print">
          <div className="bg-white p-10 rounded-3xl shadow-2xl text-center max-w-sm">
             <Loader2 className="mx-auto text-blue-600 animate-spin mb-4" size={56} />
             <h3 className="text-xl font-black text-slate-900 tracking-tight uppercase">
                {isPreparingPDF ? "Menyiapkan File PDF..." : "Memproses Data..."}
             </h3>
             <p className="text-slate-500 text-xs font-bold mt-2 leading-relaxed uppercase">
                {isPreparingPDF ? "Data BNBA sedang dikonversi menjadi file PDF resmi. File akan otomatis terunduh." : "Mohon tunggu sejenak."}
             </p>
          </div>
        </div>
      )}

      {/* Main Action Bar */}
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200 no-print">
        <div className="flex-1 flex items-center bg-slate-100 rounded-2xl px-5 py-3 border border-slate-200 max-w-md focus-within:bg-white focus-within:ring-4 focus-within:ring-blue-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Nama / NIK / No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="flex items-center flex-wrap gap-2">
          <button 
            onClick={handleDownloadPDF} 
            className="flex items-center space-x-2 px-6 py-3 bg-red-600 text-white rounded-2xl text-[10px] font-black hover:bg-red-700 transition-all uppercase tracking-widest shadow-lg shadow-red-200"
          >
            <Download size={16} />
            <span>Unduh PDF BNBA</span>
          </button>

          <button onClick={handleDownloadCSV} className="flex items-center space-x-2 px-5 py-3 bg-emerald-50 border border-emerald-200 rounded-2xl text-[10px] font-black text-emerald-700 hover:bg-emerald-100 transition-all uppercase tracking-widest shadow-sm">
            <Download size={16} />
            <span>Ekspor CSV</span>
          </button>

          <button onClick={downloadTemplate} className="flex items-center space-x-2 px-5 py-3 bg-white border border-slate-200 rounded-2xl text-[10px] font-black text-slate-700 hover:bg-slate-50 transition-all uppercase tracking-widest">
            <BookOpen size={16} />
            <span>Format Data</span>
          </button>

          <label className="flex items-center space-x-2 px-5 py-3 bg-blue-50 border border-blue-200 rounded-2xl text-[10px] font-black text-blue-700 hover:bg-blue-100 transition-all cursor-pointer uppercase tracking-widest">
            <Upload size={16} />
            <span>Import CSV</span>
            <input ref={fileInputRef} type="file" className="hidden" onChange={handleImport} accept=".csv" />
          </label>

          <button onClick={() => setIsAddModalOpen(true)} className="flex items-center space-x-2 px-6 py-3 bg-slate-900 text-white rounded-2xl text-[10px] font-black hover:bg-slate-800 transition-all shadow-lg uppercase tracking-widest">
            <Plus size={16} />
            <span>Tambah KK</span>
          </button>
        </div>
      </div>

      {/* Advanced Filter Bar */}
      <div className="flex flex-wrap items-center gap-3 bg-white p-3 rounded-[2rem] border border-slate-200 shadow-sm no-print">
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[150px]">
           <MapPin size={14} className="text-slate-400 mr-2" />
           <select className="bg-transparent text-xs font-black uppercase outline-none uppercase w-full" value={filters.dusun} onChange={(e) => setFilters({ ...filters, dusun: e.target.value, rw: '', rt: '' })}>
             <option value="">Pilih Dusun</option>
             {dusunList.map(d => <option key={d} value={d}>{d}</option>)}
           </select>
        </div>
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RW</span>
           <select className="bg-transparent text-xs font-black outline-none w-full" value={filters.rw} onChange={(e) => setFilters({ ...filters, rw: e.target.value, rt: '' })} disabled={!filters.dusun}>
             <option value="">Semua</option>
             {rwList.map(rw => <option key={rw} value={rw}>{rw}</option>)}
           </select>
        </div>
        <div className="flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2 min-w-[100px]">
           <span className="text-[10px] font-black text-slate-400 mr-2 uppercase">RT</span>
           <select className="bg-transparent text-xs font-black outline-none w-full" value={filters.rt} onChange={(e) => setFilters({ ...filters, rt: e.target.value })} disabled={!filters.rw}>
             <option value="">Semua</option>
             {rtList.map(rt => <option key={rt} value={rt}>{rt}</option>)}
           </select>
        </div>
        <button onClick={() => setFilters({ dusun: '', rw: '', rt: '' })} className="p-2.5 text-slate-400 hover:text-slate-900 transition-all hover:rotate-180 duration-500"><RefreshCcw size={16} /></button>
        <div className="ml-auto flex items-center space-x-2 text-[10px] font-black text-slate-400 uppercase tracking-widest pr-4">
          <Info size={14} />
          <span>{filteredData.length} KK Terfilter</span>
        </div>
      </div>

      {/* Screen Table */}
      <div className="bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden no-print">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse min-w-[1100px]">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-5 w-12 text-center">
                  <button onClick={() => selectedIds.length === filteredData.length ? setSelectedIds([]) : setSelectedIds(filteredData.map(r => r.id))} className="text-slate-400">
                    {selectedIds.length === filteredData.length && filteredData.length > 0 ? <CheckSquare size={20} className="text-blue-600" /> : <Square size={20} />}
                  </button>
                </th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center w-40">Aksi</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Wilayah</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">No. KK / NIK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nama Kepala Keluarga</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Usia / JK</th>
                <th className="px-4 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pekerjaan</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredData.map((r) => (
                <tr key={r.id} className="hover:bg-blue-50/30 transition-all group">
                  <td className="px-6 py-6 text-center">
                    <button onClick={() => setSelectedIds(prev => prev.includes(r.id) ? prev.filter(i => i !== r.id) : [...prev, r.id])} className="text-slate-300">
                      {selectedIds.includes(r.id) ? <CheckSquare size={22} className="text-blue-600" /> : <Square size={22} />}
                    </button>
                  </td>
                  <td className="px-4 py-6">
                    <div className="flex items-center justify-center space-x-1">
                      <button onClick={() => setViewingFamilyKK(r.noKK)} className="p-2.5 bg-blue-50 text-blue-600 rounded-xl hover:bg-blue-600 hover:text-white transition-all shadow-sm"><Eye size={16} /></button>
                      <button onClick={() => setEditingResident(r)} className="p-2.5 bg-slate-50 text-slate-600 rounded-xl hover:bg-slate-900 hover:text-white transition-all shadow-sm"><Edit3 size={16} /></button>
                      <button onClick={() => setDeletingFamily({ item: r })} className="p-2.5 bg-rose-50 text-rose-600 rounded-xl hover:bg-rose-600 hover:text-white transition-all shadow-sm"><Trash2 size={16} /></button>
                    </div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-slate-900">{r.dusun}</div>
                    <div className="text-[11px] text-slate-400 font-bold uppercase">RT {r.rt} / RW {r.rw}</div>
                  </td>
                  <td className="px-4 py-6">
                    <div className="text-sm font-black text-blue-600 cursor-pointer hover:underline" onClick={() => setViewingFamilyKK(r.noKK)}>{r.noKK}</div>
                    <div className="text-[11px] text-slate-400 font-mono">{r.nik}</div>
                  </td>
                  <td className="px-4 py-6 text-sm font-black text-slate-800 uppercase">{r.fullName}</td>
                  <td className="px-4 py-6 text-center">
                    <div className="text-sm font-black text-slate-900">{calculateAge(r.birthDate)} <span className="text-[10px] font-normal text-slate-400">Thn</span></div>
                    <div className={`text-[9px] uppercase font-black px-2 py-0.5 rounded-full inline-block mt-1 ${r.gender.includes('Perempuan') ? 'bg-pink-100 text-pink-700' : 'bg-blue-100 text-blue-700'}`}>
                      {r.gender.includes('Laki-laki') ? 'L' : 'P'}
                    </div>
                  </td>
                  <td className="px-4 py-6 text-sm text-slate-500 font-medium truncate max-w-[180px]">{r.job || '-'}</td>
                </tr>
              ))}
              {filteredData.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-24 text-center text-slate-400 font-black uppercase tracking-widest text-xs">Data tidak ditemukan.</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Modals Section */}
      {viewingFamilyKK && <FamilyDetailModal noKK={viewingFamilyKK} residents={residents} setResidents={setResidents} onClose={() => setViewingFamilyKK(null)} />}
      {editingResident && <EditResidentModal resident={editingResident} onClose={() => setEditingResident(null)} onSave={(u) => { setResidents(prev => prev.map(r => r.id === u.id ? u : r)); setEditingResident(null); }} />}
      {isAddModalOpen && <AddResidentModal onClose={() => setIsAddModalOpen(false)} onSave={(nr) => { setResidents(prev => [...prev, ...nr]); setIsAddModalOpen(false); }} />}
      {deletingFamily && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden border border-slate-200">
            <div className="p-6 bg-slate-900 text-white flex justify-between items-center uppercase font-black tracking-widest text-sm">
               <span>Hapus Keluarga (Arsip)</span>
               <button onClick={() => setDeletingFamily(null)}><X size={24}/></button>
            </div>
            <div className="p-8 space-y-4">
               <div className="text-center bg-rose-50 p-5 rounded-2xl border border-rose-100">
                 <p className="text-xs font-black text-rose-600 uppercase mb-2 tracking-widest">Akan Dipindahkan Ke Arsip Terhapus</p>
                 <h5 className="text-lg font-black text-slate-900 uppercase leading-tight">{deletingFamily.item.fullName}</h5>
               </div>
               <div className="pt-2 space-y-3">
                 <button onClick={() => {
                    setResidents(prev => prev.map(r => r.noKK === deletingFamily.item.noKK ? {...r, status: 'Terhapus' as ResidentStatus, deleteDate: new Date().toISOString().split('T')[0], deleteReason: 'Penghapusan via Antarmuka'} : r));
                    setDeletingFamily(null);
                 }} className="w-full py-4 bg-rose-600 text-white rounded-2xl font-black text-sm uppercase shadow-xl hover:bg-rose-700 transition-all">Konfirmasi Hapus Keluarga</button>
                 <button onClick={() => setDeletingFamily(null)} className="w-full py-3 text-center text-xs font-black text-slate-400 uppercase tracking-widest hover:text-slate-900 transition-all">Batal & Kembali</button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PopulationManagement;

import React, { useState, useMemo, useRef } from 'react';
import { 
  Search, 
  Plus, 
  Trash2, 
  Eye,
  CheckSquare,
  Square,
  Upload,
  BookOpen,
  Loader2,
  MapPin,
  X,
  Edit3,
  Download,
  RefreshCcw,
  Printer,
  Info,
  PlaneLanding,
  Calendar,
  Save
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Resident, BloodType, MaritalStatus, Education, ResidentStatus } from '../types';
import { calculateAge, downloadTemplate, downloadCSV } from '../utils/helpers';
import FamilyDetailModal from './FamilyDetailModal';
import EditResidentModal from './EditResidentModal';
import AddResidentModal from './AddResidentModal';

interface PopulationManagementProps {
  residents: Resident[];
  setResidents: React.Dispatch<React.SetStateAction<Resident[]>>;
}

const PopulationManagement: React.FC<PopulationManagementProps> = ({ residents, setResidents }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [isImporting, setIsImporting] = useState(false);
  const [isPreparingPDF, setIsPreparingPDF] = useState(false);
  const [filters, setFilters] = useState({ dusun: '', rw: '', rt: '' });
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [viewingFamilyKK, setViewingFamilyKK] = useState<string | null>(null);
  const [editingResident, setEditingResident] = useState<Resident | null>(null);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [deletingFamily, setDeletingFamily] = useState<{item: Resident, ids?: string[]} | null>(null);
  const [movingFamily, setMovingFamily] = useState<Resident | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const activeResidents = useMemo(() => residents.filter(r => r.status === 'Aktif'), [residents]);
  const headOfFamilies = useMemo(() => activeResidents.filter(r => r.isHeadOfFamily), [activeResidents]);

  const dusunList = useMemo(() => Array.from(new Set(activeResidents.map(r => r.dusun))).sort(), [activeResidents]);

  const rwList = useMemo(() => {
    const filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    return Array.from(new Set(filtered.map(r => r.rw))).sort();
  }, [activeResidents, filters.dusun]);

  const rtList = useMemo(() => {
    let filtered = filters.dusun ? activeResidents.filter(r => r.dusun === filters.dusun) : activeResidents;
    if (filters.rw) filtered = filtered.filter(r => r.rw === filters.rw);
    return Array.from(new Set(filtered.map(r => r.rt))).sort();
  }, [activeResidents, filters.dusun, filters.rw]);

  const filteredData = useMemo(() => {
    return headOfFamilies.filter(r => {
      const s = searchTerm.toLowerCase();
      const matchSearch = r.fullName.toLowerCase().includes(s) || r.nik.includes(s) || r.noKK.includes(s);
      const matchDusun = !filters.dusun || r.dusun === filters.dusun;
      const matchRW = !filters.rw || r.rw === filters.rw;
      const matchRT = !filters.rt || r.rt === filters.rt;
      return matchSearch && matchDusun && matchRW && matchRT;
    });
  }, [headOfFamilies, searchTerm, filters]);

  const residentsToExport = useMemo(() => {
    const displayedKKs = new Set(filteredData.map(r => r.noKK.trim()));
    return activeResidents
      .filter(r => displayedKKs.has(r.noKK.trim()))
      .sort((a, b) => {
        if (a.dusun !== b.dusun) return a.dusun.localeCompare(b.dusun);
        if (a.rw !== b.rw) return a.rw.localeCompare(b.rw);
        if (a.rt !== b.rt) return a.rt.localeCompare(b.rt);
        if (a.noKK !== b.noKK) return a.noKK.localeCompare(b.noKK);
        return a.relationship.localeCompare(b.relationship);
      });
  }, [filteredData, activeResidents]);

  const handleDownloadPDF = async () => {
    if (residentsToExport.length === 0) return alert("Tidak ada data untuk dicetak.");
    setIsPreparingPDF(true);

    try {
      const doc = new jsPDF({
        orientation: 'landscape',
        unit: 'mm',
        format: 'a4'
      });

      const addHeader = (data: any) => {
        doc.setFontSize(14);
        doc.setFont('helvetica', 'bold');
        doc.text('PEMERINTAH KABUPATEN BLORA', 148.5, 15, { align: 'center' });
        doc.setFontSize(12);
        doc.text('KECAMATAN TODANAN - DESA NGUMBUL', 148.5, 21, { align: 'center' });
        doc.setFontSize(8);
        doc.setFont('helvetica', 'normal');
        doc.text('Alamat: Jl. Raya Todanan-Ngumbul KM. 05, Desa Ngumbul, Kec. Todanan, Kab. Blora (58256)', 148.5, 26, { align: 'center' });
        doc.setLineWidth(0.5);
        doc.line(20, 28, 277, 28);
        doc.setLineWidth(0.1);
        doc.line(20, 29, 277, 29);

        doc.setFontSize(11);
        doc.setFont('helvetica', 'bold');
        doc.text('DAFTAR PENDUDUK BY NAME BY ADDRESS (BNBA)', 148.5, 38, { align: 'center' });

        doc.setFontSize(8);
        doc.setFont('helvetica', 'normal');
        doc.text(`Wilayah: ${filters.dusun || 'Seluruh Desa'} ${filters.rw ? '/ RW ' + filters.rw : ''} ${filters.rt ? '/ RT ' + filters.rt : ''}`, 20, 45);
        doc.text(`Tanggal Cetak: ${new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}`, 277, 45, { align: 'right' });
      };

      const tableData = residentsToExport.map((r, idx) => [
        idx + 1,
        r.fullName.toUpperCase(),
        r.nik,
        r.noKK,
        `${r.dusun} / ${r.rw} / ${r.rt}`,
        r.gender.includes('Laki') ? 'L' : 'P',
        calculateAge(r.birthDate),
        r.relationship.split('. ').pop() || r.relationship,
        r.education.split('. ').pop() || r.education,
        r.job.split('. ').pop()?.toUpperCase() || r.job.toUpperCase()
      ]);

      autoTable(doc, {
        head: [['NO', 'NAMA LENGKAP', 'NIK', 'NOMOR KK', 'ALAMAT (DS/RW/RT)', 'JK', 'USIA', 'HUBUNGAN', 'PENDIDIKAN', 'PEKERJAAN']],
        body: tableData,
        startY: 50,
        styles: { fontSize: 7, cellPadding: 1.5, lineColor: [0, 0, 0], lineWidth: 0.1 },
        headStyles: { fillColor: [230, 230, 230], textColor: [0, 0, 0], fontStyle: 'bold', halign: 'center' },
        columnStyles: {
          0: { halign: 'center', cellWidth: 8 },
          1: { fontStyle: 'bold', cellWidth: 45 },
          5: { halign: 'center', cellWidth: 8 },
          6: { halign: 'center', cellWidth: 10 },
        },
        margin: { top: 50, bottom: 40 },
        didDrawPage: (data) => {
          if (data.pageNumber === 1) {
            addHeader(data);
          }
        }
      });

      const finalY = (doc as any).lastAutoTable.finalY || 150;
      const signatureY = finalY + 15;

      let currentY: number;
      if (signatureY > 170) {
        doc.addPage();
        currentY = 20;
      } else {
        currentY = signatureY;
      }

      const dateStr = `Ngumbul, ${new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}`;
      doc.setFontSize(9);
      doc.text(dateStr, 230, currentY, { align: 'center' });
      doc.setFont('helvetica', 'bold');
      doc.text('KEPALA DESA NGUMBUL', 230, currentY + 5, { align: 'center' });
      doc.text('SULARNO', 230, currentY + 25, { align: 'center' });
      doc.setLineWidth(0.2);
      doc.line(210, currentY + 26, 250, currentY + 26);

      doc.save(`BNBA_Ngumbul_${new Date().toISOString().split('T')[0]}.pdf`);
    } catch (error) {
      console.error("PDF Generation Error:", error);
      alert("Gagal membuat PDF. Pastikan koneksi internet stabil.");
    } finally {
      setIsPreparingPDF(false);
    }
  };

  const handleDownloadCSV = () => {
    if (residentsToExport.length === 0) return alert("Tidak ada data untuk diekspor.");
    const dataToExport = residentsToExport.map(r => ({
      'Dusun': r.dusun, 'RW': r.rw, 'RT': r.rt, 'No. KK': r.noKK, 'NIK': r.nik, 
      'Nama Lengkap': r.fullName, 'Hubungan': r.relationship, 'Tgl Lahir': r.birthDate,
      'Usia': calculateAge(r.birthDate), 'JK': r.gender, 'Gol. Darah': r.bloodType,
      'Status': r.maritalStatus, 'Pendidikan': r.education, 'Pekerjaan': r.job
    }));
    downloadCSV(dataToExport, `BNBA_Ngumbul_${new Date().toISOString().split('T')[0]}`);
  };

  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsImporting(true);
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim() !== '');
        const delimiter = lines[0].includes(';') ? ';' : ',';
        const headers = lines[0].split(delimiter).map(h => h.trim().replace(/^"|"$/g, ''));
        const newResidents: Resident[] = lines.slice(1).map((line, index) => {
          const values = line.split(delimiter).map(v => v.trim().replace(/^"|"$/g, ''));
          const item: any = {};
          headers.forEach((h, i) => item[h] = values[i] || '');
          const rel = item['Status Hubungan dalam Keluarga'] || item['Hubungan'] || '';
          return {
            id: `imp-${Date.now()}-${index}`,
            dusun: item['Dusun'] || '-',
            rt: item['RT'] || '-',
            rw: item['RW'] || '-',
            noKK: (item['No.KK'] || item['No. KK'] || '').replace(/\D/g, '').slice(0, 16),
            nik: (item['NIK'] || '').replace(/\D/g, '').slice(0, 16),
            fullName: (item['Nama Lengkap'] || '-').toUpperCase(),
            relationship: rel,
            birthPlace: item['Tempat Lahir'] || '', 
            birthDate: item['Tanggal Lahir'] || item['Tgl Lahir'] || '1990-01-01',
            gender: (item['Jenis Kelamin'] || item['JK'] || '').includes('P') ? 'Perempuan' : 'Laki-laki',
            bloodType: (item['Golongan Darah'] || item['Gol. Darah'] || 'Tidak Tahu') as BloodType,
            maritalStatus: (item['Status Perkawinan'] || item['Status'] || 'Belum Kawin') as MaritalStatus,
            education: (item['Pendidikan Tertinggi'] || item['Pendidikan'] || 'SMA') as Education,
            job: item['Pekerjaan'] || '',
            fatherName: item['Nama Ayah Kandung'] || '',
            motherName: item['Nama Ibu Kandung'] || '',
            isHeadOfFamily: rel.toLowerCase().includes('kepala keluarga') || rel.startsWith('1'),
            status: 'Aktif' as ResidentStatus
          };
        });
        setResidents(prev => [...prev, ...newResidents]);
        setIsImporting(false);
        alert(`Berhasil mengimpor ${newResidents.length} data penduduk.`);
        if (fileInputRef.current) fileInputRef.current.value = '';
      } catch (err) {
        alert('Gagal mengimpor file.');
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  const handleArchiveMove = (destination: string, date: string) => {
    if (!movingFamily) return;
    setResidents(prev => prev.map(r => 
      r.noKK === movingFamily.noKK ? {
        ...r, 
        status: 'Pindah' as ResidentStatus, 
        moveDestination: destination, 
        moveDate: date
      } : r
    ));
    setMovingFamily(null);
  };

  return (
