        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.noKK.includes(searchTerm)
      );
  }, [residents, searchTerm]);

  const handleRegisterBirth = (family: Resident) => {
    setSelectedFamily(family);
    setIsBirthFormOpen(true);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-200">
        <div className="flex items-center space-x-6 mb-8">
          <div className="w-14 h-14 bg-emerald-500 text-white rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-500/20">
            <Baby size={32} />
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-900 uppercase tracking-tighter leading-none">Pendaftaran Kelahiran</h2>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest mt-2">Daftarkan bayi baru lahir ke dalam Kartu Keluarga aktif</p>
          </div>
        </div>

        <div className="flex items-center bg-slate-100 rounded-2xl px-5 py-3.5 border border-slate-200 max-w-xl focus-within:bg-white focus-within:ring-4 focus-within:ring-emerald-500/10 transition-all">
          <Search size={18} className="text-slate-400 mr-3" />
          <input 
            type="text" 
            placeholder="Cari Kepala Keluarga / No. KK..."
            className="bg-transparent border-none outline-none text-sm w-full font-bold"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {headOfFamilies.length > 0 ? headOfFamilies.map((h) => (
          <div key={h.id} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-200 hover:border-emerald-500 transition-all group">
            <div className="flex justify-between items-start mb-4">
              <div className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full uppercase">Aktif</div>
              <div className="text-[10px] font-mono text-slate-400">{h.noKK}</div>
            </div>
            <h3 className="text-sm font-black text-slate-900 uppercase mb-1">{h.fullName}</h3>
            <div className="flex items-center text-[10px] text-slate-400 font-bold uppercase mb-6">
              <MapPin size={12} className="mr-1" />
              {h.dusun} | RT {h.rt} RW {h.rw}
            </div>
            <button 
              onClick={() => handleRegisterBirth(h)}
              className="w-full py-3 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-emerald-600 transition-all shadow-lg"
            >
              Daftar Kelahiran
            </button>
