    e.preventDefault();
    if (formData.nik.length !== 16) return alert("NIK harus 16 digit!");

    const baby: Resident = {
      id: `birth-${Date.now()}`,
      dusun: family.dusun,
      rt: family.rt,
      rw: family.rw,
