    return residents
      .filter(r => r.status === 'Aktif' && calculateAge(r.birthDate) <= 1)
      .filter(r => !dusunFilter || r.dusun === dusunFilter)
      .filter(r => 
        r.fullName.toLowerCase().includes(searchTerm.toLowerCase()) || 
        r.nik.includes(searchTerm) ||
        r.noKK.includes(searchTerm)
