    autoTable(doc, {
      head: [['NO', 'NAMA BAYI', 'NIK', 'NOMOR KK', 'TGL LAHIR', 'JK', 'NAMA AYAH', 'NAMA IBU', 'ALAMAT']],
      body: tableData,
      startY: 40,
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: [16, 185, 129], halign: 'center' },
