  if (age <= 12) return '6-12 Anak-anak';
  if (age <= 18) return '13-18 Remaja';
  if (age <= 30) return '19-30 Dewasa';
  if (age <= 45) return '31-45 Dewasa Produktif';
  if (age <= 59) return '46-59 Pra Lansia';
