  { id: 'wilayah', label: 'Sebaran Wilayah', icon: MapPin, color: 'bg-slate-700', key: 'dusun' },
];

const AGE_ORDER = [
  '0-1 Bayi', 
  '1-5 Balita', 
  '6-12 Anak-anak', 
  '13-18 Remaja', 
  '19-30 Dewasa', 
  '31-45 Dewasa Produktif', 
  '46-59 Pra Lansia', 
  '60+ Lansia'
];

