import React, { useState, useMemo } from 'react';
import { 
  Users, 
  Baby, 
  MapPin,
  Home,
  Layers,
  X,
  Info,
  TrendingUp
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  Tooltip, 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid,
  Cell,
  LabelList
} from 'recharts';
import { Resident } from '../types';
import { calculateAge } from '../utils/helpers';

interface DashboardProps {
  residents: Resident[];
}

interface DrillDownState {
  title: string;
  type: string;
  value: string;
  breakdown: { label: string, value: number, sublabel?: string }[];
}

const AGE_BINS = [
  { min: 0, max: 1, label: '0-1', sub: 'Bayi' },
  { min: 2, max: 5, label: '1-5', sub: 'Balita' },
  { min: 6, max: 12, label: '6-12', sub: 'Anak-anak' },
  { min: 13, max: 18, label: '13-18', sub: 'Remaja' },
  { min: 19, max: 30, label: '19-30', sub: 'Dewasa' },
  { min: 31, max: 45, label: '31-45', sub: 'Dewasa Produktif' },
  { min: 46, max: 59, label: '46-59', sub: 'Pra Lansia' },
  { min: 60, max: 150, label: '60+', sub: 'Lansia' }
];

const Dashboard: React.FC<DashboardProps> = ({ residents }) => {
  const [drillDown, setDrillDown] = useState<DrillDownState | null>(null);

  // Statistik Utama
  const totalResidents = residents.length;
  const totalKK = useMemo(() => new Set(residents.map(r => r.noKK)).size, [residents]);
  const totalRT = useMemo(() => new Set(residents.map(r => `${r.dusun}-${r.rt}`)).size, [residents]);
  const totalDusun = useMemo(() => new Set(residents.map(r => r.dusun)).size, [residents]);

  // Data Piramida Penduduk
  const pyramidData = useMemo(() => {
    return AGE_BINS.map(bin => {
      const groupResidents = residents.filter(r => {
        const age = calculateAge(r.birthDate);
        return age >= bin.min && age <= bin.max;
      });

      const males = groupResidents.filter(r => r.gender.includes('Laki')).length;
      const females = groupResidents.filter(r => r.gender.includes('Perempuan')).length;

      return {
        ...bin,
        fullLabel: `${bin.label}\n${bin.sub}`,
        males: males,
        females: -females, // Negatif agar bar mengarah ke kiri
        displayFemales: females
      };
    }).reverse(); // Balik agar usia tua di atas
  }, [residents]);

  // Data Dusun
  const dusunChartData = useMemo(() => {
    const counts = residents.reduce((acc, r) => {
      acc[r.dusun] = (acc[r.dusun] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);
    return Object.entries(counts)
      .map(([name, count]) => ({ name, count }))
      .sort((a, b) => b.count - a.count);
  }, [residents]);

  const handlePyramidClick = (data: any, gender: 'Laki' | 'Perempuan') => {
    if (!data) return;
    const ageLabel = data.label;
    const bin = AGE_BINS.find(b => b.label === ageLabel);
    if (!bin) return;

    const filtered = residents.filter(r => {
      const age = calculateAge(r.birthDate);
      return age >= bin.min && age <= bin.max && r.gender.includes(gender);
    });

    const breakdown = Object.entries(
      filtered.reduce((acc, r) => {
        acc[r.dusun] = (acc[r.dusun] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    ).map(([dusun, count]) => ({ label: dusun, value: count, sublabel: 'Jiwa' }))
    .sort((a, b) => b.value - a.value);

    setDrillDown({
      title: `Sebaran ${gender === 'Laki' ? 'Laki-laki' : 'Perempuan'} (${bin.sub}) per Dusun`,
      type: 'pyramid',
      value: ageLabel,
      breakdown
    });
  };

  const StatCard = ({ icon: Icon, label, value, colorClass, delay }: any) => (
    <div 
      className={`bg-white p-4 md:p-6 rounded-2xl md:rounded-[2rem] shadow-sm border border-slate-200 flex items-center space-x-4 md:space-x-5 animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-both`}
      style={{ animationDelay: `${delay}ms` }}
    >
      <div className={`p-3 md:p-4 rounded-xl md:rounded-2xl ${colorClass} shadow-lg shadow-current/10`}>
        <Icon size={20} className="md:w-6 md:h-6" />
      </div>
      <div>
        <p className="text-[8px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5 md:mb-1">{label}</p>
        <p className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{value}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-6 md:space-y-8 pb-10">
      {/* Top Indicators */}
      <div className="grid grid-cols-2 md:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        <StatCard icon={Users} label="Penduduk" value={totalResidents} colorClass="bg-blue-600 text-white" delay={0} />
        <StatCard icon={Home} label="Kepala Kel." value={totalKK} colorClass="bg-slate-900 text-white" delay={100} />
        <StatCard icon={Layers} label="Unit RT/RW" value={totalRT} colorClass="bg-emerald-600 text-white" delay={200} />
        <StatCard icon={MapPin} label="Dusun" value={totalDusun} colorClass="bg-amber-500 text-white" delay={300} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 md:gap-8">
        {/* Population Pyramid */}
        <div className="lg:col-span-8 bg-white p-5 md:p-12 rounded-3xl md:rounded-[3rem] shadow-sm border border-slate-200 animate-in fade-in duration-1000">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8 md:mb-12">
             <div className="flex items-center space-x-4">
               <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-100 rounded-xl md:rounded-2xl flex items-center justify-center text-slate-600">
                  <TrendingUp size={20} className="md:w-6 md:h-6" />
               </div>
               <div>
                  <h3 className="text-sm md:text-base font-black text-slate-900 uppercase tracking-tighter leading-none">Piramida Penduduk</h3>
                  <p className="text-[9px] md:text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1.5">Struktur Usia & Gender</p>
               </div>
             </div>
             <div className="flex items-center space-x-4 md:space-x-6 text-[9px] md:text-[10px] font-black uppercase tracking-widest">
                <div className="flex items-center"><div className="w-2.5 h-2.5 bg-pink-500 rounded-full mr-2"></div> Wanita</div>
                <div className="flex items-center"><div className="w-2.5 h-2.5 bg-blue-600 rounded-full mr-2"></div> Pria</div>
             </div>
          </div>

          <div className="h-[400px] md:h-[550px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={pyramidData}
                layout="vertical"
                stackOffset="sign"
                margin={{ top: 5, right: 10, left: 10, bottom: 5 }}
              >
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis 
                  dataKey="label" 
                  type="category" 
                  width={60} 
                  axisLine={false} 
                  tickLine={false} 
                  tick={(props) => {
                    const { x, y, payload } = props;
                    const bin = AGE_BINS.find(b => b.label === payload.value);
                    return (
                      <g transform={`translate(${x},${y})`}>
                        <text x={0} y={-3} textAnchor="middle" fill="#94a3b8" fontSize={9} fontWeight={900}>{payload.value}</text>
                        <text x={0} y={8} textAnchor="middle" fill="#cbd5e1" fontSize={7} fontWeight={700} className="uppercase">{bin?.sub.substring(0, 5)}</text>
                      </g>
                    );
                  }}
                />
                <Tooltip 
                  cursor={{ fill: 'transparent' }}
                  content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                      const data = payload[0].payload;
                      return (
                        <div className="bg-slate-900 text-white p-4 rounded-2xl shadow-2xl border border-slate-800 text-xs">
                          <p className="font-black mb-2 uppercase tracking-widest text-slate-400">{data.sub} ({data.label})</p>
                          <div className="space-y-1">
                            <p className="flex justify-between space-x-8"><span>Laki-laki:</span> <span className="font-black text-blue-400">{data.males} Jiwa</span></p>
                            <p className="flex justify-between space-x-8"><span>Perempuan:</span> <span className="font-black text-pink-400">{data.displayFemales} Jiwa</span></p>
                          </div>
                        </div>
                      );
                    }
                    return null;
                  }}
                />

                <Bar 
                  dataKey="females" 
                  fill="#db2777" 
                  radius={[10, 0, 0, 10]} 
                  barSize={24}
                  onClick={(data) => handlePyramidClick(data, 'Perempuan')}
                  className="cursor-pointer hover:opacity-80 transition-opacity"
                >
                  <LabelList 
                    dataKey="displayFemales" 
                    position="left" 
                    style={{ fontSize: '9px', fontWeight: 'bold', fill: '#db2777' }} 
                    formatter={(val: number) => val > 0 ? val : ''}
                  />
                </Bar>

                <Bar 
                  dataKey="males" 
                  fill="#1e40af" 
                  radius={[0, 10, 10, 0]} 
                  barSize={24}
                  onClick={(data) => handlePyramidClick(data, 'Laki')}
                  className="cursor-pointer hover:opacity-80 transition-opacity"
                >
                  <LabelList 
                    dataKey="males" 
                    position="right" 
                    style={{ fontSize: '9px', fontWeight: 'bold', fill: '#1e40af' }} 
                    formatter={(val: number) => val > 0 ? val : ''}
                  />
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
          <p className="text-center text-[9px] md:text-[10px] text-slate-300 font-bold uppercase mt-6 md:mt-8 tracking-widest">Klik pada batang grafik untuk rincian (BNBA)</p>
        </div>

        {/* Dusun Breakdown */}
        <div className="lg:col-span-4 space-y-6 md:space-y-8">
           <div className="bg-white p-6 md:p-8 rounded-3xl md:rounded-[3rem] shadow-sm border border-slate-200">
              <div className="flex items-center space-x-4 mb-6 md:mb-8">
                 <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-xl flex items-center justify-center">
                    <MapPin size={20} />
                 </div>
                 <h3 className="text-xs md:text-sm font-black text-slate-800 uppercase tracking-widest">Wilayah</h3>
              </div>

              <div className="space-y-3 md:space-y-4">
                 {dusunChartData.map((d, idx) => (
                    <div key={d.name} className="group p-3 md:p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-white hover:border-emerald-500 transition-all">
                       <div className="flex justify-between items-center mb-2">
                          <span className="text-[10px] md:text-xs font-black text-slate-700 uppercase">{d.name}</span>
                          <span className="text-xs md:text-sm font-black text-slate-900">{d.count} <span className="text-[9px] md:text-[10px] text-slate-400">Jiwa</span></span>
                       </div>
                       <div className="w-full bg-slate-200 h-1.5 rounded-full overflow-hidden">
                          <div 
                            className="bg-emerald-500 h-full rounded-full transition-all duration-1000" 
                            style={{ width: `${(d.count / (totalResidents || 1)) * 100}%` }}
                          ></div>
                       </div>
                    </div>
                 ))}
              </div>
           </div>

           <div className="bg-slate-900 p-6 md:p-8 rounded-3xl md:rounded-[3rem] text-white overflow-hidden relative group">
              <div className="relative z-10">
                <h4 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em] text-slate-400 mb-2">Rasio Demografi</h4>
                <div className="text-2xl md:text-3xl font-black tracking-tighter">
                   {totalResidents > 0 ? ((residents.filter(r => r.gender.includes('Laki')).length / totalResidents) * 100).toFixed(1) : 0}% 
                   <span className="text-slate-500 text-xs md:text-sm ml-2">Laki-laki</span>
                </div>
              </div>
              <Users className="absolute -right-4 -bottom-4 text-slate-800/50 group-hover:scale-110 transition-transform duration-700" size={100} />
           </div>
        </div>
      </div>

      {/* Drill Down Modal - Optimized for mobile */}
      {drillDown && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-3 md:p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white rounded-3xl md:rounded-[2.5rem] shadow-2xl w-full max-w-lg overflow-hidden border border-slate-200 animate-in zoom-in-95 duration-300">
              <div className="p-5 md:p-6 bg-slate-900 text-white flex justify-between items-center">
                 <div className="flex items-center space-x-3">
                    <div className="w-9 h-9 md:w-10 md:h-10 bg-blue-600 rounded-xl flex items-center justify-center">
                       <Layers size={18} />
                    </div>
                    <h4 className="font-black text-[10px] md:text-xs uppercase tracking-widest">{drillDown.title}</h4>
                 </div>
                 <button onClick={() => setDrillDown(null)} className="p-2 hover:bg-slate-800 rounded-xl transition-all">
                    <X size={20} />
                 </button>
              </div>
              <div className="p-5 md:p-8 space-y-3 md:space-y-4 max-h-[60vh] overflow-y-auto">
                 {drillDown.breakdown.length > 0 ? drillDown.breakdown.map((item, idx) => (
                    <div key={idx} className="flex items-center justify-between p-4 md:p-5 bg-slate-50 border border-slate-100 rounded-xl md:rounded-2xl hover:bg-blue-50 transition-all group">
                       <div className="flex items-center space-x-3 md:space-x-4">
                          <div className="w-7 h-7 md:w-8 md:h-8 bg-white border border-slate-200 rounded-lg flex items-center justify-center text-[9px] md:text-[10px] font-black text-slate-400 group-hover:text-blue-600 transition-colors">
                             {idx + 1}
                          </div>
                          <span className="text-xs font-black text-slate-700 uppercase tracking-tighter">{item.label}</span>
                       </div>
                       <div className="flex items-center space-x-2">
                          <span className="text-base md:text-lg font-black text-slate-900">{item.value}</span>
                          <span className="text-[9px] md:text-[10px] font-bold text-slate-400 uppercase">{item.sublabel || ''}</span>
                       </div>
                    </div>
                 )) : (
                   <div className="py-12 text-center text-slate-400 font-bold uppercase text-[10px] tracking-widest">
                      Tidak ada data penduduk.
                   </div>
                 )}
              </div>
              <div className="p-5 md:p-6 bg-slate-50 border-t border-slate-100 text-center">
                 <button 
                   onClick={() => setDrillDown(null)}
                   className="w-full md:w-auto px-10 py-3 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-lg"
                 >
                   Tutup Detail
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

