import React, { useState, useMemo } from 'react';
import { 
  Users, 
  Baby, 
  MapPin,
  Home,
  Layers,
  X,
  Info,
  TrendingUp
} from 'lucide-react';
import { 
  ResponsiveContainer, 
  Tooltip, 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid,
  Cell,
  LabelList
} from 'recharts';
import { Resident } from '../types';
import { calculateAge } from '../utils/helpers';

interface DashboardProps {
  residents: Resident[];
}

interface DrillDownState {
  title: string;
  type: string;
  value: string;
  breakdown: { label: string, value: number, sublabel?: string }[];
}

const AGE_BINS = [
  { min: 0, max: 1, label: '0-1', sub: 'Bayi' },
  { min: 2, max: 5, label: '1-5', sub: 'Balita' },
  { min: 6, max: 12, label: '6-12', sub: 'Anak-anak' },
  { min: 13, max: 18, label: '13-18', sub: 'Remaja' },
  { min: 19, max: 30, label: '19-30', sub: 'Dewasa' },
  { min: 31, max: 45, label: '31-45', sub: 'Dewasa Produktif' },
  { min: 46, max: 59, label: '46-59', sub: 'Pra Lansia' },
  { min: 60, max: 150, label: '60+', sub: 'Lansia' }
];

const Dashboard: React.FC<DashboardProps> = ({ residents }) => {
  const [drillDown, setDrillDown] = useState<DrillDownState | null>(null);

  // Statistik Utama
  const totalResidents = residents.length;
  const totalKK = useMemo(() => new Set(residents.map(r => r.noKK)).size, [residents]);
  const totalRT = useMemo(() => new Set(residents.map(r => `${r.dusun}-${r.rt}`)).size, [residents]);
  const totalDusun = useMemo(() => new Set(residents.map(r => r.dusun)).size, [residents]);

  // Data Piramida Penduduk
  const pyramidData = useMemo(() => {
    return AGE_BINS.map(bin => {
      const groupResidents = residents.filter(r => {
        const age = calculateAge(r.birthDate);
        return age >= bin.min && age <= bin.max;
      });

      const males = groupResidents.filter(r => r.gender.includes('Laki')).length;
      const females = groupResidents.filter(r => r.gender.includes('Perempuan')).length;

      return {
        ...bin,
        fullLabel: `${bin.label}\n${bin.sub}`,
        males: males,
        females: -females, // Negatif agar bar mengarah ke kiri
        displayFemales: females
      };
    }).reverse(); // Balik agar usia tua di atas
  }, [residents]);

  // Data Dusun
  const dusunChartData = useMemo(() => {
    const counts = residents.reduce((acc, r) => {
      acc[r.dusun] = (acc[r.dusun] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);
    return Object.entries(counts)
      .map(([name, count]) => ({ name, count }))
      .sort((a, b) => b.count - a.count);
  }, [residents]);

  const handlePyramidClick = (data: any, gender: 'Laki' | 'Perempuan') => {
    if (!data) return;
    const ageLabel = data.label;
    const bin = AGE_BINS.find(b => b.label === ageLabel);
    if (!bin) return;

    const filtered = residents.filter(r => {
      const age = calculateAge(r.birthDate);
      return age >= bin.min && age <= bin.max && r.gender.includes(gender);
    });

    const breakdown = Object.entries(
      filtered.reduce((acc, r) => {
        acc[r.dusun] = (acc[r.dusun] || 0) + 1;
        return acc;
      }, {} as Record<string, number>)
    ).map(([dusun, count]) => ({ label: dusun, value: count, sublabel: 'Jiwa' }))
    .sort((a, b) => b.value - a.value);

    setDrillDown({
      title: `Sebaran ${gender === 'Laki' ? 'Laki-laki' : 'Perempuan'} (${bin.sub}) per Dusun`,
      type: 'pyramid',
      value: ageLabel,
      breakdown
    });
  };

  const StatCard = ({ icon: Icon, label, value, colorClass, delay }: any) => (
    <div 
      className={`bg-white p-3 md:p-6 rounded-xl md:rounded-[2rem] shadow-sm border border-slate-200 flex items-center space-x-3 md:space-x-5 animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-both`}
      style={{ animationDelay: `${delay}ms` }}
    >
      <div className={`p-2.5 md:p-4 rounded-lg md:rounded-2xl ${colorClass} shadow-lg shadow-current/10 shrink-0`}>
        <Icon size={18} className="md:w-6 md:h-6" />
      </div>
      <div className="min-w-0">
        <p className="text-[7px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5 truncate">{label}</p>
        <p className="text-lg md:text-2xl font-black text-slate-900 tracking-tight leading-none">{value}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-4 md:space-y-8 pb-10">
      {/* Top Indicators - Use Grid 2 cols on smallest screens */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6">
        <StatCard icon={Users} label="Penduduk" value={totalResidents} colorClass="bg-blue-600 text-white" delay={0} />
        <StatCard icon={Home} label="Kepala Kel." value={totalKK} colorClass="bg-slate-900 text-white" delay={100} />
        <StatCard icon={Layers} label="Unit RT/RW" value={totalRT} colorClass="bg-emerald-600 text-white" delay={200} />
        <StatCard icon={MapPin} label="Dusun" value={totalDusun} colorClass="bg-amber-500 text-white" delay={300} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 md:gap-8">
        {/* Population Pyramid */}
        <div className="lg:col-span-8 bg-white p-4 md:p-12 rounded-2xl md:rounded-[3rem] shadow-sm border border-slate-200 animate-in fade-in duration-1000">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-3 mb-6 md:mb-12">
             <div className="flex items-center space-x-3">
               <div className="w-8 h-8 md:w-12 md:h-12 bg-slate-100 rounded-lg md:rounded-2xl flex items-center justify-center text-slate-600">
                  <TrendingUp size={16} className="md:w-6 md:h-6" />
               </div>
               <div>
                  <h3 className="text-xs md:text-base font-black text-slate-900 uppercase tracking-tighter leading-none">Piramida Penduduk</h3>
                  <p className="text-[8px] md:text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Struktur Usia & Gender</p>
               </div>
             </div>
             <div className="flex items-center space-x-3 md:space-x-6 text-[8px] md:text-[10px] font-black uppercase tracking-widest">
                <div className="flex items-center"><div className="w-2 h-2 bg-pink-500 rounded-full mr-1.5"></div> Wanita</div>
                <div className="flex items-center"><div className="w-2 h-2 bg-blue-600 rounded-full mr-1.5"></div> Pria</div>
             </div>
          </div>

          <div className="h-[350px] md:h-[550px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart
                data={pyramidData}
                layout="vertical"
                stackOffset="sign"
                margin={{ top: 5, right: 10, left: 10, bottom: 5 }}
              >
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis 
                  dataKey="label" 
                  type="category" 
                  width={50} 
                  axisLine={false} 
                  tickLine={false} 
                  tick={(props) => {
                    const { x, y, payload } = props;
                    const bin = AGE_BINS.find(b => b.label === payload.value);
                    return (
                      <g transform={`translate(${x},${y})`}>
                        <text x={0} y={-3} textAnchor="middle" fill="#94a3b8" fontSize={8} fontWeight={900}>{payload.value}</text>
                        <text x={0} y={7} textAnchor="middle" fill="#cbd5e1" fontSize={6} fontWeight={700} className="uppercase">{bin?.sub.substring(0, 5)}</text>
                      </g>
                    );
                  }}
                />
                <Tooltip 
                  cursor={{ fill: 'transparent' }}
                  content={({ active, payload }) => {
                    if (active && payload && payload.length) {
                      const data = payload[0].payload;
                      return (
                        <div className="bg-slate-900 text-white p-3 rounded-xl shadow-2xl border border-slate-800 text-[10px]">
                          <p className="font-black mb-1 uppercase tracking-widest text-slate-400">{data.sub} ({data.label})</p>
