                            <p className="flex justify-between space-x-6"><span>Pria:</span> <span className="font-black text-blue-400">{data.males} Jiwa</span></p>
                            <p className="flex justify-between space-x-6"><span>Wanita:</span> <span className="font-black text-pink-400">{data.displayFemales} Jiwa</span></p>
