} from 'recharts';
import { 
  GraduationCap, 
  Briefcase, 
  Calendar, 
  Heart, 
  MapPin, 
  UserCircle,
  ArrowLeft,
  ChevronRight,
  Printer,
  X,
  Users
} from 'lucide-react';
import { Resident } from '../types';
import { calculateAge, getAgeGroup } from '../utils/helpers';

const INDICATORS_CONFIG = [
  { id: 'pendidikan', label: 'Pendidikan', icon: GraduationCap, color: 'bg-blue-500', key: 'education' },
  { id: 'pekerjaan', label: 'Pekerjaan', icon: Briefcase, color: 'bg-emerald-500', key: 'job' },
  { id: 'usia', label: 'Usia', icon: Calendar, color: 'bg-amber-500', key: 'ageGroup' },
  { id: 'gender', label: 'Gender', icon: UserCircle, color: 'bg-indigo-500', key: 'gender' },
  { id: 'perkawinan', label: 'Kawin', icon: Heart, color: 'bg-pink-500', key: 'maritalStatus' },
  { id: 'wilayah', label: 'Wilayah', icon: MapPin, color: 'bg-slate-700', key: 'dusun' },
];

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#64748b', '#1e293b'];

const RecapIndicators: React.FC<RecapIndicatorsProps> = ({ residents = [] }) => {
  const [selectedIndicator, setSelectedIndicator] = useState<string | null>(null);
  const [selectedBNBA, setSelectedBNBA] = useState<{ label: string, value: string } | null>(null);

  const filteredResidents = residents;

  const getRecapData = (key: string) => {
    const counts = filteredResidents.reduce((acc, r) => {
      let val: string = 'N/A';
      if (key === 'ageGroup') val = getAgeGroup(calculateAge(r.birthDate));
      else val = String(r[key as keyof Resident] || 'N/A');
      acc[val] = (acc[val] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);
    return Object.entries(counts).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value);
  };

  const currentIndicatorData = useMemo(() => {
    if (!selectedIndicator) return [];
    const item = INDICATORS_CONFIG.find(i => i.id === selectedIndicator);
    return item ? getRecapData(item.key) : [];
  }, [selectedIndicator, residents]);

  if (!selectedIndicator) {
    return (
      <div className="grid grid-cols-2 md:grid-cols-3 gap-3 md:gap-6 animate-in fade-in">
        {INDICATORS_CONFIG.map((item) => (
          <button
            key={item.id}
            onClick={() => setSelectedIndicator(item.id)}
            className="bg-white p-4 md:p-8 rounded-xl md:rounded-3xl border border-slate-200 flex flex-col items-center text-center space-y-3"
          >
            <div className={`${item.color} text-white p-3 md:p-6 rounded-lg md:rounded-2xl shrink-0`}>
              <item.icon size={20} className="md:w-8 md:h-8" />
            </div>
            <h3 className="text-[9px] md:text-sm font-black text-slate-800 uppercase tracking-tighter">{item.label}</h3>
          </button>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-4 animate-in slide-in-from-right-4">
      <div className="bg-white p-4 rounded-2xl border border-slate-200 flex items-center justify-between">
        <button onClick={() => setSelectedIndicator(null)} className="p-2 bg-slate-100 rounded-lg"><ArrowLeft size={18} /></button>
        <h2 className="text-[10px] md:text-lg font-black uppercase tracking-widest">{selectedIndicator}</h2>
        <div className="w-10"></div>
      </div>

      <div className="bg-white p-5 rounded-3xl border border-slate-200">
         <div className="h-[300px] md:h-[450px]">
            <ResponsiveContainer width="100%" height="100%">
               <BarChart data={currentIndicatorData} layout="vertical" margin={{ left: -10 }}>
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={90} tick={{ fontSize: 8, fontWeight: 900 }} axisLine={false} tickLine={false} />
                  <Tooltip cursor={{ fill: '#f8fafc' }} />
                  <Bar dataKey="value" radius={[0, 8, 8, 0]} barSize={20}>
