  Cell
} from 'recharts';
import { Resident } from '../types';
import { calculateAge } from '../utils/helpers';

interface DashboardProps {
  residents: Resident[];
}

interface DrillDownState {
  title: string;
  data: { label: string; value: number }[];
}

const AGE_BINS = [
  { min: 0, max: 1, label: '0-1 Bayi', sub: 'Bayi' },
  { min: 2, max: 5, label: '1-5 Balita', sub: 'Balita' },
  { min: 6, max: 12, label: '6-12 Anak', sub: 'Anak' },
  { min: 13, max: 18, label: '13-18 Remaja', sub: 'Remaja' },
  { min: 19, max: 30, label: '19-30 Dewasa', sub: 'Dewasa' },
  { min: 31, max: 45, label: '31-45 Prod', sub: 'Produktif' },
  { min: 46, max: 59, label: '46-59 Pra', sub: 'Pra Lansia' },
  { min: 60, max: 150, label: '60+ Lansia', sub: 'Lansia' }
];

const Dashboard: React.FC<DashboardProps> = ({ residents }) => {
  const [drillDown, setDrillDown] = useState<DrillDownState | null>(null);

  const totalResidents = residents.length;
  const totalKK = useMemo(() => new Set(residents.map(r => r.noKK)).size, [residents]);
  const totalRT = useMemo(() => new Set(residents.map(r => `${r.dusun}-${r.rt}`)).size, [residents]);
  const totalDusun = useMemo(() => new Set(residents.map(r => r.dusun)).size, [residents]);

  const pyramidData = useMemo(() => {
    return AGE_BINS.map(bin => {
      const groupResidents = residents.filter(r => {
        const age = calculateAge(r.birthDate);
        return age >= bin.min && age <= bin.max;
      });
      const males = groupResidents.filter(r => r.gender.includes('Laki')).length;
      const females = groupResidents.filter(r => r.gender.includes('Perempuan')).length;
      return { ...bin, males, females: -females, displayFemales: females };
    }).reverse();
  }, [residents]);

  const handlePyramidClick = (data: any, gender: 'Laki' | 'Perempuan') => {
    if (!data) return;
    const ageLabel = data.label;
    const bin = AGE_BINS.find(b => b.label === ageLabel);
    if (!bin) return;

    const filtered = residents.filter(r => {
      const age = calculateAge(r.birthDate);
      return age >= bin.min && age <= bin.max && r.gender.includes(gender);
    });

    const counts = filtered.reduce((acc, r) => {
      acc[r.dusun] = (acc[r.dusun] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    // Fixed: Explicitly cast value as number to resolve arithmetic operation errors on line 83/92 (binary subtraction in sort)
    setDrillDown({
      title: `${gender === 'Laki' ? 'Pria' : 'Wanita'} Kelompok ${ageLabel} per Dusun`,
      data: Object.entries(counts).map(([label, value]) => ({ label, value: value as number })).sort((a, b) => b.value - a.value)
    });
  };

  const dusunChartData = useMemo(() => {
    const counts = residents.reduce((acc, r) => {
      acc[r.dusun] = (acc[r.dusun] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);
    // Fixed: Explicitly cast count as number to resolve potential arithmetic errors when using d.count in JSX
    return Object.entries(counts).map(([name, count]) => ({ name, count: count as number })).sort((a, b) => b.count - a.count);
  }, [residents]);

  const StatCard = ({ icon: Icon, label, value, colorClass }: any) => (
    <div className={`bg-white p-3 md:p-6 rounded-xl md:rounded-3xl border border-slate-200 flex items-center space-x-3 md:space-x-5 shadow-sm transition-transform hover:scale-[1.02]`}>
      <div className={`p-2 md:p-4 rounded-lg md:rounded-2xl ${colorClass} shrink-0`}>
        <Icon size={16} className="md:w-6 md:h-6" />
      </div>
      <div className="min-w-0">
        <p className="text-[7px] md:text-[9px] font-black text-slate-400 uppercase tracking-widest mb-0.5 truncate">{label}</p>
        <p className="text-base md:text-2xl font-black text-slate-900 tracking-tight leading-none">{value}</p>
      </div>
    </div>
  );

  return (
    <div className="space-y-4 md:space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6">
        <StatCard icon={Users} label="Penduduk" value={totalResidents} colorClass="bg-blue-600 text-white" />
        <StatCard icon={Home} label="Kepala KK" value={totalKK} colorClass="bg-slate-900 text-white" />
        <StatCard icon={Layers} label="Unit RT" value={totalRT} colorClass="bg-emerald-600 text-white" />
        <StatCard icon={MapPin} label="Dusun" value={totalDusun} colorClass="bg-amber-500 text-white" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-4 md:gap-8">
        <div className="lg:col-span-8 bg-white p-4 md:p-10 rounded-2xl md:rounded-[3rem] border border-slate-200 shadow-sm relative">
          <div className="flex items-center justify-between mb-6">
             <div className="flex items-center space-x-3">
               <TrendingUp size={16} className="text-blue-600" />
               <h3 className="text-[10px] md:text-base font-black text-slate-900 uppercase">Piramida Penduduk</h3>
             </div>
             <div className="flex items-center space-x-2 text-[7px] md:text-[9px] font-bold uppercase">
                <div className="flex items-center"><div className="w-2 h-2 bg-pink-500 rounded-full mr-1"></div> Wanita</div>
                <div className="flex items-center"><div className="w-2 h-2 bg-blue-600 rounded-full mr-1"></div> Pria</div>
             </div>
          </div>
          <div className="h-[350px] md:h-[550px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={pyramidData} layout="vertical" stackOffset="sign" margin={{ left: 10, right: 30 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis 
                  dataKey="label" 
                  type="category" 
                  width={110} 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{ fontSize: 9, fontWeight: 900, fill: '#64748b' }} 
                />
                <Tooltip cursor={{ fill: 'transparent' }} content={({ active, payload }) => {
                  if (active && payload?.length) {
                    const data = payload[0].payload;
                    return (
                      <div className="bg-slate-900 text-white p-3 rounded-xl text-[9px] uppercase font-black shadow-2xl border border-slate-800">
                        <p className="text-slate-400 mb-1 border-b border-slate-800 pb-1">{data.label}</p>
                        <p className="text-blue-400">Pria: {data.males} Jiwa</p>
                        <p className="text-pink-400">Wanita: {data.displayFemales} Jiwa</p>
                        <p className="mt-2 text-[7px] text-slate-500 italic">Klik bar untuk rincian dusun</p>
                      </div>
                    );
                  }
                  return null;
                }} />
                <Bar 
                  dataKey="females" 
                  fill="#db2777" 
                  radius={[5, 0, 0, 5]} 
                  barSize={20} 
                  className="cursor-pointer hover:opacity-80 transition-opacity"
                  onClick={(data) => handlePyramidClick(data, 'Perempuan')}
                />
                <Bar 
                  dataKey="males" 
                  fill="#1e40af" 
                  radius={[0, 5, 5, 0]} 
                  barSize={20} 
                  className="cursor-pointer hover:opacity-80 transition-opacity"
                  onClick={(data) => handlePyramidClick(data, 'Laki')}
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="lg:col-span-4 bg-white p-4 md:p-10 rounded-2xl md:rounded-[3rem] border border-slate-200 shadow-sm">
           <h3 className="text-[10px] md:text-sm font-black text-slate-800 uppercase mb-6 tracking-widest flex items-center">
              <MapPin size={14} className="mr-2 text-emerald-500" /> Sebaran Wilayah
           </h3>
           <div className="space-y-3">
              {dusunChartData.map((d) => (
                 <div key={d.name} className="p-3 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-white hover:shadow-sm transition-all group">
                    <div className="flex justify-between items-center mb-1.5">
                       <span className="text-[8px] md:text-xs font-black text-slate-700 uppercase">{d.name}</span>
                       <span className="text-[10px] md:text-sm font-black text-slate-900">{d.count} <span className="text-[8px] text-slate-400 font-normal">Jiwa</span></span>
                    </div>
                    <div className="w-full bg-slate-200 h-1 rounded-full overflow-hidden">
                       <div className="bg-emerald-500 h-full rounded-full transition-all duration-1000" style={{ width: `${(d.count / (totalResidents || 1)) * 100}%` }}></div>
                    </div>
                 </div>
              ))}
           </div>
        </div>
      </div>

      {/* Drill Down Modal */}
      {drillDown && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md overflow-hidden border border-slate-200 animate-in zoom-in-95">
             <div className="p-6 bg-slate-900 text-white flex justify-between items-center">
                <div className="flex items-center space-x-3">
                   <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center shadow-lg">
                      <Layers size={18} />
                   </div>
                   <h4 className="text-[10px] md:text-xs font-black uppercase tracking-widest">{drillDown.title}</h4>
                </div>
                <button onClick={() => setDrillDown(null)} className="p-2 hover:bg-slate-800 rounded-xl transition-all">
                   <X size={20} />
                </button>
             </div>
             <div className="p-6 md:p-8 space-y-3 max-h-[60vh] overflow-y-auto">
                {drillDown.data.map((item, idx) => (
                   <div key={idx} className="flex items-center justify-between p-4 bg-slate-50 border border-slate-100 rounded-2xl hover:bg-blue-50 transition-all group">
                      <span className="text-[10px] font-black text-slate-700 uppercase tracking-tighter">{item.label}</span>
                      <div className="flex items-center space-x-2">
                         <span className="text-base font-black text-slate-900">{item.value}</span>
                         <span className="text-[8px] font-black text-slate-400 uppercase">Jiwa</span>
                      </div>
                   </div>
                ))}
             </div>
             <div className="p-6 bg-slate-50 border-t border-slate-100 text-center">
                <button onClick={() => setDrillDown(null)} className="w-full py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-widest hover:opacity-90 shadow-xl">Tutup</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { 
  BarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell
} from 'recharts';
import { 
  GraduationCap, 
  Briefcase, 
  Calendar, 
  Heart, 
  MapPin, 
  UserCircle,
  ArrowLeft,
  X,
  Users,
  Search,
  Eye,
  Download,
  Filter,
  Printer,
  FileText
} from 'lucide-react';
import { jsPDF } from 'jspdf';
import autoTable from 'jspdf-autotable';
import { Resident, AppConfig } from '../types';
import { calculateAge, getAgeGroup, formatDate } from '../utils/helpers';

interface RecapIndicatorsProps {
  residents: Resident[];
  config: AppConfig;
}

const INDICATORS_CONFIG = [
  { id: 'pendidikan', label: 'Pendidikan', icon: GraduationCap, color: 'bg-blue-500', key: 'education' },
  { id: 'pekerjaan', label: 'Pekerjaan', icon: Briefcase, color: 'bg-emerald-500', key: 'job' },
  { id: 'usia', label: 'Usia', icon: Calendar, color: 'bg-amber-500', key: 'ageGroup' },
  { id: 'gender', label: 'Gender', icon: UserCircle, color: 'bg-indigo-500', key: 'gender' },
  { id: 'perkawinan', label: 'Kawin', icon: Heart, color: 'bg-pink-500', key: 'maritalStatus' },
  { id: 'wilayah', label: 'Wilayah', icon: MapPin, color: 'bg-slate-700', key: 'dusun' },
];

const COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#64748b', '#1e293b'];

const RecapIndicators: React.FC<RecapIndicatorsProps> = ({ residents = [], config }) => {
  const [selectedIndicator, setSelectedIndicator] = useState<string | null>(null);
  const [dusunFilter, setDusunFilter] = useState<string>('');
  const [selectedBNBA, setSelectedBNBA] = useState<{ label: string, categoryKey: string, categoryValue: string } | null>(null);
  const [bnbaSearch, setBnbaSearch] = useState('');

  const dusunList = useMemo(() => 
    Array.from(new Set(residents.map(r => r.dusun))).sort()
  , [residents]);

  const filteredForChart = useMemo(() => {
    if (!dusunFilter) return residents;
    return residents.filter(r => r.dusun === dusunFilter);
  }, [residents, dusunFilter]);

  const getRecapData = (key: string) => {
    const counts = filteredForChart.reduce((acc, r) => {
      let val: string = 'N/A';
      if (key === 'ageGroup') val = getAgeGroup(calculateAge(r.birthDate));
      else val = String(r[key as keyof Resident] || 'N/A');
      acc[val] = (acc[val] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    // Fixed: Explicitly cast value as number to resolve 'unknown' assignment error on line 76
    return Object.entries(counts)
      .map(([name, value]): { name: string; value: number } => ({ name, value: value as number }))
      .sort((a, b) => b.value - a.value);
  };

  const currentIndicatorData = useMemo(() => {
    if (!selectedIndicator) return [];
    const item = INDICATORS_CONFIG.find(i => i.id === selectedIndicator);
    return item ? getRecapData(item.key) : [];
  }, [selectedIndicator, filteredForChart]);

  const handleBarClick = (data: any) => {
    if (!data || !selectedIndicator) return;
    const item = INDICATORS_CONFIG.find(i => i.id === selectedIndicator);
    if (!item) return;

    setSelectedBNBA({
      label: data.name,
      categoryKey: item.key,
      categoryValue: data.name
    });
    setBnbaSearch('');
  };

  const bnbaList = useMemo(() => {
    if (!selectedBNBA) return [];
    let baseList = filteredForChart.filter(r => {
      if (selectedBNBA.categoryKey === 'ageGroup') {
        return getAgeGroup(calculateAge(r.birthDate)) === selectedBNBA.categoryValue;
      }
      return String(r[selectedBNBA.categoryKey as keyof Resident]) === selectedBNBA.categoryValue;
    });

    if (bnbaSearch) {
      const s = bnbaSearch.toLowerCase();
      baseList = baseList.filter(r => 
        r.fullName.toLowerCase().includes(s) || r.nik.includes(s)
      );
    }

    return baseList.sort((a, b) => a.fullName.localeCompare(b.fullName));
  }, [selectedBNBA, filteredForChart, bnbaSearch]);

  const handleDownloadBNBAPDF = () => {
    if (!selectedBNBA || bnbaList.length === 0) return;

    const doc = new jsPDF({ orientation: 'portrait', unit: 'mm', format: 'a4' });

    doc.setFontSize(14);
    doc.setFont('helvetica', 'bold');
    doc.text('PEMERINTAH KABUPATEN BLORA', 105, 15, { align: 'center' });
    doc.setFontSize(12);
    doc.text('KECAMATAN TODANAN - DESA NGUMBUL', 105, 21, { align: 'center' });
    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    doc.text('Alamat: Jl. Raya Todanan-Ngumbul KM. 05, Desa Ngumbul, Kec. Todanan, Kab. Blora (58256)', 105, 26, { align: 'center' });
    doc.setLineWidth(0.5);
    doc.line(20, 28, 190, 28);

    doc.setFontSize(11);
    doc.setFont('helvetica', 'bold');
    const indicatorLabel = INDICATORS_CONFIG.find(i => i.id === selectedIndicator)?.label || '';
    doc.text(`DAFTAR PENDUDUK (BNBA) - ${indicatorLabel.toUpperCase()}`, 105, 38, { align: 'center' });
    doc.setFontSize(10);
    doc.text(`KATEGORI: ${selectedBNBA.label.toUpperCase()}`, 105, 43, { align: 'center' });

    doc.setFontSize(8);
    doc.setFont('helvetica', 'normal');
    doc.text(`Wilayah: ${dusunFilter || 'Seluruh Desa'}`, 20, 50);
    doc.text(`Jumlah: ${bnbaList.length} Jiwa`, 190, 50, { align: 'right' });

    const tableData = bnbaList.map((r, idx) => [
      idx + 1,
      r.fullName.toUpperCase(),
      r.nik,
      `${r.dusun}`,
      `RT ${r.rt} / RW ${r.rw}`,
      calculateAge(r.birthDate)
    ]);

    autoTable(doc, {
      head: [['NO', 'NAMA LENGKAP', 'NIK', 'DUSUN', 'RT/RW', 'USIA']],
      body: tableData,
      startY: 55,
      styles: { fontSize: 8, cellPadding: 2 },
      headStyles: { fillColor: [15, 23, 42], textColor: [255, 255, 255], fontStyle: 'bold' },
      columnStyles: {
        0: { halign: 'center', cellWidth: 10 },
        2: { fontStyle: 'normal' },
        5: { halign: 'center', cellWidth: 15 }
      }
    });

    const finalY = (doc as any).lastAutoTable.finalY + 15;
    doc.setFontSize(9);
    doc.text(`Ngumbul, ${new Date().toLocaleDateString('id-ID', { day: 'numeric', month: 'long', year: 'numeric' })}`, 150, finalY, { align: 'center' });
    doc.setFont('helvetica', 'bold');
    doc.text('KEPALA DESA NGUMBUL', 150, finalY + 5, { align: 'center' });
    doc.text(config.villageHeadName.toUpperCase(), 150, finalY + 25, { align: 'center' });

    doc.save(`BNBA_${selectedBNBA.label.replace(/[\s/]/g, '_')}_Ngumbul.pdf`);
  };

  if (!selectedIndicator) {
    return (
      <div className="grid grid-cols-2 md:grid-cols-3 gap-3 md:gap-6 animate-in fade-in duration-500">
        {INDICATORS_CONFIG.map((item) => (
          <button
            key={item.id}
            onClick={() => setSelectedIndicator(item.id)}
            className="bg-white p-5 md:p-10 rounded-2xl md:rounded-[3rem] border border-slate-200 shadow-sm flex flex-col items-center text-center space-y-4 transition-all hover:shadow-xl hover:scale-[1.03] group"
          >
            <div className={`${item.color} text-white p-4 md:p-8 rounded-2xl md:rounded-[2rem] shrink-0 shadow-lg shadow-current/10 group-hover:scale-110 transition-transform`}>
              <item.icon size={24} className="md:w-10 md:h-10" />
            </div>
            <h3 className="text-[10px] md:text-base font-black text-slate-800 uppercase tracking-widest">{item.label}</h3>
          </button>
        ))}
      </div>
    );
  }

  return (
    <div className="space-y-4 md:space-y-6 animate-in slide-in-from-right-4 duration-500">
      <div className="bg-white p-4 md:p-6 rounded-[2rem] border border-slate-200 shadow-sm flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="flex items-center space-x-3">
          <button onClick={() => { setSelectedIndicator(null); setDusunFilter(''); }} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-xl transition-all">
            <ArrowLeft size={18} />
          </button>
          <h2 className="text-[11px] md:text-xl font-black uppercase tracking-widest text-slate-900">{INDICATORS_CONFIG.find(i => i.id === selectedIndicator)?.label}</h2>
        </div>

        <div className="flex items-center space-x-2 bg-slate-100 p-1.5 rounded-2xl border border-slate-200">
           <div className="pl-3 pr-1 text-slate-400"><Filter size={14} /></div>
           <select 
             className="bg-transparent text-[10px] md:text-xs font-black uppercase outline-none px-2 py-1 cursor-pointer"
             value={dusunFilter}
             onChange={(e) => setDusunFilter(e.target.value)}
           >
             <option value="">Seluruh Desa</option>
             {dusunList.map(d => <option key={d} value={d}>{d}</option>)}
           </select>
        </div>
      </div>

      <div className="bg-white p-6 md:p-12 rounded-[2.5rem] md:rounded-[4rem] border border-slate-200 shadow-sm relative overflow-hidden">
         <div className="flex items-center justify-between mb-8 md:mb-12">
            <div>
              <h3 className="text-[9px] md:text-sm font-black text-slate-400 uppercase tracking-widest">Visualisasi Data</h3>
              <p className="text-[8px] md:text-[10px] font-bold text-slate-400 mt-1 uppercase tracking-tighter">Wilayah: {dusunFilter || 'Seluruh Desa'}</p>
            </div>
            <span className="text-[8px] md:text-[10px] font-bold text-blue-600 uppercase bg-blue-50 px-3 py-1 rounded-full border border-blue-100">Klik bar untuk rincian BNBA</span>
         </div>
         <div className="h-[400px] md:h-[600px]">
            <ResponsiveContainer width="100%" height="100%">
               <BarChart data={currentIndicatorData} layout="vertical" margin={{ left: -10, right: 30 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                  <XAxis type="number" hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{ fontSize: 9, fontWeight: 900, fill: '#64748b' }} axisLine={false} tickLine={false} />
                  <Tooltip 
                    cursor={{ fill: '#f8fafc' }} 
                    content={({ active, payload }) => {
                      if (active && payload?.length) {
                        return (
                          <div className="bg-slate-900 text-white p-3 rounded-xl shadow-2xl text-[10px] font-black uppercase">
                            {payload[0].payload.name}: <span className="text-emerald-400">{payload[0].value} Jiwa</span>
                          </div>
                        );
                      }
                      return null;
                    }}
                  />
                  <Bar 
                    dataKey="value" 
                    radius={[0, 10, 10, 0]} 
                    barSize={24} 
                    className="cursor-pointer hover:opacity-80 transition-opacity"
                    onClick={(data) => handleBarClick(data)}
                  >
                    {currentIndicatorData.map((e, i) => <Cell key={i} fill={COLORS[i % COLORS.length]} />)}
                  </Bar>
               </BarChart>
            </ResponsiveContainer>
         </div>
      </div>

      {selectedBNBA && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-3 md:p-6 bg-slate-900/60 backdrop-blur-md animate-in fade-in">
           <div className="bg-white rounded-[2rem] md:rounded-[3rem] shadow-2xl w-full max-w-4xl h-[90vh] flex flex-col border border-slate-200 animate-in zoom-in-95">
              <div className="p-6 md:p-8 bg-slate-900 text-white flex justify-between items-center shrink-0">
                 <div className="flex items-center space-x-4">
                    <div className="w-12 h-12 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg">
                       <Users size={24} />
                    </div>
                    <div>
                       <h4 className="text-[11px] md:text-base font-black uppercase tracking-widest leading-none">BNBA: {selectedBNBA.label}</h4>
                       <p className="text-[8px] md:text-[10px] text-slate-400 font-bold uppercase mt-2 tracking-widest">{bnbaList.length} Jiwa Ditemukan ({dusunFilter || 'Seluruh Desa'})</p>
                    </div>
                 </div>
                 <div className="flex items-center space-x-2">
                    <button 
                      onClick={handleDownloadBNBAPDF}
                      className="p-3 bg-emerald-600 hover:bg-emerald-700 text-white rounded-2xl transition-all flex items-center space-x-2 shadow-lg shadow-emerald-900/20"
                      title="Unduh PDF"
                    >
                      <Printer size={18} />
                      <span className="hidden sm:inline text-[9px] font-black uppercase tracking-widest">Cetak PDF</span>
                    </button>
                    <button onClick={() => setSelectedBNBA(null)} className="p-3 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                       <X size={20} />
                    </button>
                 </div>
              </div>

              <div className="flex-1 overflow-hidden flex flex-col bg-slate-50/50">
                 <div className="p-4 md:p-6 bg-white border-b border-slate-100 flex items-center">
                    <div className="flex-1 flex items-center bg-slate-50 border border-slate-200 rounded-xl px-4 py-2.5">
                       <Search size={16} className="text-slate-400 mr-3" />
                       <input 
                         type="text" 
                         placeholder="Cari nama dalam daftar ini..." 
                         className="bg-transparent text-xs font-bold outline-none w-full"
                         value={bnbaSearch}
                         onChange={(e) => setBnbaSearch(e.target.value)}
                       />
                    </div>
                 </div>

                 <div className="flex-1 overflow-auto p-4 md:p-8">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                       {bnbaList.map((r, idx) => (
                          <div key={idx} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex items-center space-x-4 hover:border-blue-500 transition-all group">
                             <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-[10px] font-black text-slate-400 group-hover:bg-blue-600 group-hover:text-white transition-all shrink-0">
                                {idx + 1}
                             </div>
                             <div className="min-w-0 flex-1">
                                <h5 className="text-[11px] font-black text-slate-900 uppercase truncate leading-none mb-1">{r.fullName}</h5>
                                <div className="flex items-center space-x-3 text-[9px] font-bold text-slate-400">
                                   <span className="font-mono">{r.nik}</span>
                                   <span className="uppercase text-blue-500 font-black">{r.dusun}</span>
                                </div>
                             </div>
                             <div className="hidden sm:block text-[9px] font-black text-slate-300 uppercase">RT {r.rt}</div>
                          </div>
                       ))}
                       {bnbaList.length === 0 && (
                         <div className="col-span-full py-20 text-center">
                            <FileText size={48} className="mx-auto text-slate-200 mb-4" />
                            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Daftar nama tidak ditemukan.</p>
                         </div>
                       )}
                    </div>
                 </div>
              </div>

              <div className="p-6 md:p-8 border-t border-slate-100 bg-white flex justify-center shrink-0">
                 <button 
                   onClick={() => setSelectedBNBA(null)}
                   className="px-12 py-4 bg-slate-900 text-white rounded-[1.5rem] text-[10px] font-black uppercase tracking-widest hover:opacity-90 shadow-2xl transition-all"
                 >
                   Tutup Daftar BNBA
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default RecapIndicators;

import React, { useState } from 'react';
import { 
  LayoutDashboard, 
  Users, 
  BarChart3, 
  Settings, 
  Menu, 
  X, 
  ChevronRight,
  Archive,
  Baby,
  PanelLeftClose,
  PanelLeftOpen,
  Cloud,
  CloudOff,
  RefreshCcw
} from 'lucide-react';
import { AppConfig } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  config: AppConfig;
  isSyncing?: boolean;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, config, isSyncing }) => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);

  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'penduduk', label: 'Data Penduduk', icon: Users },
    { id: 'kelahiran', label: 'Kelahiran', icon: Baby },
    { id: 'arsip', label: 'Arsip', icon: Archive },
    { id: 'rekap', label: 'Rekap Indikator', icon: BarChart3 },
    { id: 'profil', label: 'Profil Aplikasi', icon: Settings },
  ];

  const getInitials = (name: string) => {
    if (!name) return 'AD';
    return name.split(' ').map(n => n[0]).join('').toUpperCase().slice(0, 2);
  };

  const sidebarWidth = isSidebarCollapsed ? 'w-20' : 'w-64';

  return (
    <div className="min-h-screen flex bg-slate-50 text-slate-900 transition-all duration-300">
      {/* Sidebar Desktop */}
      <aside className={`hidden md:flex flex-col ${sidebarWidth} bg-slate-900 text-white shadow-xl fixed h-full transition-all duration-300 z-40`}>
        <div className={`p-6 border-b border-slate-800 flex items-center ${isSidebarCollapsed ? 'justify-center' : 'space-x-3'}`}>
          <img 
            src={config.logoUrl || "https://upload.wikimedia.org/wikipedia/commons/1/1d/Lambang_Kabupaten_Blora.png"} 
            alt="Logo" 
            className="w-10 h-10 rounded-lg bg-white p-1 min-w-[40px]"
          />
          {!isSidebarCollapsed && (
            <div className="animate-in fade-in duration-300 min-w-0 flex-1">
              <h1 className="font-bold text-base lg:text-lg leading-tight uppercase tracking-tighter truncate">{config.appName}</h1>
              <p className="text-[10px] text-slate-400 font-medium uppercase tracking-widest leading-tight mt-1 whitespace-normal break-words">
                {config.subtitle}
              </p>
            </div>
          )}
        </div>

        <nav className="flex-1 p-4 space-y-2 overflow-y-auto">
          {menuItems.map((item) => (
            <button
              key={item.id}
              onClick={() => setActiveTab(item.id)}
              className={`w-full flex items-center rounded-xl transition-all group ${
                isSidebarCollapsed ? 'justify-center p-3' : 'space-x-3 px-4 py-3'
              } ${
                activeTab === item.id 
                  ? 'bg-blue-600 text-white shadow-lg shadow-blue-900/20' 
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon size={20} />
              {!isSidebarCollapsed && <span className="font-bold text-sm">{item.label}</span>}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-800">
