    setFormData({
      ...formData,
      firebaseConfig: {
        ...(formData.firebaseConfig || {
          apiKey: '',
          authDomain: '',
          projectId: '',
          storageBucket: '',
          messagingSenderId: '',
          appId: '',
          enabled: false
        }),
